const e=[{q:"\uB2E8 \uD558\uB098\uC758 \uBD88\uAF43\uC774 \uB300\uCD08\uC6D0\uC5D0 \uBD88\uC744 \uC77C\uC73C\uD0AC \uC218 \uC788\uC2B5\uB2C8\uB2E4",s:'"\uB2E8 \uD558\uB098\uC758 \uBD88\uAF43\uC774 \uCD08\uC6D0\uC758 \uBD88\uC744 \uC77C\uC73C\uD0AC \uC218 \uC788\uB2E4"(1930\uB144 1\uC6D4)',e:"\uC0C8\uB85C\uC6B4 \uAC83\uC774 \uCC98\uC74C\uC5D0\uB294 \uD798\uC774 \uC57D\uD558\uB354\uB77C\uB3C4 \uC0DD\uBA85\uB825\uC774 \uAC15\uD558\uACE0 \uBC1C\uC804 \uC804\uB9DD\uC774 \uB113\uB2E4\uB294 \uBE44\uC720\uC785\uB2C8\uB2E4. \uD601\uBA85\uC774 \uC1E0\uD1F4\uD558\uACE0 \uBE44\uAD00\uB860\uC774 \uD655\uC0B0\uB420 \uB54C, \uB9C8\uC624\uCA4C\uB465\uC740 \uC774\uB97C \uC774\uC6A9\uD574 \uB3D9\uC9C0\uB4E4\uC5D0\uAC8C \uD76C\uB9DD\uC744 \uBCF4\uACE0 \uD601\uBA85\uC758 \uD798\uC774 \uB354\uC6B1 \uAC15\uD574\uC9C8 \uAC83\uC774\uB77C\uB294 \uD655\uACE0\uD55C \uBBFF\uC74C\uC744 \uAC16\uB3C4\uB85D \uB3C5\uB824\uD588\uC2B5\uB2C8\uB2E4."},{q:"\uD601\uBA85\uC740 \uC190\uB2D8\uC5D0\uAC8C \uC800\uB141 \uC2DD\uC0AC\uB97C \uB300\uC811\uD558\uAC70\uB098, \uAE30\uC0AC\uB97C \uC4F0\uAC70\uB098, \uADF8\uB9BC\uC744 \uADF8\uB9AC\uACE0 \uC790\uC218\uB97C \uD558\uB294 \uAC83\uC774 \uC544\uB2D9\uB2C8\uB2E4. \uADF8\uD1A0\uB85D \uC6B0\uC544\uD558\uACE0, \uADF8\uD1A0\uB85D \uC5EC\uC720\uB86D\uACE0, \uADF8\uD1A0\uB85D \uC628\uD654\uD558\uACE0, \uADF8\uD1A0\uB85D \uC628\uD654\uD558\uACE0, \uC608\uC758 \uBC14\uB974\uACE0, \uAC80\uC18C\uD560 \uC218\uB294 \uC5C6\uC2B5\uB2C8\uB2E4. \uD601\uBA85\uC740 \uD3ED\uB3D9, \uC989 \uD55C \uACC4\uAE09\uC774 \uB2E4\uB978 \uACC4\uAE09\uC744 \uC804\uBCF5\uC2DC\uD0A4\uB294 \uD3ED\uB825\uC801\uC778 \uD589\uB3D9\uC774\uB2E4.",s:"\u300E\uD638\uB0A8\uC131 \uB18D\uBBFC\uC6B4\uB3D9\uC5D0 \uAD00\uD55C \uAC80\uC5F4\uBCF4\uACE0\u300F(1927\uB144 3\uC6D4)",e:"\uD601\uBA85\uC758 \uBCF8\uC9C8\uC740 \uCE58\uC5F4\uD55C \uACC4\uAE09\uD22C\uC7C1\uC784\uC744 \uAC15\uC870\uD558\uBA74\uC11C \uC628\uAC74\uD55C \uAC1C\uD601\uBC29\uC2DD\uC73C\uB85C\uB294 \uD601\uBA85\uC744 \uB300\uCCB4\uD560 \uC218 \uC5C6\uB2E4. \uADF9\uC2EC\uD55C \uC5B5\uC555\uC5D0 \uB9DE\uC11C\uC11C \uACFC\uAC10\uD558\uAC8C \uC2F8\uC6CC\uC57C\uB9CC \uC5B5\uC555\uBC1B\uB294 \uC0AC\uB78C\uB4E4\uC758 \uC6B4\uBA85\uC744 \uC9C4\uC815\uC73C\uB85C \uBC14\uAFC0 \uC218 \uC788\uC2B5\uB2C8\uB2E4."},{q:"\uACFC\uC789\uAD50\uC815\uC740 \uACFC\uD574\uC57C \uD558\uC9C0\uB9CC \uAD50\uC815\uC740 \uACFC\uD558\uC9C0 \uC54A\uC544\uC57C \uD569\uB2C8\uB2E4.",s:"\u300E\uD638\uB0A8\uC131 \uB18D\uBBFC\uC6B4\uB3D9\uC5D0 \uAD00\uD55C \uAC80\uC5F4\uBCF4\uACE0\u300F(1927\uB144 3\uC6D4)",e:"\uB0A1\uC740 \uBD09\uAC74\uC9C8\uC11C\uB97C \uC885\uC2DD\uC2DC\uD0A4\uB824\uBA74 \uC810\uC9C4\uC801\uC778 \uAC1C\uD601\uBCF4\uB2E4\uB294 \uAE09\uC9C4\uC801\uC778 \uD601\uBA85\uC801 \uBC29\uBC95\uC744 \uC0AC\uC6A9\uD574\uC57C \uD569\uB2C8\uB2E4. \uD655\uACE0\uD55C \uB0A1\uC740 \uC2DC\uC2A4\uD15C\uC744 \uBB34\uB108\uB728\uB9AC\uB824\uBA74 \uB54C\uB85C\uB294 \uAE30\uC874\uC758 \uB178\uB825\uBCF4\uB2E4 \uB354 \uB9CE\uC740 \uB178\uB825\uC774 \uD544\uC694\uD569\uB2C8\uB2E4."},{q:"\uC870\uC0AC\uAC00 \uC5C6\uC73C\uBA74 \uB9D0\uD560 \uAD8C\uB9AC\uB3C4 \uC5C6\uC2B5\uB2C8\uB2E4.",s:'"\uB18D\uCD0C\uC870\uC0AC"\uC758 \uC11C\uBB38\uACFC \uD6C4\uAE30"(1941\uB144 3\uC6D4)',e:"\uBAA8\uB4E0 \uACB0\uB860\uC740 \uC870\uC0AC\uAC00 \uC2DC\uC791\uB420 \uB54C\uAC00 \uC544\uB2C8\uB77C \uC870\uC0AC\uAC00 \uB05D\uB0A0 \uB54C \uB3C4\uCD9C\uB429\uB2C8\uB2E4. \uC870\uC0AC\uB3C4 \uD558\uC9C0 \uC54A\uACE0 \uBB34\uC791\uC704\uB85C \uB313\uAE00\uC744 \uB2EC\uBA74 10\uBC88 \uC911 10\uBC88\uC740 \uC2E4\uD328\uD558\uAC8C \uB429\uB2C8\uB2E4. \uC774\uAC83\uC774 \uC8FC\uAD00\uC801 \uC0C1\uC0C1\uC774 \uC544\uB2CC \uD604\uC2E4\uC5D0\uC11C \uCD9C\uBC1C\uD558\uB294 \uC0AC\uC2E4\uB85C\uBD80\uD130 \uC9C4\uC2E4\uC744 \uCC3E\uB294 \uC774\uB150\uB178\uC120\uC758 \uD575\uC2EC\uC774\uB2E4."},{q:"\uC628 \uB9C8\uC74C\uC744 \uB2E4\uD574 \uAD6D\uBBFC\uC744 \uC12C\uAE30\uB2E4",s:'"\uC5F0\uB9BD \uC815\uBD80\uC5D0 \uAD00\uD558\uC5EC"(1945\uB144 4\uC6D4)',e:"\uC774\uAC83\uC774 \uC6B0\uB9AC \uB2F9\uACFC \uAD70\uB300\uC758 \uADFC\uBCF8\uBAA9\uC801\uC774\uB2E4. \uBAA8\uB4E0 \uC0AC\uC5C5\uC758 \uC2DC\uC791\uC810\uACFC \uB05D\uC810\uC740 \uAD6D\uBBFC\uC758 \uC774\uC775\uC774 \uB418\uC5B4\uC57C \uD569\uB2C8\uB2E4. \uC774 \uB2E4\uC12F \uB2E8\uC5B4\uB294 \uBAA8\uB4E0 \uD589\uB3D9\uC744 \uD14C\uC2A4\uD2B8\uD558\uB294 \uAC00\uC7A5 \uB192\uC740 \uAE30\uC900\uC785\uB2C8\uB2E4."},{q:"\uC0AC\uB78C\uC740 \uC5B8\uC81C\uB098 \uC8FD\uAC8C \uB9C8\uB828\uC774\uC9C0\uB9CC \uC8FD\uC74C\uC758 \uC758\uBBF8\uB294 \uB2E4\uB985\uB2C8\uB2E4. \uBC31\uC131\uC744 \uC704\uD574 \uC8FD\uB294 \uAC83\uC774 \uD0DC\uC0B0\uBCF4\uB2E4 \uB354 \uC911\uC694\uD558\uB2E4",s:'"\uC778\uBBFC\uC5D0 \uBD09\uC0AC"(1944\uB144 9\uC6D4)',e:"\uC0B6\uC758 \uAC00\uCE58\uB294 \uAE38\uC774\uC5D0 \uC788\uB294 \uAC83\uC774 \uC544\uB2C8\uB77C \uBAA9\uC801\uC5D0 \uC788\uC2B5\uB2C8\uB2E4. \uC720\uD55C\uD55C \uC0DD\uBA85\uC744 \uC778\uBBFC\uC744 \uC704\uD55C \uB300\uC5C5\uC5D0 \uBC14\uCE5C\uB2E4\uBA74 \uADF8\uB7EC\uD55C \uC8FD\uC74C\uC740 \uD0DC\uC0B0\uBCF4\uB2E4 \uB354 \uC911\uC694\uD560 \uAC83\uC785\uB2C8\uB2E4. \uC774\uB294 Zhang Side\uC5D0 \uB300\uD55C \uCC2C\uC0AC\uC77C \uBFD0\uB9CC \uC544\uB2C8\uB77C \uBAA8\uB4E0 \uC0AC\uB78C\uC5D0\uAC8C \uC601\uAC10\uC744 \uC8FC\uB294 \uAC83\uC774\uAE30\uB3C4 \uD569\uB2C8\uB2E4."},{q:"\uC6B0\uB9AC\uB294 \uAD6D\uBBFC\uC744 \uC704\uD574 \uBD09\uC0AC\uD558\uAE30 \uB54C\uBB38\uC5D0 \uBD80\uC871\uD55C \uC810\uC774 \uC788\uC73C\uBA74 \uB2E4\uB978 \uC0AC\uB78C\uB4E4\uC774 \uC6B0\uB9AC\uB97C \uBE44\uD310\uD558\uACE0 \uC9C0\uC801\uD558\uB294 \uAC83\uC744 \uB450\uB824\uC6CC\uD558\uC9C0 \uC54A\uC2B5\uB2C8\uB2E4.",s:'"\uC778\uBBFC\uC5D0 \uBD09\uC0AC"(1944\uB144 9\uC6D4)',e:"\uC9C4\uC815\uC73C\uB85C \uC790\uC2E0\uAC10 \uC788\uB294 \uC0AC\uB78C\uC740 \uBE44\uD310\uC744 \uB450\uB824\uC6CC\uD558\uC9C0 \uC54A\uC2B5\uB2C8\uB2E4. \uC778\uBBFC\uC758 \uC774\uC775\uC5D0 \uB9DE\uB294 \uAC83\uC740 \uBB34\uC5C7\uC774\uB4E0 \uACAC\uC9C0\uD558\uACE0 \uC778\uBBFC\uC758 \uC774\uC775\uC5D0 \uB9DE\uC9C0 \uC54A\uB294 \uAC83\uC740 \uBC14\uB85C\uC7A1\uB294 \uB9C8\uC74C\uACFC \uD0DC\uB3C4\uAC00 \uBC14\uB85C \uAC1C\uC778\uACFC \uC870\uC9C1\uC758 \uC9C0\uC18D\uC801\uC778 \uBC1C\uC804\uC744 \uB2F4\uBCF4\uD558\uB294 \uAC83\uC785\uB2C8\uB2E4."},{q:"\uC6B0\uB9AC \uBAA8\uB450\uB294 \uC804 \uC138\uACC4\uC5D0\uC11C \uBAA8\uC5EC \uACF5\uD1B5\uC758 \uD601\uBA85\uC801 \uBAA9\uD45C\uB97C \uC704\uD574 \uD568\uAED8 \uBAA8\uC600\uC2B5\uB2C8\uB2E4.",s:'"\uC778\uBBFC\uC5D0 \uBD09\uC0AC"(1944\uB144 9\uC6D4)',e:"\uCD9C\uC2E0\uC774\uB098 \uC9C0\uC5ED\uC744 \uBD88\uBB38\uD558\uACE0 \uBAA9\uC801\uC774 \uAC19\uC73C\uBA74 \uAC15\uB825\uD55C \uC138\uB825\uC73C\uB85C \uBAA8\uC77C \uC218 \uC788\uB2E4. \uC774 \uC778\uC6A9\uBB38\uC740 \uC5EC\uC804\uD788 \u200B\u200B\uB2E4\uC591\uD55C \uBC30\uACBD\uC744 \uAC00\uC9C4 \uC0AC\uB78C\uB4E4\uC774 \uD568\uAED8 \uC77C\uD558\uB3C4\uB85D \uC601\uAC10\uC744 \uC90D\uB2C8\uB2E4."},{q:"\uACB0\uB2E8\uD558\uACE0 \uD76C\uC0DD\uC744 \uB450\uB824\uC6CC\uD558\uC9C0 \uC544\uB2C8\uD558\uBA70 \uBAA8\uB4E0 \uC5B4\uB824\uC6C0\uC744 \uC774\uACA8\uB0B4\uACE0 \uC2B9\uB9AC\uB97C \uC704\uD558\uC5EC \uBD84\uD22C\uD558\uB77C",s:"\u300E\uC5B4\uB9AC\uC11D\uC740 \uB178\uC778\uC740 \uC0B0\uC744 \uC62E\uAE34\uB2E4\u300F(1945\uB144 6\uC6D4)",e:"\u300E\uC5B4\uB9AC\uC11D\uC740 \uB178\uC778\uC774 \uC0B0\uC744 \uC62E\uAE34\uB2E4\u300F\uC5D0\uC11C \uAC00\uC7A5 \uAC15\uB825\uD55C \uAD6C\uC808\uC774\uB2E4. \uADF9\uBCF5\uD560 \uC218 \uC5C6\uC744 \uAC83 \uAC19\uC740 \uC5ED\uACBD \uC18D\uC5D0\uC11C\uB294 \uACB0\uB2E8\uB825\uC774 \uC6B0\uC120\uC785\uB2C8\uB2E4. \uC544\uBB34\uB9AC \uD070 \uC5B4\uB824\uC6C0\uC774\uB77C\uB3C4 \uB300\uAC00\uB97C \uCE58\uB974\uB294 \uAC83\uC744 \uB450\uB824\uC6CC\uD558\uC9C0 \uC54A\uACE0 \uACB0\uB2E8\uB825 \uC788\uAC8C \uCC28\uADFC\uCC28\uADFC \uADF9\uBCF5\uD574 \uB098\uAC08 \uC218 \uC788\uC2B5\uB2C8\uB2E4."},{q:"\uC6B0\uB9AC\uB294 \uC778\uB0B4\uD558\uACE0 \uB04A\uC784\uC5C6\uC774 \uB178\uB825\uD574\uC57C \uD558\uBA70, \uB610\uD55C \uD558\uB098\uB2D8\uC744 \uAC10\uB3D9\uC2DC\uD0A4\uAC8C \uB420 \uAC83\uC785\uB2C8\uB2E4. \uC774 \uC2E0\uC740 \uBC14\uB85C \uC911\uAD6D \uC0AC\uB78C\uB4E4\uC774\uB2E4.",s:"\u300E\uC5B4\uB9AC\uC11D\uC740 \uB178\uC778\uC740 \uC0B0\uC744 \uC62E\uAE34\uB2E4\u300F(1945\uB144 6\uC6D4)",e:"\uAD6D\uBBFC\uC774 \uACE7 \uC2E0\uC774\uACE0, \uB048\uC9C8\uAE34 \uD589\uB3D9\uC740 \uACB0\uAD6D \uAD6D\uBBFC\uC758 \uD638\uC751\uACFC \uC9C0\uC9C0\uB97C \uBC1B\uAC8C \uB41C\uB2E4. \uC678\uBD80\uC758 \uD798\uC5D0 \uB300\uD574 \uBBF8\uC2E0\uC744 \uBBFF\uC9C0 \uB9C8\uC2ED\uC2DC\uC624. \uC9C4\uC815\uD55C \uD798\uC740 \uAD6D\uBBFC\uC5D0\uAC8C\uC11C \uB098\uC635\uB2C8\uB2E4."},{q:"\uB3D9\uC9C0\uB4E4\uC774 \uC5B4\uB824\uC6C0\uC5D0 \uCC98\uD560 \uB54C \uC6B0\uB9AC\uB294 \uC131\uACFC\uB97C \uBCF4\uACE0, \uBE5B\uC744 \uBCF4\uACE0, \uC6A9\uAE30\uB97C \uD0A4\uC6CC\uC57C \uD569\uB2C8\uB2E4.",s:'"\uC778\uBBFC\uC5D0 \uBD09\uC0AC"(1944\uB144 9\uC6D4)',e:"\uC5ED\uACBD \uC18D\uC5D0\uC11C \uC0AC\uB78C\uB4E4\uC758 \uBCF8\uB2A5\uC740 \uBB38\uC81C\uC640 \uC5B4\uB824\uC6C0\uC744 \uBCF4\uB294 \uAC83\uC785\uB2C8\uB2E4. \uB9C8\uC624\uCA4C\uB465\uC740 \uC6B0\uB9AC\uC5D0\uAC8C \uB2E4\uC74C\uACFC \uAC19\uC774 \uC0C1\uAE30\uC2DC\uCF30\uC2B5\uB2C8\uB2E4. \uC6B0\uB9AC\uB294 \uC194\uC120\uD558\uC5EC \uAE0D\uC815\uC801\uC778 \uBA74\uC744 \uCC3E\uC544\uC57C \uD569\uB2C8\uB2E4. \uC9C0\uAE08\uAE4C\uC9C0 \uB2EC\uC131\uD55C \u200B\u200B\uACB0\uACFC\uC640 \uC55E\uC73C\uB85C\uC758 \uBC1D\uC740 \uBBF8\uB798\uB97C \uBCF4\uBA74 \uC6A9\uAE30\uAC00 \uC790\uC5F0\uC2A4\uB7FD\uAC8C \uC19F\uC544\uB0A9\uB2C8\uB2E4."},{q:"\uB300\uC7A5\uC815\uC740 \uC120\uC5B8\uBB38\uC774\uACE0, \uB300\uC7A5\uC815\uC740 \uC120\uC804\uD300\uC774\uBA70, \uB300\uC7A5\uC815\uC740 \uD30C\uC885\uAE30\uC774\uB2E4.",s:"\u3008\uC77C\uC81C \uBC18\uB300\uC804\uB7B5\uC5D0 \uB300\uD558\uC5EC\u3009(1935\uB144 12\uC6D4)",e:'\uB300\uC7A5\uC815\uC740 \uB2E8\uC21C\uD55C \uAD70\uC0AC\uC791\uC804 \uADF8 \uC774\uC0C1\uC774\uC5C8\uC2B5\uB2C8\uB2E4. \uBD89\uC740 \uAD70\uB300\uC758 \uBB34\uC801\uC744 \uC138\uACC4\uC5D0 \uC120\uC5B8\uD558\uACE0 \uADF8 \uACFC\uC815\uC5D0\uC11C \uC778\uBBFC\uB4E4\uC5D0\uAC8C \uD601\uBA85\uC758 \uC528\uC557\uC744 \uBFCC\uB838\uC2B5\uB2C8\uB2E4. \uBAA8\uB4E0 \uC704\uB300\uD55C \uC0AC\uC5C5\uC5D0\uB294 \uBE44\uC2B7\uD55C "\uC7A5\uAC70\uB9AC \uD589\uC9C4" \uB2E8\uACC4\uAC00 \uC788\uC2B5\uB2C8\uB2E4.'},{q:"\uC77D\uB294 \uAC83\uB3C4 \uD559\uC2B5\uC774\uACE0, \uD65C\uC6A9\uB3C4 \uD559\uC2B5\uC774\uBA70, \uB354 \uC911\uC694\uD55C \uD559\uC2B5\uC785\uB2C8\uB2E4.",s:'"\uC911\uAD6D \uD601\uBA85 \uC804\uC7C1\uC758 \uC804\uB7B5\uC801 \uBB38\uC81C"(1936\uB144 12\uC6D4)',e:"\uC9C0\uC2DD\uC740 \uC0AC\uC6A9\uB420 \uB54C\uB9CC \uAC00\uCE58\uAC00 \uC788\uC2B5\uB2C8\uB2E4. \uB9CE\uC740 \uC0AC\uB78C\uB4E4\uC774 '\uD559\uC2B5' \uB2E8\uACC4\uC5D0 \uBA38\uBB3C\uB7EC \uC788\uC9C0\uB9CC \uC2E4\uC81C \uC131\uC7A5\uC740 \uC2E4\uC81C\uB85C \uD14C\uC2A4\uD2B8\uD558\uACE0 \uC218\uC815\uD558\uACE0 \uC774\uD574\uB97C \uC2EC\uD654\uD558\uB294 '\uC0AC\uC6A9'\uC5D0\uC11C \uBE44\uB86F\uB429\uB2C8\uB2E4."},{q:"\uC758\uC9C0\uAC00 \uC788\uB294 \uC0AC\uB78C\uC774 \uC788\uB294 \uD55C \uC138\uC0C1\uC5D0 \uC5B4\uB824\uC6B4 \uC77C\uC740 \uC5C6\uC2B5\uB2C8\uB2E4.",s:'"\uC911\uAD6D \uD601\uBA85 \uC804\uC7C1\uC758 \uC804\uB7B5\uC801 \uBB38\uC81C"(1936\uB144 12\uC6D4)',e:"\uC6B0\uB9AC \uC870\uC0C1\uB4E4\uC774 \uB0A8\uAE34 \uC9C0\uD61C\uB294 \uB9C8\uC624\uCA4C\uB465\uC774 \uAD70\uC0AC \uC800\uC220\uC5D0 \uC778\uC6A9\uD55C \uAC83\uC785\uB2C8\uB2E4. \uC5F4\uC2EC\uD788 \uC77C\uD558\uB824\uB294 \uC758\uC9C0\uC640 \uC758\uC9C0\uAC00 \uC788\uB294 \uD55C, \uC2DC\uC791\uD558\uB294 \uAC83\uC740 \uC5B4\uB835\uC9C0 \uC54A\uACE0 \uB9C8\uC2A4\uD130\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4."},{q:"\uAC00\uC838\uAC00\uACE0 \uC2F6\uC73C\uBA74 \uBA3C\uC800 \uC8FC\uC5B4\uC57C \uD55C\uB2E4",s:'"\uC911\uAD6D \uD601\uBA85 \uC804\uC7C1\uC758 \uC804\uB7B5\uC801 \uBB38\uC81C"(1936\uB144 12\uC6D4)',e:"\uB178\uC790\uC758 \uB3C4\uB355\uACBD(\u9053\u5FB7\u667A)\uC758 \uC9C0\uD61C\uAC00 \uAD70\uC0AC\uC804\uB7B5\uC5D0 \uD65C\uC6A9\uB418\uC5C8\uB2E4. \uB54C\uB85C\uB294 \uC55E\uC73C\uB85C \uB098\uC544\uAC00\uAE30 \uC704\uD574 \uD3EC\uAE30\uD574\uC57C \uD558\uACE0, \uBB34\uC5B8\uAC00\uB97C \uC5BB\uAE30 \uC704\uD574 \uD3EC\uAE30\uD574\uC57C \uD560 \uB54C\uB3C4 \uC788\uC2B5\uB2C8\uB2E4. \uC774\uAC83\uC740 \uBCC0\uC99D\uBC95\uC758 \uC0DD\uC0DD\uD55C \uAD6C\uD604\uC785\uB2C8\uB2E4."},{q:"\uBC18\uB3D9\uD30C\uB294 \uBAA8\uB450 \uC885\uC774\uD638\uB791\uC774",s:"\u201C\uBBF8\uAD6D \uC5B8\uB860\uC778 \uC560\uB098 \uB8E8\uC774\uC2A4 \uC2A4\uD2B8\uB871\uACFC\uC758 \uB300\uD654\u201D(1946\uB144 8\uC6D4)",e:"\uC774 \uC720\uBA85\uD55C \uBA85\uC5B8\uC740 \uC804 \uC138\uACC4\uB97C \uB180\uB77C\uAC8C \uD588\uC2B5\uB2C8\uB2E4. \uD45C\uBA74\uC801\uC73C\uB85C \uAC15\uD574 \uBCF4\uC774\uB294 \uC801\uB4E4\uC740 \uAD6D\uBBFC\uACFC \uBD84\uB9AC\uB418\uC5B4 \uC788\uAE30 \uB54C\uBB38\uC5D0 \uBCF8\uC9C8\uC801\uC73C\uB85C\uB098 \uC7A5\uAE30\uC801\uC73C\uB85C\uB098 \uC57D\uD558\uB2E4. \uC9C4\uC815\uC73C\uB85C \uAC15\uB825\uD55C \uD798\uC740 \uC5B8\uC81C\uB098 \uAD6D\uBBFC\uC758 \uD3B8\uC5D0 \uC788\uC2B5\uB2C8\uB2E4."},{q:"\uBBF8\uB798\uB294 \uBC1D\uC9C0\uB9CC \uAC08 \uAE38\uC740 \uD5D8\uB09C\uD558\uB2E4",s:'"\uCDA9\uCE6D\uD611\uC0C1\uC5D0 \uAD00\uD558\uC5EC"(1945\uB144 10\uC6D4)',e:"\uB2E8 \uC5F4 \uB2E8\uC5B4\uC5D0\uB3C4 \uAC00\uC7A5 \uB2E8\uC21C\uD558\uACE0 \uC2EC\uC624\uD55C \uC0B6\uC758 \uCCA0\uD559\uC774 \uB2F4\uACA8 \uC788\uC2B5\uB2C8\uB2E4. \uC6B0\uB9AC\uB294 \uBBF8\uB798\uC5D0 \uB300\uD55C \uC790\uC2E0\uAC10\uC744 \uAC00\uC838\uC57C \uD558\uBA70, \uB3D9\uC2DC\uC5D0 \uC55E\uC73C\uB85C \uB2E4\uAC00\uC62C \uC5B4\uB824\uC6C0\uC744 \uCDA9\uBD84\uD788 \uC608\uC0C1\uD574\uC57C \uD569\uB2C8\uB2E4."},{q:"\uB9CC\uB144\uC740 \uB108\uBB34 \uAE38\uC5B4, \uD558\uB8E8\uB97C \uC990\uACA8\uB77C",s:'"\uB9CC\uC7A5\uD64D\uACFC \uAD88\uBAA8\uC57D \uB3D9\uC9C0"(1963\uB144 1\uC6D4)',e:"\uC2DC\uAC04\uC740 \uB204\uAD6C\uB3C4 \uAE30\uB2E4\uB824\uC8FC\uC9C0 \uC54A\uC2B5\uB2C8\uB2E4. \uC549\uC544\uC11C \uBA3C \uBBF8\uB798\uB97C \uAE30\uB2E4\uB9AC\uC9C0 \uB9D0\uACE0 \uD604\uC7AC\uC758 \uBAA8\uB4E0 \uC21C\uAC04\uC744 \uD3EC\uCC29\uD558\uC138\uC694. \uC774 \uBB38\uC7A5\uC740 \uC5EC\uB7EC \uC138\uB300\uC758 \uC911\uAD6D\uC778\uB4E4\uC774 \uC2DC\uAC04\uACFC \uD22C\uC7C1\uC5D0 \uB9DE\uC11C \uC2F8\uC6B0\uB3C4\uB85D \uC601\uAC10\uC744 \uC8FC\uC5C8\uC2B5\uB2C8\uB2E4."},{q:"Xiongguan\uC744 \uD1B5\uACFC\uD558\uB294 \uAE34 \uAE38\uC740 \uC815\uB9D0 \uCCA0\uACFC \uAC19\uC544\uC11C \uC774\uC81C \uC6B0\uB9AC\uB294 \uCC98\uC74C\uBD80\uD130 \uAC74\uB108\uACE0 \uC788\uC2B5\uB2C8\uB2E4.",s:'"\uC9C4\uC5B4\xB7\uB7EC\uC0B0\uAD00\uC744 \uD68C\uC0C1\uD558\uB2E4"(1935\uB144 2\uC6D4)',e:"\uB8E8\uC0B0\uAD00\uC740 \uD64D\uAD70 \uC7A5\uC815\uC758 \uCE58\uC5F4\uD55C \uC804\uD22C\uC600\uC2B5\uB2C8\uB2E4. \uBA3C\uC800 \uACE0\uAC1C\uC758 \uC704\uD5D8\uACFC \uC804\uD22C\uC758 \uCE58\uC5F4\uD568\uC5D0 \uB300\uD574 \uC4F0\uACE0, \uADF8 \uB2E4\uC74C\uC5D0\uB294 \uACE0\uAC1C\uB97C \uB118\uC740 \uD6C4\uC758 \uC601\uC6C5\uC801 \uD589\uC704\uC5D0 \uB300\uD574 \uC4F0\uC2ED\uC2DC\uC624. \uC544\uBB34\uB9AC '\uC5F4\uC815'\uC774 \uC5B4\uB835\uACE0 \uC704\uD5D8\uD574\uB3C4 \uC77C\uB2E8 \uADF9\uBCF5\uD558\uBA74 \uC0C8\uB85C\uC6B4 \uCD9C\uBC1C\uC810\uC5D0\uC11C \uC2DC\uC791\uD560 \uC218 \uC788\uB2E4."},{q:"\uBD89\uC740 \uAD70\uB300\uB294 \uC6D0\uC815\uC758 \uC5B4\uB824\uC6C0\uC744 \uB450\uB824\uC6CC\uD558\uC9C0 \uC54A\uC73C\uBA70 \uC218\uCC9C \uAC1C\uC758 \uAC15\uACFC \uC0B0\uB9CC \uAE30\uB2E4\uB9B4 \uC218 \uC788\uC2B5\uB2C8\uB2E4",s:"\u300E\uCE60\uCE59\xB7\uC7A5\uC815\u300F(1935\uB144 10\uC6D4)",e:"\uB300\uC7A5\uC815\uC740 \uC0C1\uC0C1\uC744 \uCD08\uC6D4\uD558\uB294 \uC77C\uC774\uC5C8\uC9C0\uB9CC \uC801\uAD70\uC758 \uB208\uC5D0\uB294 \uC26C\uC6B4 \uC77C\uC5D0 \uC9C0\uB098\uC9C0 \uC54A\uC558\uC2B5\uB2C8\uB2E4. \uC774\uB7EC\uD55C \uB178\uB825\uD558\uC9C0 \uC54A\uB294 \uC815\uC2E0\uC740 \uD655\uACE0\uD55C \uC2E0\uB150\uACFC \uB192\uC740 \uBAA9\uD45C\uC5D0\uC11C \uBE44\uB86F\uB429\uB2C8\uB2E4."},{q:"\uB9CC\uB9AC\uC7A5\uC131\uC5D0 \uAC00\uBCF4\uC9C0 \uC54A\uC73C\uBA74 \uC9C4\uC815\uD55C \uB0A8\uC790\uAC00 \uC544\uB2C8\uB2E4",s:'"\uCCAD\uD3C9\uAC01\xB7\uC721\uBC18\uC0B0"(1935\uB144 10\uC6D4)',e:'\uC720\uD310\uC0B0 \uC7A5\uC815\uC740 \uC0B0\uC2DC\uC131(\u965D\u897F\u7701) \uBD81\uBD80 \uAE30\uC9C0 \uC9C0\uC5ED\uC5D0 \uACE7 \uB3C4\uB2EC\uD588\uC74C\uC744 \uC758\uBBF8\uD55C\uB2E4. "\uB9CC\uB9AC\uC7A5\uC131"\uC740 \uC9C0\uB9AC\uC801 \uC88C\uD45C\uC774\uC790 \uC815\uC2E0\uC801 \uB192\uC774\uC785\uB2C8\uB2E4. \uC9C4\uC815\uD55C \uC6A9\uAC10\uD55C \uC0AC\uB78C\uC740 \uBAA9\uD45C\uB97C \uB2EC\uC131\uD560 \uB54C\uAE4C\uC9C0 \uD3EC\uAE30\uD558\uC9C0 \uC54A\uC2B5\uB2C8\uB2E4.'},{q:"\uC720\uBA85\uD55C \uC0AC\uB78C\uB4E4\uC744 \uC138\uC5B4\uBCF4\uBA74\uC11C \uD604\uC7AC\uB97C \uC0B4\uD3B4\uBCF4\uC138\uC694",s:'"\uCE5C\uC704\uC548 \uBD04\xB7\uB208"(1936\uB144 2\uC6D4)',e:"\uC774 \uC2DC\uC758 \uACB0\uB9D0\uC740 \uAC15\uB825\uD558\uB2E4. \uC5ED\uC0AC\uC758 \uC601\uC6C5\uC740 \uBAA8\uB450 \uACFC\uAC70\uC5D0 \uC788\uC9C0\uB9CC, \uC9C4\uC815\uD55C \uC601\uC6C5\uC740 \uD604\uC7AC\uC640 \uBBF8\uB798\uC5D0 \uC788\uC2B5\uB2C8\uB2E4. \uC774\uAC83\uC774 \uD604\uB300\uC778\uC758 \uAE30\uB300\uC774\uC790 \uC601\uAC10\uC774\uB2E4."},{q:"\uBC14\uB78C\uACFC \uD30C\uB3C4\uC640 \uC0C1\uAD00\uC5C6\uC774 \uC5EC\uC720\uB86D\uAC8C \uC0B0\uCC45\uD558\uB294 \uAC83\uBCF4\uB2E4 \uB0AB\uB2E4",s:'"\uBB3C\uC758 \uC120\uC728 \uC1A1\uB450\xB7\uC218\uC601" (1956\uB144 6\uC6D4)',e:"\uC591\uCBD4\uAC15\uC5D0\uC11C \uC218\uC601\uD558\uBA74\uC11C \uC4F4 \uBB38\uC7A5. \uAC15\uD55C \uBC14\uB78C\uACFC \uD30C\uB3C4\uB3C4 \uB450\uB835\uC9C0 \uC54A\uC744 \uBFD0\uB9CC \uC544\uB2C8\uB77C, \uC548\uB730\uC744 \uAC77\uB294 \uAC83\uBCF4\uB2E4 \uD3B8\uC548\uD568\uC744 \uB290\uB08D\uB2C8\uB2E4. \uC774 \uD3C9\uC628\uD568\uC740 \uC790\uC5F0\uACFC \uC0DD\uBA85\uC758 \uBC95\uCE59\uC744 \uC774\uD574\uD558\uB294 \uB370\uC11C \uBE44\uB86F\uB429\uB2C8\uB2E4."},{q:"\uD76C\uC0DD\uACFC \uD070 \uC57C\uB9DD\uC744 \uC704\uD574 \uB098\uB294 \uAC10\uD788 \uD574\uC640 \uB2EC\uC5D0\uAC8C \uD558\uB298\uC744 \uBC14\uAFB8\uB294 \uBC95\uC744 \uAC00\uB974\uCCD0 \uC8FC\uACA0\uB2E4",s:'"\uACC4\uB85D\xB7\uD1A0\uC18C\uC0B0"(1959\uB144 6\uC6D4)',e:"\uC218\uB9CE\uC740 \uC21C\uAD50\uC790\uB4E4\uC758 \uD76C\uC0DD\uC73C\uB85C \uC778\uD574 \uC138\uC0C1\uC744 \uBC14\uAFB8\uACA0\uB2E4\uB294 \uC57C\uC2EC\uC774 \uBD88\uD0C0\uC62C\uB790\uC2B5\uB2C8\uB2E4. \uC624\uB298\uB0A0\uC758 \uC131\uACFC\uB294 \uD798\uB4E4\uAC8C \uC5BB\uC740 \uAC83\uC774\uC9C0\uB9CC, \uACC4\uC18D\uD574\uC11C \uBCC0\uD654\uD558\uB824\uBA74 \uC6A9\uAE30\uB3C4 \uD544\uC694\uD569\uB2C8\uB2E4."},{q:"\uB108\uBB34 \uB9CE\uC774 \uBD88\uD3C9\uD558\uBA74 \uB9C8\uC74C\uC758 \uC0C1\uCC98\uB97C \uC608\uBC29\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4. \uC0AC\uB78C\uB4E4\uC740 \uD48D\uACBD\uC744 \uD3ED\uB113\uAC8C \uBC14\uB77C\uBCF4\uC544\uC57C \uD569\uB2C8\uB2E4.",s:"\u300E\uAE30\uB8E8\xB7\uC720\uC57C\uC790\uC640 \uD568\uAED8\u300F(1949\uB144 4\uC6D4)",e:"\uCE5C\uAD6C\uB4E4\uC744 \uC704\uB85C\uD558\uB294 \uC720\uBA85\uD55C \uC778\uC6A9\uBB38. \uB108\uBB34 \uB9CE\uC774 \uBD88\uD3C9\uD558\uBA74 \uC790\uC2E0\uB9CC \uD574\uCE60 \uBFD0\uC785\uB2C8\uB2E4. \uC2DC\uC57C\uB97C \uB113\uD788\uACE0 \uC7A5\uAE30\uC801\uC778 \uAD00\uC810\uC744 \uAC16\uB294 \uAC83\uC774 \uC88B\uC2B5\uB2C8\uB2E4. \uC0B6\uC758 \uBD88\uB9CC\uC740 \uB354 \uB113\uC740 \uC2DC\uAC04\uACFC \uACF5\uAC04\uC5D0\uC11C \uC5B8\uAE09\uD560 \uAC00\uCE58\uAC00 \uC5C6\uB294 \uACBD\uC6B0\uAC00 \uB9CE\uC2B5\uB2C8\uB2E4."},{q:"\uBD04\uBC14\uB78C\uC740 \uC218\uCC9C \uADF8\uB8E8\uC758 \uBC84\uB4DC\uB098\uBB34\uB97C \uAC00\uC838\uC624\uACE0, \uC911\uAD6D 6\uC5B5 \uC8FC\uC5D0\uB294 \uBAA8\uB450 \uC21C\uC57C\uC624\uAC00 \uAC00\uB4DD\uD569\uB2C8\uB2E4.",s:'"7\uBC15\uC790\uC758 \uB450 \uB178\uB798: \uC5ED\uBCD1\uC758 \uC2E0\uC5D0\uAC8C \uC791\uBCC4 \uC778\uC0AC"(1958\uB144 7\uC6D4)',e:"\uBC31\uC131\uC774 \uC870\uC9C1\uB418\uACE0 \uC8FC\uB3C4\uC801\uC774\uB77C\uBA74 \uB204\uAD6C\uB098 \uC694\uC21C(\u582F\u821C)\uACFC \uAC19\uC740 \uC131\uC778\uC774 \uB420 \uC218 \uC788\uB2E4. \uC774\uB294 \uB300\uC911\uC758 \uCC3D\uC758\uC131\uC5D0 \uB300\uD55C \uCD5C\uACE0\uC758 \uCC2C\uC0AC\uC785\uB2C8\uB2E4."},{q:"\uD558\uB298\uC5D0 \uC0AC\uB791\uC774 \uC788\uC73C\uBA74 \uD558\uB298\uB3C4 \uB299\uACE0 \uC138\uC0C1\uC758 \uBC14\uB978 \uAE38\uC740 \uC778\uC0DD\uC758 \uC6B0\uC5EC\uACE1\uC808\uC774 \uB420 \uAC83\uC785\uB2C8\uB2E4.",s:'"7\uAC00\uC9C0 \uADDC\uCE59: \uC778\uBBFC\uD574\uBC29\uAD70\uC774 \uB09C\uC9D5\uC744 \uC810\uB839\uD55C\uB2E4"(1949\uB144 4\uC6D4)',e:"\uC5ED\uC0AC\uC758 \uBC95\uCE59\uC740 \uB204\uAD6C\uC758 \uC758\uC9C0\uC5D0\uB3C4 \uC601\uD5A5\uC744 \uBC1B\uC9C0 \uC54A\uC2B5\uB2C8\uB2E4. \uBE44\uB85D \uC5ED\uC0AC\uC758 \uD750\uB984\uC744 \uB530\uB974\uACE0 \uC62C\uBC14\uB978 \uAE38\uC744 \uAC77\uB294\uB2E4\uB294 \uAC83\uC740 \uACE0\uB09C\uC774 \uB530\uB974\uC9C0\uB9CC \uC778\uB958\uC0AC\uD68C\uC758 \uBC1C\uC804\uC744 \uC704\uD574\uC11C\uB294 \uD544\uC5F0\uC801\uC778 \uC77C\uC785\uB2C8\uB2E4. \uC778\uC0DD\uC758 \uC6B0\uC5EC\uACE1\uC808 \uC790\uCCB4\uAC00 \uC138\uC0C1\uC758 \uC62C\uBC14\uB978 \uAE38\uC785\uB2C8\uB2E4."},{q:"\uAD6C\uCC9C\uC5D0 \uC62C\uB77C\uAC00\uBA74 \uB2EC\uC744 \uC7A1\uC744 \uC218 \uC788\uACE0, \uC624\uB300\uC591\uC5D0 \uB0B4\uB824\uAC00\uBA74 \uAC70\uBD81\uC774\uB97C \uC7A1\uC744 \uC218 \uC788\uB2E4.",s:'"Shui Tiao Ge Tou\uAC00 \uC9D5\uAC15\uC0B0\uC73C\uB85C \uB3CC\uC544\uC634"(1965\uB144 5\uC6D4)',e:"\uB9E4\uC6B0 \uAC15\uB825\uD55C \uB450 \uBB38\uC7A5. \uC778\uAC04\uC740 \uB2EC\uC5D0 \uCC29\uB959\uD560 \uC218\uB3C4 \uC788\uACE0 \uAE4A\uC740 \uBC14\uB2E4\uC5D0 \uC7A0\uC218\uD560 \uC218\uB3C4 \uC788\uC2B5\uB2C8\uB2E4. \uBD88\uAC00\uB2A5\uD55C \uAC83\uC740 \uC5C6\uC2B5\uB2C8\uB2E4. \uC774\uB294 \uAE30\uC220 \uC9C4\uBCF4\uC5D0 \uB300\uD55C \uC608\uC5B8\uC77C \uBFD0\uB9CC \uC544\uB2C8\uB77C \uC778\uAC04\uC758 \uC8FC\uAD00\uC801 \uC8FC\uB3C4\uC131\uC5D0 \uB300\uD55C \uCC2C\uC0AC\uC774\uAE30\uB3C4 \uD569\uB2C8\uB2E4."},{q:"\uC704\uD5D8\uD55C \uBD09\uC6B0\uB9AC\uC5D0 \uBB34\uD55C\uD55C \uD48D\uACBD\uC744 \uC120\uC0AC\uD558\uB294 \uC694\uC815\uC758 \uB3D9\uAD74\uB85C \uD0C4\uC0DD",s:'"Qijue: Li Jin \uB3D9\uC9C0\uAC00 \uCD2C\uC601\uD55C Lu\uC0B0 \uBD88\uBA78\uC758 \uB3D9\uAD74 \uC0AC\uC9C4"(1961\uB144 9\uC6D4)',e:"\uAC00\uC7A5 \uC544\uB984\uB2E4\uC6B4 \uD48D\uACBD\uC740 \uAC00\uC7A5 \uC704\uD5D8\uD55C \uACF3\uC5D0 \uC788\uB2E4. \uACE0\uB09C\uACFC \uC7A5\uC560\uBB3C\uC744 \uD1B5\uACFC\uD558\uC9C0 \uC54A\uC73C\uBA74 \uBB34\uD55C\uD55C \uD48D\uACBD\uC744 \uBCFC \uC218 \uC5C6\uC2B5\uB2C8\uB2E4. \uC774\uAC83\uC774 \uB178\uB825\uD558\uB294 \uC0AC\uB78C\uB4E4\uC5D0\uAC8C \uCD5C\uACE0\uC758 \uB3D9\uAE30 \uBD80\uC5EC\uC785\uB2C8\uB2E4."},{q:"\uC804\uAD6D\uC801\uC778 \uC2B9\uB9AC\uB97C \uC7C1\uCDE8\uD558\uB294 \uAC83\uC740 \uC218\uCC9C\uB9AC\uC758 \uC7A5\uC815\uC758 \uCCAB\uAC78\uC74C\uC77C \uBFD0\uC785\uB2C8\uB2E4.",s:"\uC911\uAD6D\uACF5\uC0B0\uB2F9 \uC911\uC559\uC704\uC6D0\uD68C \uC81C7\uAE30 \uC81C2\uCC28\uC804\uC6D0\uD68C\uC758 \uBCF4\uACE0(1949\uB144 3\uC6D4)",e:"\uD601\uBA85\uC758 \uC2B9\uB9AC\uB97C \uC55E\uB454 \uC5C4\uC219\uD55C \uACBD\uACE0: \uC2B9\uB9AC\uC5D0 \uD604\uD639\uB418\uC9C0 \uB9C8\uC2ED\uC2DC\uC624. \uB354 \uD070 \uB3C4\uC804\uC774 \uAE30\uB2E4\uB9AC\uACE0 \uC788\uC2B5\uB2C8\uB2E4. \uBB34\uC5C7\uC778\uAC00\uB97C \uC131\uCDE8\uD560 \uB54C\uB9C8\uB2E4 \uADF8\uAC83\uC740 \uB2E8\uC9C0 \uC0C8\uB85C\uC6B4 \uCD9C\uBC1C\uC810\uC77C \uBFD0\uC785\uB2C8\uB2E4."},{q:"\uC6B0\uB9AC\uB294 \uB3D9\uC9C0\uB4E4\uC774 \uACC4\uC18D\uD574\uC11C \uACB8\uC190\uD558\uACE0 \uC2E0\uC911\uD558\uBA70 \uC624\uB9CC\uD558\uC9C0 \uC54A\uACE0 \uC131\uAE09\uD558\uC9C0 \uC54A\uC740 \uC5C5\uBB34 \uC2A4\uD0C0\uC77C\uC744 \uC720\uC9C0\uD558\uB3C4\uB85D \uD574\uC57C \uD569\uB2C8\uB2E4.",s:"\uC911\uAD6D\uACF5\uC0B0\uB2F9 \uC911\uC559\uC704\uC6D0\uD68C \uC81C7\uAE30 \uC81C2\uCC28\uC804\uC6D0\uD68C\uC758 \uBCF4\uACE0(1949\uB144 3\uC6D4)",e:'"\uB450 \uAC00\uC9C0 \uD544\uC218 \uC0AC\uD56D"\uC740 \uC2DC\uD5D8\uC744 \uBCF4\uAE30 \uC704\uD574 \uBCA0\uC774\uC9D5\uC5D0 \uAC00\uAE30 \uC804 \uC790\uAE30 \uC778\uC2DD\uC774\uBA70, \uC774\uB294 \uC5EC\uC804\uD788 \uC0B6\uACFC \uC77C\uC5D0 \uC788\uC5B4\uC11C \uC911\uC694\uD55C \uC6D0\uCE59\uC785\uB2C8\uB2E4. \uC131\uACF5\uC758 \uAC00\uC7A5 \uC704\uD5D8\uD55C \uC801\uC740 \uC790\uB9CC\uC2EC\uACFC \uC870\uBC14\uC2EC\uC785\uB2C8\uB2E4.'},{q:"\uC5F0\uC2B5\uD558\uACE0 \uC774\uD574\uD558\uACE0 \uB610 \uC5F0\uC2B5\uD558\uACE0 \uB610 \uC774\uD574\uD558\uACE0 \uB05D\uC5C6\uC774 \uBC18\uBCF5\uB418\uB294 \uC774 \uD615\uD0DC",s:'"\uC5F0\uC2B5 \uC911"(1937\uB144 7\uC6D4)',e:"\uC774\uD574\uB294 \uD55C \uBC88 \uC131\uCDE8\uB418\uB294 \uAC83\uC774 \uC544\uB2C8\uB77C, \uC2E4\uCC9C\uACFC \uC774\uD574\uC758 \uBC18\uBCF5\uC744 \uD1B5\uD574 \uC9C0\uC18D\uC801\uC73C\uB85C \uC2EC\uD654\uB429\uB2C8\uB2E4. \uBB34\uC5C7\uC744 \uD558\uB4E0\uC9C0 \uD589\uD568\uC73C\uB85C\uC368 \uBC30\uC6B0\uACE0, \uBC30\uC6B0\uBA74\uC11C \uD589\uB3D9\uD574\uC57C \uD569\uB2C8\uB2E4."},{q:"\uC0AC\uBB3C\uC774 \uBC1C\uC804\uD558\uB294 \uADFC\uBCF8\uC801\uC778 \uC6D0\uC778\uC740 \uC0AC\uBB3C \uC678\uBD80\uC5D0 \uC788\uB294 \uAC83\uC774 \uC544\uB2C8\uB77C \uC0AC\uBB3C \uB0B4\uBD80\uC5D0 \uC788\uB2E4.",s:'"\uBAA8\uC21C\uC5D0 \uAD00\uD558\uC5EC"(1937\uB144 8\uC6D4)',e:"\uBB38\uC81C\uAC00 \uC0DD\uAE30\uBA74 \uC678\uBD80 \uD658\uACBD\uC744 \uD0D3\uD558\uAE30\uBCF4\uB2E4\uB294 \uBA3C\uC800 \uC790\uC2E0\uC5D0\uAC8C\uC11C \uC6D0\uC778\uC744 \uCC3E\uC544\uC57C \uD569\uB2C8\uB2E4. \uB0B4\uBD80\uC694\uC778\uC740 \uBCC0\uD654\uC758 \uAE30\uCD08\uC774\uACE0, \uC678\uBD80\uC694\uC778\uC740 \uB2E8\uC9C0 \uC870\uAC74\uC77C \uBFD0\uC785\uB2C8\uB2E4."},{q:"\uC678\uBD80\uC694\uC778\uC740 \uBCC0\uD654\uC758 \uC870\uAC74\uC774\uACE0, \uB0B4\uBD80\uC694\uC778\uC740 \uBCC0\uD654\uC758 \uAE30\uCD08\uC774\uBA70, \uC678\uBD80\uC694\uC778\uC740 \uB0B4\uBD80\uC694\uC778\uC744 \uD1B5\uD574 \uC791\uC6A9\uD55C\uB2E4.",s:'"\uBAA8\uC21C\uC5D0 \uAD00\uD558\uC5EC"(1937\uB144 8\uC6D4)',e:"\uC774\uAC83\uC740 \uBCC0\uC99D\uBC95\uC758 \uACE0\uC804\uC801\uC778 \uBA85\uC81C\uC774\uB2E4. \uD658\uACBD\uB3C4 \uC911\uC694\uD558\uC9C0\uB9CC \uACB0\uC815\uC801\uC778 \uC694\uC778\uC740 \uC5B8\uC81C\uB098 \uB2F9\uC2E0\uC785\uB2C8\uB2E4. \uB2ED\uC740 \uC801\uC808\uD55C \uC628\uB3C4\uC5D0\uC11C \uC54C\uC5D0\uC11C \uBD80\uD654\uD560 \uC218 \uC788\uC9C0\uB9CC \uB3CC\uC5D0\uC11C\uB294 \uBD80\uD654\uD560 \uC218 \uC5C6\uC2B5\uB2C8\uB2E4."},{q:"\uB2F9\uC2E0\uC774 \uC774\uBC31 \uB144\uC744 \uC0B4 \uC790\uC2E0\uC774 \uC788\uB2E4\uBA74, \uB2F9\uC2E0\uC740 \uC0BC\uCC9C \uB9AC\uB97C \uB36E\uCE58\uB294 \uBB3C\uACFC \uAC19\uC744 \uAC83\uC785\uB2C8\uB2E4.",s:'"\uC77C\uACF1 \uAC1C\uC758 \uACE0\uB300 \uD30C\uD3B8"(1917\uB144\uACBD)',e:"\uB9C8\uC624\uCA4C\uB465(\u6BDB\u6FA4dong) \uCCAD\uB144\uC758 \uC790\uC870\uC801\uC778 \uB9D0. \uACE0\uC0C1\uD55C \uC815\uB150\uC73C\uB85C \uAC00\uB4DD \uCC28\uC11C, \uD070 \uC5F4\uC815\uC73C\uB85C \uC0B0\uACFC \uAC15\uC744 \uC0BC\uD0A4\uACE0, \uC790\uC2E0\uC758 \uC0B6\uC5D0 \uB300\uD55C \uC644\uC804\uD55C \uC790\uC2E0\uAC10\uC744 \uAC16\uACE0, \uB0A0\uAC1C\uB97C \uD3BC\uCE58\uB294 \uC554\uB188\uCC98\uB7FC 3000\uB9AC\uB97C \uB2EC\uB9AC\uACE0 \uC2F6\uC5B4\uD569\uB2C8\uB2E4."},{q:"\uC218\uCC9C \uBA85\uC758 \uC801\uAD70\uC774 \uB098\uB97C \uD3EC\uC704\uD588\uC9C0\uB9CC \uB098\uB294 \uC6C0\uC9C1\uC774\uC9C0 \uC54A\uC558\uC2B5\uB2C8\uB2E4.",s:'"\uC11C\uAC15\xB7\uC9D5\uAC15\uC0B0\uC758 \uB2EC"(1928\uB144 \uAC00\uC744)',e:"\uC804\uC7C1 \uB2F9\uC2DC \uD669\uC591\uC9C0\uC5D0(Huang Yangjie)\uC758 \uBB18\uC0AC. \uC678\uBD80 \uC138\uACC4\uC758 \uC555\uB825 \uC18D\uC5D0\uC11C\uB3C4 \uB0B4\uBA74\uC758 \uACAC\uACE0\uD568\uACFC \uD3C9\uC628\uD568\uC744 \uC720\uC9C0\uD558\uC2ED\uC2DC\uC624. \uC774 \uACB0\uB2E8\uC740 \uBBFF\uC74C\uC5D0 \uB300\uD55C \uC778\uB0B4\uC5D0\uC11C \uBE44\uB86F\uB429\uB2C8\uB2E4."},{q:"\uD478\uB978 \uC0B0\uC744 \uC5EC\uD589\uD560 \uB54C \uC0AC\uB78C\uB4E4\uC740 \uC544\uC9C1 \uC5B4\uB9AC\uC9C0\uB9CC \uC774\uACF3\uC758 \uD48D\uACBD\uC740 \uB3C5\uD2B9\uD569\uB2C8\uB2E4.",s:'"\uCCAD\uD3C9\uAC01 \uD68C\uCC3D"(1934\uB144 \uC5EC\uB984)',e:"\uC7A5\uC815\uC744 \uC55E\uB454 \uC0C1\uD669\uC774 \uC5B4\uB824\uC6E0\uC9C0\uB9CC \uC2DC\uC778\uC740 \uC774\uB807\uAC8C \uB9D0\uD588\uB2E4. \u201C\uBB34\uC218\uD55C \uD478\uB978 \uC0B0\uC744 \uAC78\uC5B4\uB3C4 \uC5EC\uC804\uD788 \uB299\uC9C0 \uC54A\uC558\uACE0, \uB208\uC55E\uC5D0 \uC788\uB294 \uC774 \uB545\uC758 \uD48D\uACBD\uC740 \uB3C5\uD2B9\uD588\uB2E4. \uAE0D\uC815\uC801\uC774\uACE0 \uB099\uAD00\uC801\uC778 \uD601\uBA85\uC801 \uB0AD\uB9CC\uC8FC\uC758."},{q:"\uC720\uBA85\uD55C \uD559\uBC8C\uC758 \uAD70\uC8FC\uAC00 \uB418\uAE30\uBCF4\uB2E4\uB294 \uB0A8\uC740 \uC6A9\uAE30\uB97C \uC774\uC6A9\uD574 \uBD88\uC30D\uD55C \uB3C4\uC801\uB4E4\uC744 \uCAD3\uC544\uB0B4\uB294 \uAC83\uC774 \uB354 \uB0AB\uB2E4.",s:'"7\uAC00\uC9C0 \uADDC\uCE59: \uC778\uBBFC\uD574\uBC29\uAD70\uC774 \uB09C\uC9D5\uC744 \uC810\uB839\uD55C\uB2E4"(1949\uB144 4\uC6D4)',e:"Xiang Yu\uC758 \uC554\uC2DC\uB97C \uC0AC\uC6A9\uD558\uC5EC \uB2E4\uC74C\uACFC \uAC19\uC774 \uACBD\uACE0\uD558\uC2ED\uC2DC\uC624. Xiang Yu\uCC98\uB7FC \uBA85\uC131\uACFC \uBA85\uC131 \uB54C\uBB38\uC5D0 Liu Bang\uC744 \uB193\uC544\uC8FC\uC9C0 \uB9C8\uC2ED\uC2DC\uC624. \uC5B4\uB5A4 \uACB0\uACFC\uB3C4 \uB0A8\uAE30\uC9C0 \uC54A\uACE0 \uD55C \uBC88\uC5D0 \uC77C\uC744 \uCC98\uB9AC\uD569\uB2C8\uB2E4."},{q:"\uC138\uC0C1\uC740 \uBC1C\uC804\uD558\uACE0 \uBBF8\uB798\uB294 \uBC1D\uC2B5\uB2C8\uB2E4. \uC774\uB7F0 \uC804\uBC18\uC801\uC778 \uC5ED\uC0AC\uC758 \uCD94\uC138\uB294 \uB204\uAD6C\uB3C4 \uBC14\uAFC0 \uC218 \uC5C6\uC2B5\uB2C8\uB2E4.",s:'"\uCDA9\uCE6D\uD611\uC0C1\uC5D0 \uAD00\uD558\uC5EC"(1945\uB144 10\uC6D4)',e:"\uC774\uAC83\uC774 \uC5ED\uC0AC\uBC95\uCE59\uC5D0 \uB300\uD55C \uADFC\uBCF8\uC801\uC778 \uBBFF\uC74C\uC774\uB2E4. \uC6B0\uB9AC\uAC00 \uC544\uBB34\uB9AC \uB9CE\uC740 \uC88C\uC808\uC744 \uACAA\uB354\uB77C\uB3C4 \uC5ED\uC0AC\uC758 \uC804\uBC18\uC801\uC778 \uBC29\uD5A5\uC740 \uC804\uC9C4\uC785\uB2C8\uB2E4. \uC774 \uBBFF\uC74C\uC744 \uC720\uC9C0\uD55C\uB2E4\uBA74 \uC77C\uC2DC\uC801\uC778 \uC5B4\uB824\uC6C0\uC5D0 \uAD74\uBCF5\uD558\uC9C0 \uC54A\uC744 \uAC83\uC785\uB2C8\uB2E4."},{q:"\uC2E4\uD328\uB294 \uC131\uACF5\uC758 \uC5B4\uBA38\uB2C8\uC774\uB2E4",s:'"\uC911\uAD6D \uD601\uBA85 \uC804\uC7C1\uC758 \uC804\uB7B5\uC801 \uBB38\uC81C"(1936\uB144 12\uC6D4)',e:"\uBAA8\uB4E0 \uC2E4\uD328\uC5D0\uB294 \uC131\uACF5\uC758 \uC528\uC557\uC774 \uB2F4\uACA8 \uC788\uC2B5\uB2C8\uB2E4. \uC911\uC694\uD55C \uAC83\uC740 \uC2E4\uD328\uB85C\uBD80\uD130 \uBC30\uC6B8 \uC218 \uC788\uB2E4\uB294 \uAC83\uC785\uB2C8\uB2E4. \uC2E4\uD328\uC5D0 \uB300\uD55C \uB450\uB824\uC6C0 \uC790\uCCB4\uAC00 \uAC00\uC7A5 \uD070 \uC2E4\uD328\uC774\uB2E4."},{q:"\uC5B4\uB824\uC6B4 \uACF3\uC77C\uC218\uB85D \uB354 \uB9CE\uC774 \uAC00\uC57C \uD569\uB2C8\uB2E4. \uC774\uAC83\uC740 \uC88B\uC740 \uB3D9\uC9C0\uC785\uB2C8\uB2E4.",s:'"\uCDA9\uCE6D\uD611\uC0C1\uC5D0 \uAD00\uD558\uC5EC"(1945\uB144 10\uC6D4)',e:"\uC5B4\uB824\uC6C0\uC5D0 \uC815\uBA74\uC73C\uB85C \uB9DE\uC11C\uACE0 \uB3C4\uB9DD\uCE58\uC9C0 \uB9C8\uC138\uC694. \uC5B4\uB824\uC6B4 \uACF3\uC740 \uAC00\uBCBC\uC6B4 \uC77C \uB300\uC2E0 \uBB34\uAC70\uC6B4 \uCC45\uC784\uC744 \uC9C0\uBA70 \uAE30\uC5EC\uD560 \uC218 \uC788\uB294 \uACF3\uC774\uB2E4."},{q:"\uD770 \uC885\uC774 \uD55C \uC7A5, \uBD80\uB2F4 \uC5C6\uC774, \uCD5C\uC2E0\uC758 \uAC00\uC7A5 \uC544\uB984\uB2E4\uC6B4 \uB9D0\uC744 \uC4F0\uAE30 \uC27D\uACE0, \uCD5C\uC2E0\uC758 \uAC00\uC7A5 \uC544\uB984\uB2E4\uC6B4 \uADF8\uB9BC\uC744 \uC27D\uAC8C \uADF8\uB9B4 \uC218 \uC788\uC2B5\uB2C8\uB2E4.",s:'"\uD611\uB3D9\uC870\uD569\uC744 \uC18C\uAC1C\uD558\uB2E4"(1958)',e:"\uB4A4\uB5A8\uC5B4\uC9C0\uACE0 \uACF5\uBC31\uC774 \uC788\uB2E4\uB294 \uAC83\uC740 \uB054\uCC0D\uD55C \uAC83\uC774 \uC544\uB2C8\uB77C, \uC5ED\uC0AC\uC801 \uC9D0\uC774 \uC5C6\uACE0 \uCC98\uC74C\uBD80\uD130 \uB2E4\uC2DC \uC2DC\uC791\uD558\uC5EC \uC0C8\uB86D\uACE0 \uC544\uB984\uB2E4\uC6B4 \uAC83\uC744 \uCC3D\uC870\uD560 \uC218 \uC788\uB2E4\uB294 \uAC83\uC744 \uC758\uBBF8\uD569\uB2C8\uB2E4."},{q:"\uC2A4\uC2A4\uB85C \uD558\uB77C, \uC74C\uC2DD\uACFC \uC758\uBCF5\uC774 \uCDA9\uBD84\uD558\uB77C",s:'"\uC815\uB9AC\uD558\uB77C"(1943\uB144 11\uC6D4)',e:"\uC790\uB9BD\uD558\uACE0 \uAE30\uB2E4\uB9AC\uC9C0 \uB9D0\uACE0 \uC758\uC9C0\uD558\uC9C0 \uB9C8\uC2ED\uC2DC\uC624. \uBD09\uC1C4\uC640 \uC5B4\uB824\uC6C0 \uC18D\uC5D0\uC11C\uB3C4 \uC790\uC2E0\uC758 \uC190\uC5D0 \uC758\uC9C0\uD558\uB294 \uAC83\uB9CC\uC774 \uC9C4\uC815\uC73C\uB85C \uBB38\uC81C\uB97C \uD574\uACB0\uD560 \uC218 \uC788\uC2B5\uB2C8\uB2E4."},{q:"\uAD8C\uB825\uC740 \uCD1D\uAD6C\uC5D0\uC11C \uB098\uC628\uB2E4",s:'"\uC804\uC7C1\uACFC \uC804\uB7B5\uC758 \uBB38\uC81C"(1938\uB144 11\uC6D4)',e:"\uACC4\uAE09\uC0AC\uD68C\uC5D0\uC11C\uB294 \uBB34\uB825 \uC5C6\uC774\uB294 \uC544\uBB34\uAC83\uB3C4 \uC5C6\uB2E4. \uD3C9\uD654\uB294 \uAE30\uB3C4\uB85C \uC774\uB8E8\uC5B4\uC9C0\uB294 \uAC83\uC774 \uC544\uB2C8\uB77C \uD798\uACFC \uD22C\uC7C1\uC744 \uD1B5\uD574 \uC774\uB8E8\uC5B4\uC9D1\uB2C8\uB2E4."},{q:"\uC138\uC0C1\uC758 \uC77C\uC740 \uBCF5\uC7A1\uD558\uACE0 \uB2E4\uC591\uD55C \uC694\uC778\uC5D0 \uC758\uD574 \uACB0\uC815\uB429\uB2C8\uB2E4. \uD55C\uCABD \uBA74\uB9CC \uBCF4\uC9C0 \uB9D0\uACE0 \uBAA8\uB4E0 \uBA74\uC5D0\uC11C \uBB38\uC81C\uB97C \uBC14\uB77C\uBCF4\uC138\uC694",s:'"\uCDA9\uCE6D\uD611\uC0C1\uC5D0 \uAD00\uD558\uC5EC"(1945\uB144 10\uC6D4)',e:"\uC77C\uBC29\uC131\uC740 \uC77C\uBC18\uC801\uC778 \uC0AC\uACE0\uC758 \uD568\uC815\uC785\uB2C8\uB2E4. \uBAA8\uB4E0 \uAC83\uC5D0\uB294 \uC5EC\uB7EC \uCE21\uBA74\uC774 \uC788\uC73C\uBA70, \uC885\uD569\uC801\uC73C\uB85C, \uC5EC\uB7EC \uAC01\uB3C4\uC5D0\uC11C \uBC14\uB77C\uBCFC \uB54C\uB9CC \uC9C4\uC2E4\uC5D0 \uB354 \uAC00\uAE4C\uC6CC\uC9C8 \uC218 \uC788\uC2B5\uB2C8\uB2E4."},{q:"\uC870\uC0AC\uC640 \uC5F0\uAD6C\uB294 '10\uAC1C\uC6D4 \uB9CC\uC5D0 \uC784\uC2E0'\uACFC \uAC19\uACE0, \uBB38\uC81C\uB97C \uD574\uACB0\uD558\uB294 \uAC83\uC740 '\uD558\uB8E8 \uB9CC\uC5D0 \uCD9C\uC0B0'\uACFC \uAC19\uB2E4",s:'"\uBD80\uAD8C\uC8FC\uC758\uC5D0 \uBC18\uB300\uD558\uB2E4"(1930\uB144 5\uC6D4)',e:"\uBB38\uC81C\uB97C \uD574\uACB0\uD558\uAE30 \uC804\uC758 \uC870\uC0AC \uACFC\uC815\uC740 \uC784\uC2E0\uACFC \uB9C8\uCC2C\uAC00\uC9C0\uB85C \uC2DC\uAC04\uACFC \uC778\uB0B4\uAC00 \uD544\uC694\uD569\uB2C8\uB2E4. \uADF8\uB7EC\uB098 \uC870\uC0AC\uAC00 \uCDA9\uBD84\uD558\uBA74 \uD574\uACB0\uCC45\uC740 \uCD9C\uC0B0\uB9CC\uD07C \uC790\uC5F0\uC2A4\uB7FD\uC2B5\uB2C8\uB2E4."},{q:"\uC911\uAD6D\uC778\uB4E4\uC740 \uC8FD\uC74C\uC744 \uB450\uB824\uC6CC\uD558\uC9C0 \uC54A\uB294\uB370, \uC5EC\uC804\uD788 \uC5B4\uB824\uC6C0\uC744 \uB450\uB824\uC6CC\uD569\uB2C8\uAE4C?",s:"\u201C\uC548\uB155, \uC2A4\uD29C\uC5B4\uD2B8\u201D (1949\uB144 8\uC6D4)",e:"\uC8FD\uC74C\uC758 \uC704\uD611\uC774 \uB2E4\uAC00\uC640\uB3C4 \uC774\uACA8\uB0BC \uC218 \uC5C6\uB294 \uC5B4\uB824\uC6C0\uC774 \uB610 \uC788\uC744\uAE4C\uC694? \uBAA9\uC228\uC744 \uAC78\uACE0 \uC0B4\uC544\uB0A8\uACA0\uB2E4\uB294 \uC815\uC2E0\uC774\uB2E4."},{q:"\uBA3C\uC800 \uC0AC\uD68C\uC5D0\uC11C \uB204\uAC00 \uCE5C\uAD6C\uC774\uACE0, \uC0C1\uB300\uBC29\uC774 \uB204\uAD6C\uC778\uC9C0 \uBA85\uD655\uD788 \uD30C\uC545\uD558\uACE0 \uC5B4\uB5BB\uAC8C \uD589\uB3D9\uD560\uC9C0 \uACB0\uC815\uD558\uC138\uC694.",s:'\uC8FC\uC81C\uB294 "\uC911\uAD6D \uC0AC\uD68C\uC758 \uACC4\uAE09 \uBD84\uC11D"(1925\uB144 12\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uB418\uC5C8\uC2B5\uB2C8\uB2E4.',e:"\uC774 \uAE00\uC740 \uACBD\uB85C \uD310\uB2E8\uC774 \uB2E8\uC9C0 \uC5F4\uC815\uC5D0\uB9CC \uAE30\uCD08\uD560 \uC218\uB294 \uC5C6\uACE0, \uBA3C\uC800 \uAC01 \uD074\uB798\uC2A4\uC758 \uC774\uD574\uAD00\uACC4\uB97C \uD30C\uC545\uD574\uC57C \uD568\uC744 \uAC15\uC870\uD569\uB2C8\uB2E4. \uC798\uBABB\uB41C \uBC29\uD5A5\uC73C\uB85C \uC9C4\uD589\uB418\uB294 \uD589\uB3D9\uC744 \uBC29\uC9C0\uD558\uAE30 \uC704\uD574 \uC758\uC9C0\uD560 \uC801\uC808\uD55C \uC0AC\uB78C\uACFC \uB3D9\uB9F9\uC744 \uCC3E\uC73C\uC138\uC694."},{q:"\uC791\uC740 \uAE30\uC9C0\uAC00 \uC124 \uC218 \uC788\uB294 \uB2A5\uB825\uC740 \uC6B4\uC5D0 \uB2EC\uB824 \uC788\uB294 \uAC83\uC774 \uC544\uB2C8\uB77C, \uB369\uC5B4\uB9AC\uC640 \uC9C0\uD615, \uC801\uC758 \uADE0\uC5F4\uC774 \uACF5\uC874\uD558\uB294 \uB370 \uB2EC\uB824 \uC788\uC2B5\uB2C8\uB2E4.",s:'\uC8FC\uC81C\uB294 "\uC65C \uC911\uAD6D\uC758 \uBD89\uC740 \uC815\uAD8C\uC774 \uC874\uC7AC\uD560 \uC218 \uC788\uB294\uAC00?"\uC5D0\uC11C \uBC1C\uCDCC\uB418\uC5C8\uC2B5\uB2C8\uB2E4. \u300B(1928\uB144 10\uC6D4)',e:"\uAE30\uC0AC\uC5D0\uC11C\uB294 \uC77C\uBD80 \uD601\uBA85\uC138\uB825\uC774 \uBC84\uD2F8 \uC218 \uC788\uB294 \uC774\uC720\uB294 \uB300\uC911\uC801 \uAE30\uBC18\uC744 \uAC16\uACE0 \uC801\uC758 \uB0B4\uBD80\uBAA8\uC21C\uACFC \uC720\uB9AC\uD55C \uC9C0\uB9AC\uC801 \uC870\uAC74\uC744 \uC7A5\uC545\uD558\uAE30 \uB54C\uBB38\uC774\uB77C\uACE0 \uC124\uBA85\uD569\uB2C8\uB2E4. \uBAA8\uB4E0 \uC9C0\uC5ED\uC801 \uB3CC\uD30C\uAD6C\uB294 \uC804\uBC18\uC801\uC778 \uD658\uACBD\uC758 \uD310\uB2E8\uACFC \uBD84\uB9AC\uB420 \uC218 \uC5C6\uC2B5\uB2C8\uB2E4."},{q:"\uD300\uC740 \uB2E8\uC21C\uD788 \uC2F8\uC6B8 \uC218\uB294 \uC5C6\uC9C0\uB9CC \uC815\uCE58\uC801 \uBAA9\uD45C, \uC870\uC9C1 \uADDC\uC728 \uBC0F \uD1B5\uC77C\uB41C \uC2A4\uD0C0\uC77C\uC744 \uAC16\uCDB0\uC57C \uD569\uB2C8\uB2E4.",s:"\uC8FC\uC81C\uB294 \u300E\uB2F9\uB0B4 \uC798\uBABB\uB41C \uC0AC\uC0C1 \uBC14\uB85C\uC7A1\uAE30\uC5D0 \uB300\uD558\uC5EC\u300F(1929\uB144 12\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uD55C \uAC83\uC774\uB2E4.",e:"\uC774 \uAE00\uC740 \uC21C\uC804\uD788 \uAD70\uC0AC\uC801 \uACAC\uD574, \uADF9\uB2E8\uC801\uC778 \uBBFC\uC8FC\uD654, \uAC1C\uC778\uC8FC\uC758, \uC8FC\uAD00\uC8FC\uC758 \uB4F1\uC758 \uBB38\uC81C\uB97C \uBC14\uB85C\uC7A1\uB294 \uB370 \uCD08\uC810\uC744 \uB9DE\uCD94\uACE0 \uC870\uC9C1\uC758 \uC804\uD22C \uD6A8\uC728\uC131\uC740 \uACF5\uD1B5\uC758 \uBAA9\uD45C\uC640 \uADDC\uC728\uC5D0\uC11C \uB098\uC628\uB2E4\uB294 \uC810\uC744 \uAC15\uC870\uD569\uB2C8\uB2E4."},{q:"\uACBD\uC81C\uC0AC\uC5C5\uC740 \uD601\uBA85\uC758 \uBD80\uC18D\uD488\uC774 \uC544\uB2D9\uB2C8\uB2E4. \uC0C1\uD669\uC774 \uC5B4\uB824\uC6B8\uC218\uB85D \uACB0\uC0B0\uD558\uACE0, \uC870\uC9C1\uD558\uACE0, \uC0DD\uC0B0\uD560 \uC218 \uC788\uB294 \uB2A5\uB825\uC774 \uB354 \uB9CE\uC774 \uD544\uC694\uD569\uB2C8\uB2E4.",s:"\uC8FC\uC81C\uB294 \u300A\uACBD\uC81C\uC0AC\uC5C5\uC5D0 \uC8FC\uBAA9\uD574\uC57C \uD55C\uB2E4\u300B(1933\uB144 8\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC",e:"\uAE30\uC9C0\uAC74\uC124\uC5D0\uC11C \uC7AC\uC815\uACFC \uC0DD\uC0B0, \uACF5\uAE09\uC740 \uACB0\uCF54 \uC0AC\uC18C\uD55C \uBB38\uC81C\uAC00 \uC544\uB2D9\uB2C8\uB2E4. \uC548\uC815\uC801\uC778 \uC0B6\uC744 \uC0B4 \uC218 \uC788\uB294\uC9C0, \uC790\uC6D0\uC744 \uC798 \uC815\uB9AC\uD560 \uC218 \uC788\uB294\uC9C0 \uC5EC\uBD80\uAC00 \uACBD\uB825\uC758 \uC9C0\uC18D \uC5EC\uBD80\uC640 \uC9C1\uACB0\uB429\uB2C8\uB2E4."},{q:"\uB18D\uCD0C\uC744 \uBD84\uC11D\uD560 \uB54C \uC2AC\uB85C\uAC74\uB9CC \uBCFC \uAC83\uC774 \uC544\uB2C8\uB77C \uD1A0\uC9C0, \uB178\uB3D9, \uC2E4\uC81C \uD61C\uD0DD\uC774 \uC5B4\uB5BB\uAC8C \uBD84\uBC30\uB418\uB294\uC9C0\uB3C4 \uC0B4\uD3B4\uBD10\uC57C \uD55C\uB2E4.",s:"\uC8FC\uC81C\uB294 \u300E\uB18D\uCD0C\uACC4\uAE09\uC744 \uBD84\uC11D\uD558\uB294 \uBC29\uBC95\u300F(1933\uB144 10\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC",e:"\uC774\uB7EC\uD55C \uC720\uD615\uC758 \uBD84\uC11D\uC740 \uC2E4\uC81C \uACBD\uC81C\uC801 \uAD00\uACC4\uB97C \uAE30\uBC18\uC73C\uB85C \uB2E4\uC591\uD55C \uADF8\uB8F9\uC758 \uC704\uCE58\uB97C \uC2DD\uBCC4\uD558\uB294 \uAC83\uC744 \uAC15\uC870\uD569\uB2C8\uB2E4. \uC5B5\uC555\uBC1B\uB294 \uC0AC\uB78C, \uAC1C\uC120\uC758 \uC5EC\uC9C0\uAC00 \uC788\uB294 \uC0AC\uB78C, \uD754\uB4E4\uB9AC\uB294 \uC0AC\uB78C\uC744 \uACB0\uC815\uD558\uB294 \uAC83\uC740 \uAD6C\uCCB4\uC801\uC778 \uC0DD\uD65C \uC870\uAC74\uC5D0 \uB530\uB77C \uB2EC\uB77C\uC9D1\uB2C8\uB2E4."},{q:"\uC815\uCC45\uC5D0\uB294 \uC77C\uC6A9\uD488, \uC300, \uAE30\uB984, \uC18C\uAE08\uC774 \uD3EC\uD568\uB418\uC5B4\uC57C \uD569\uB2C8\uB2E4. \uAD6D\uBBFC\uC774 \uC774\uC775\uC744 \uB290\uAEF4\uC57C \uC0AC\uC5C5\uC774 \uBFCC\uB9AC\uB0B4\uB9B4 \uC218 \uC788\uB2E4.",s:"\uC8FC\uC81C\uB294 \u300A\uC0AC\uB78C\uC758 \uC0DD\uBA85\uC744 \uB3CC\uBCF4\uACE0 \uC0AC\uC5C5\uBC29\uBC95\uC744 \uC911\uC2DC\uD558\uB77C\u300B(1934\uB144 1\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uD55C \uAC83\uC785\uB2C8\uB2E4.",e:"\uC774 \uAE30\uC0AC\uB294 \uB9AC\uB354\uB4E4\uC774 \uC790\uC2E0\uC758 \uC5C5\uBB34\uAC00 \uB2E8\uC9C0 \uD070 \uBAA9\uD45C\uC5D0\uB9CC \uCD08\uC810\uC744 \uB9DE\uCDB0\uC11C\uB294 \uC548 \uB41C\uB2E4\uB294 \uC810\uC744 \uC0C1\uAE30\uC2DC\uCF1C \uC90D\uB2C8\uB2E4. \uC18C\uAE08\uACFC \uC300, \uC8FC\uD0DD, \uC758\uB8CC, \uBAA9\uCD95 \uB4F1 \uAD6C\uCCB4\uC801\uC778 \uBB38\uC81C\uB97C \uC5BC\uB9C8\uB098 \uC798 \uD574\uACB0\uD558\uB290\uB0D0\uC5D0 \uB530\uB77C \uB300\uC911\uC774 \uC9C4\uC815\uC73C\uB85C \uC774\uB97C \uC9C0\uC9C0\uD558\uB294\uC9C0\uAC00 \uC9C1\uC811\uC801\uC73C\uB85C \uACB0\uC815\uB429\uB2C8\uB2E4."},{q:"\uACF5\uB3D9\uC804\uC120\uC740 \uC678\uCCD0\uC57C \uD560 \uAC83\uC774 \uC544\uB2C8\uB77C, \uCD5C\uB300\uD55C \uD3ED\uB113\uC740 \uD798\uC73C\uB85C \uC9C4\uC815\uC73C\uB85C \uC870\uC9C1\uB418\uC5B4\uC57C \uD569\uB2C8\uB2E4.",s:"\uC8FC\uC81C\uB294 \u300A\uBC31\uB9CC\uC778\uBBFC\uC744 \uD56D\uC77C\uBBFC\uC871\uD1B5\uC77C\uC804\uC120\uC73C\uB85C \uB04C\uC5B4\uC624\uAE30 \uC704\uD55C \uD22C\uC7C1\u300B(1937\uB144 5\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uD55C \uAC83\uC785\uB2C8\uB2E4.",e:"\uC911\uC694\uD55C \uAC83\uC740 \uC18C\uC218\uC758 \uC5F4\uC815\uC801\uC778 \uD45C\uD604\uC774 \uC544\uB2C8\uB77C, \uD769\uC5B4\uC838 \uC788\uB294 \uC9D1\uB2E8\uC774 \uACF5\uB3D9\uC758 \uD22C\uC7C1\uC744 \uC704\uD55C \uC138\uB825\uC73C\uB85C \uBC14\uB014 \uC218 \uC788\uB294\uC9C0 \uC5EC\uBD80\uC785\uB2C8\uB2E4. \uC784\uBB34\uAC00 \uC804\uBC18\uC801\uC77C\uC218\uB85D \uAD11\uBC94\uC704\uD55C \uB3D9\uC6D0\uC5D0 \uB354 \uB9CE\uC774 \uC758\uC874\uD569\uB2C8\uB2E4."},{q:"\uBB38\uC81C\uB97C \uBCF4\uACE0\uB3C4 \uBABB \uBCF8 \uCC99\uD558\uACE0, \uAC89\uC73C\uB85C\uB294 \uB2E4\uC815\uD558\uAC8C \uC9C0\uB0B4\uB2E4\uAC00 \uACB0\uAD6D\uC5D0\uB294 \uADF8 \uC0AC\uB78C \uC804\uCCB4\uC5D0\uAC8C \uC0C1\uCC98\uB97C \uC8FC\uB294 \uACBD\uC6B0\uAC00 \uB9CE\uB2E4",s:'\uC8FC\uC81C\uB294 "\uC790\uC720\uC8FC\uC758\uC5D0 \uBC18\uB300\uD558\uB2E4"(1937\uB144 9\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uB418\uC5C8\uC2B5\uB2C8\uB2E4.',e:"\uC774 \uAE00\uC740 \uBE44\uC6D0\uCE59\uC801\uC778 \uC218\uC6A9\uC744 \uC5F0\uB300\uB85C \uAC04\uC8FC\uD558\uB294 \uAC83\uC5D0 \uBC18\uB300\uD569\uB2C8\uB2E4. \uC9C4\uC815\uD55C \uCC45\uC784\uC744 \uC9C4\uB2E4\uB294 \uAC83\uC740 \uAC08\uB4F1\uC744 \uD53C\uD558\uB294 \uAC83\uC774 \uC544\uB2C8\uB77C \uACF5\uB3D9\uC758 \uBAA9\uD45C\uB97C \uC704\uD574 \uAC10\uD788 \uBB38\uC81C\uB97C \uC9C0\uC801\uD558\uACE0 \uC2DC\uC815\uC744 \uCD09\uC9C4\uD558\uB294 \uAC83\uC785\uB2C8\uB2E4."},{q:"\uC2B9\uB9AC\uB294 \uBE60\uB978 \uC0DD\uAC01\uC5D0\uC11C \uC624\uB294 \uACBD\uC6B0\uAC00 \uAC70\uC758 \uC5C6\uC2B5\uB2C8\uB2E4. \uC7A5\uAE30\uC801\uC778 \uC870\uAC74\uC744 \uBA3C\uC800 \uC0B4\uD3B4\uBCF4\uACE0 \uBB34\uB300\uC640 \uB9AC\uB4EC\uC744 \uC815\uB9AC\uD558\uC138\uC694.",s:'\uC8FC\uC81C\uB294 "\uC7A5\uAE30\uC801\uC778 \uC804\uC7C1\uC5D0 \uAD00\uD558\uC5EC"(1938\uB144 5\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC',e:"\uAE30\uC0AC\uC758 \uD575\uC2EC\uC740 \uC804\uB9DD\uC5D0 \uB300\uD55C \uD655\uC2E0\uC744 \uAC16\uB294 \uAC83\uBFD0\uB9CC \uC544\uB2C8\uB77C \uB9F9\uBAA9\uC801\uC778 \uBE44\uAD00\uC8FC\uC758\uB098 \uB9F9\uBAA9\uC801\uC778 \uB099\uAD00\uC8FC\uC758\uB97C \uD53C\uD558\uAE30 \uC704\uD574 \uC801\uACFC \uC6B0\uB9AC \uAD70\uB300, \uAD6D\uC81C \uD658\uACBD, \uC815\uCE58\uC801 \uB3D9\uC6D0 \uBC0F \uC804\uB7B5\uC801 \uB2E8\uACC4\uB97C \uD568\uAED8 \uD310\uB2E8\uD558\uB294 \uAC83\uC785\uB2C8\uB2E4."},{q:"\uD1B5\uC77C\uC804\uC120\uC5D0 \uC11C\uB354\uB77C\uB3C4 \uC790\uC2E0\uC758 \uD310\uB2E8\uACFC \uC870\uC9C1, \uC8FC\uB3C4\uAD8C\uC744 \uC720\uC9C0\uD574\uC57C \uD569\uB2C8\uB2E4.",s:"\uC8FC\uC81C\uB294 \u300E\uD1B5\uC77C\uC804\uC120\uC5D0\uC11C\uC758 \uC790\uC8FC\uC640 \uC790\uC8FC\uC758 \uBB38\uC81C\u300F(1938\uB144 11\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uD55C \uAC83\uC774\uB2E4.",e:"\uD611\uB825\uC740 \uC9C0\uC704\uB97C \uD3EC\uAE30\uD558\uB294 \uAC83\uC744 \uC758\uBBF8\uD558\uC9C0 \uC54A\uC2B5\uB2C8\uB2E4. \uB3C5\uB9BD\uC801\uC778 \uC0AC\uACE0\uC640 \uC870\uC9C1 \uB2A5\uB825\uC744 \uC720\uC9C0\uD574\uC57C\uB9CC \uD611\uB825\uC740 \uC218\uB3D9\uC801\uC778 \uCD94\uC885\uC790\uAC00 \uB418\uC9C0 \uC54A\uC744 \uAC83\uC785\uB2C8\uB2E4."},{q:"\uC815\uCE58\uB178\uC120\uC744 \uAD00\uCCA0\uD558\uAE30 \uC704\uD55C \uBA85\uD655\uD55C \uC120\uC804\uACFC \uC870\uC9C1, \uAC04\uBD80\uB4E4\uC774 \uC5C6\uB2E4\uBA74 \uADF8\uAC83\uC740 \uACE7 \uADF8 \uBAA8\uC2B5\uC744 \uC783\uAC8C \uB420 \uAC83\uC785\uB2C8\uB2E4.",s:'\uC8FC\uC81C\uB294 "\uACF5\uC0B0\uC8FC\uC758\uC790"(1939\uB144 10\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uB418\uC5C8\uC2B5\uB2C8\uB2E4.',e:"\uC774 \uAE00\uC5D0\uC11C\uB294 \uB2F9\uAC74\uC124\uACFC \uD1B5\uC77C\uC804\uC120, \uBB34\uC7A5\uD22C\uC7C1\uC758 \uC5F0\uACC4\uC131\uC744 \uAC15\uC870\uD558\uACE0 \uC788\uB2E4. \uC62C\uBC14\uB978 \uACBD\uB85C\uC5D0\uB294 \uC544\uC774\uB514\uC5B4, \uC870\uC9C1 \uBC0F \uCEE4\uBBA4\uB2C8\uCF00\uC774\uC158 \uB3C4\uAD6C\uC758 \uC9C0\uC6D0\uC774 \uD544\uC694\uD569\uB2C8\uB2E4."},{q:"\uC9C4\uC815\uD55C \uD559\uC2B5\uC740 \uBBF8\uB9AC \uB9CC\uB4E4\uC5B4\uC9C4 \uC77C\uB828\uC758 \uC124\uBA85\uC744 \uC554\uAE30\uD558\uB294 \uAC83\uC774 \uC544\uB2C8\uB77C \uC774\uB860\uC744 \uC0AC\uC6A9\uD558\uC5EC \uB2F9\uBA74\uD55C \uC911\uAD6D\uC758 \uBB38\uC81C\uB97C \uC124\uBA85\uD558\uB294 \uAC83\uC785\uB2C8\uB2E4.",s:"\uC8FC\uC81C\uB294 \uC6B0\uB9AC \uD559\uC2B5\uC758 \uC804\uD658(1941\uB144 5\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uB418\uC5C8\uC2B5\uB2C8\uB2E4.",e:"\uC774 \uAE00\uC740 \uC8FC\uAD00\uC8FC\uC758\uC640 \uB3C5\uB2E8\uC8FC\uC758\uB97C \uBE44\uD310\uD558\uB294 \uB370 \uCD08\uC810\uC744 \uB9DE\uCD94\uACE0 \uC788\uC73C\uBA70, \uD559\uC2B5\uC740 \uC870\uC0AC\uC640 \uC5F0\uAD6C, \uC5ED\uC0AC\uC801 \uACBD\uD5D8\uACFC \uC2E4\uCC9C\uC801 \uBB38\uC81C\uC640 \uACB0\uD569\uB418\uC5B4 \uAD81\uADF9\uC801\uC73C\uB85C \uD2B9\uC815 \uBB38\uC81C \uD574\uACB0\uC5D0 \uC548\uCC29\uD574\uC57C \uD568\uC744 \uAC15\uC870\uD569\uB2C8\uB2E4."},{q:"\uC5C5\uBB34\uBC29\uC2DD \uAD50\uC815\uC740 \uB2E8\uC21C\uD55C \uBAB8\uC9D3\uC774 \uC544\uB2C8\uB77C \uC8FC\uAD00\uC8FC\uC758, \uC885\uD30C\uC8FC\uC758, \uACF5\uD5C8\uD55C \uB9D0\uC5D0 \uB300\uD55C \uC2E4\uC9C8\uC801\uC778 \uC5B5\uC555\uC774\uB2E4",s:"\uC8FC\uC81C\uB294 \u300A\uB2F9\uD48D\uC744 \uBC14\uB85C\uC7A1\uB2E4\u300B(1942\uB144 2\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC",e:"\uC774 \uAE00\uC740 \uC0AC\uACE0\uBC29\uC2DD, \uBC29\uBC95, \uC870\uC9C1\uC0DD\uD65C \uCE21\uBA74\uC5D0\uC11C \uB098\uC05C \uC2A4\uD0C0\uC77C\uC744 \uCCAD\uC0B0\uD560 \uAC83\uC744 \uC694\uAD6C\uD558\uACE0 \uC788\uB2E4. \uC2A4\uD0C0\uC77C \uBB38\uC81C\uB294 \uCD94\uC0C1\uC801\uC73C\uB85C \uBCF4\uC77C \uC218 \uC788\uC9C0\uB9CC \uACB0\uAD6D \uC9C1\uC7A5\uC5D0\uC11C\uC758 \uBE44\uD6A8\uC728\uC131, \uACA9\uCC28 \uBC0F \uC624\uD310\uC73C\uB85C \uBCC0\uD560 \uAC83\uC785\uB2C8\uB2E4."},{q:"\uAE30\uC0AC\uC640 \uC5F0\uC124\uC774 \uACF5\uD5C8\uD558\uACE0 \uC0C1\uD22C\uC801\uC774\uB77C\uBA74 \uC62C\uBC14\uB978 \uC758\uBBF8\uAC00 \uC0AC\uB78C\uB4E4\uC758 \uB9C8\uC74C\uC5D0 \uC804\uB2EC\uB418\uC9C0 \uC54A\uC744 \uAC83\uC785\uB2C8\uB2E4.",s:'\uC8FC\uC81C\uB294 "\uD314\uB2E4\uB9AC \uC57C\uB2F9 \uAE00\uC4F0\uAE30"(1942\uB144 2\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC',e:"\uC774 \uAE00\uC740 \uD604\uC2E4\uACFC \uB3D9\uB5A8\uC5B4\uC9C4 \uD45C\uD604, \uC0AC\uBB3C\uACFC \uB3D9\uB5A8\uC5B4\uC9C4 \uD45C\uD604, \uACBD\uC9C1\uB41C \uC5B8\uC5B4\uB97C \uC9C0\uB2CC \uD45C\uD604\uC5D0 \uBC18\uB300\uD55C\uB2E4. \uC0AC\uB78C\uB4E4\uC744 \uC124\uB4DD\uD558\uB294 \uAC83\uC740 \uC77C\uB828\uC758 \uAC1C\uB150\uC5D0 \uC758\uC874\uD558\uB294 \uAC83\uC774 \uC544\uB2C8\uB77C, \uC774\uD574\uD560 \uC218 \uC788\uB294 \uC0AC\uC2E4, \uB17C\uB9AC, \uB2E8\uC5B4\uC5D0 \uC758\uC874\uD569\uB2C8\uB2E4."},{q:"\uBB38\uD559\uACFC \uC608\uC220\uC740 \uACF5\uC911\uC5D0 \uB5A0 \uC788\uC744 \uC218 \uC5C6\uC2B5\uB2C8\uB2E4. \uD56D\uC0C1 \uC0AC\uB78C\uB4E4\uC758 \uC2E4\uC81C \uC0DD\uD65C, \uAC10\uC815, \uC0C1\uD669\uC5D0 \uBC18\uC751\uD574\uC57C \uD569\uB2C8\uB2E4.",s:"\uC8FC\uC81C\uB294 \u300E\uC60C\uC548\uBB38\uD559\uC608\uC220\uD3EC\uB7FC\uC5D0\uC11C\uC758 \uC5F0\uC124\u300F(1942\uB144 5\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC",e:"\uBCF8 \uC5F0\uC124\uC5D0\uC11C\uB294 \uBB38\uD559\uC608\uC220\uC758 \uBD09\uC0AC\uB300\uC0C1\uACFC \uCC3D\uC870\uC801 \uC785\uC7A5\uC5D0 \uB300\uD574 \uB17C\uD55C\uB2E4. \uD575\uC2EC\uC740 \uCC3D\uC791\uC744 \uC555\uCD95\uD558\uB294 \uAC83\uC774 \uC544\uB2C8\uB77C \uC791\uD488\uC774 \uD604\uC2E4 \uC0AC\uD68C\uC640 \uC5F0\uACB0\uB418\uC5B4\uC57C \uD55C\uB2E4\uB294 \uC810\uC744 \uAC15\uC870\uD558\uB294 \uAC83\uC774\uB2E4."},{q:"\uC77C\uC744 \uD560 \uB54C \uC6B0\uB9AC\uB294 \uADF8 \uC77C\uC5D0 \uB300\uD55C \uC77C\uBC18\uC801\uC778 \uC18C\uBA85\uC744 \uAC00\uC9C8 \uBFD0\uB9CC \uC544\uB2C8\uB77C \uADF8 \uC77C\uC744 \uCCA0\uC800\uD788 \uD558\uAE30 \uC704\uD574 \uBA87 \uAC00\uC9C0 \uC0AC\uD56D\uC5D0 \uCD08\uC810\uC744 \uB9DE\uCDB0\uC57C \uD569\uB2C8\uB2E4.",s:'\uC8FC\uC81C\uB294 "\uB9AC\uB354\uC2ED \uBC29\uBC95\uC5D0 \uAD00\uD55C \uBA87 \uAC00\uC9C0 \uC9C8\uBB38"(1943\uB144 6\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uB418\uC5C8\uC2B5\uB2C8\uB2E4.',e:"\uC774 \uAE00\uC5D0\uC11C\uB294 \uC77C\uBC18\uACFC \uAC1C\uC778\uC758 \uACB0\uD569, \uB9AC\uB354\uC2ED\uACFC \uB300\uC911\uC758 \uACB0\uD569\uC744 \uC81C\uC548\uD558\uACE0 \uC788\uB2E4. \uD070 \uC2AC\uB85C\uAC74\uC744 \uAC16\uB294 \uAC83\uB9CC\uC73C\uB85C\uB294 \uCDA9\uBD84\uD558\uC9C0 \uC54A\uC2B5\uB2C8\uB2E4. \uBA3C\uC800 \uD604\uC9C0 \uACBD\uD5D8\uC744 \uC313\uC740 \uB2E4\uC74C \uC774\uB97C \uB354 \uB113\uC740 \uBC94\uC704\uB85C \uD64D\uBCF4\uD574\uC57C \uD569\uB2C8\uB2E4."},{q:"\uB0A8\uC758 \uC77C\uC744 \uC790\uAE30 \uCC45\uC784\uC73C\uB85C \uC5EC\uAE30\uACE0 \uD558\uB294 \uAC83\uC774 \uCC38\uC73C\uB85C \uAC00\uCE58 \uC788\uB294 \uC815\uC2E0\uC774\uB2E4",s:'\uC8FC\uC81C\uB294 "In Memory of Bethune"(1939\uB144 12\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uB418\uC5C8\uC2B5\uB2C8\uB2E4.',e:"\uC774 \uAE30\uC0AC\uC5D0\uC11C\uB294 Bethune\uC758 \uC5C5\uC801\uC744 \uC0AC\uC6A9\uD558\uC5EC \uC774\uD0C0\uC2EC, \uCC45\uC784\uAC10 \uBC0F \uC6B0\uC218\uC131\uC744 \uAC15\uC870\uD569\uB2C8\uB2E4. \uC804\uBB38\uC131\uACFC \uACF5\uACF5\uC815\uC2E0\uC740 \uBCC4\uAC1C\uAC00 \uC544\uB2C8\uB77C\uB294 \uC810\uC744 \uC77C\uAE68\uC6CC\uC8FC\uB294 \uC5ED\uD560\uC744 \uD569\uB2C8\uB2E4."},{q:"\uC2F8\uC6B8 \uC218 \uC788\uB294 \uAC83\uB9CC\uC73C\uB85C\uB294 \uCDA9\uBD84\uD558\uC9C0 \uC54A\uACE0, \uC0DD\uC0B0\uC744 \uC870\uC9C1\uD558\uACE0, \uBB3C\uC790\uB97C \uAD00\uB9AC\uD558\uACE0, \uC0B6\uC744 \uAC1C\uC120\uD560 \uC218 \uC788\uC5B4\uC57C \uD569\uB2C8\uB2E4.",s:'\uC8FC\uC81C\uB294 "\uC6B0\uB9AC\uB294 \uACBD\uC81C \uC0AC\uC5C5\uC744 \uBC30\uC6CC\uC57C \uD55C\uB2E4"(1945\uB144 1\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uB418\uC5C8\uC2B5\uB2C8\uB2E4.',e:"\uAE30\uC0AC\uC5D0\uC11C\uB294 \uACBD\uC81C\uC5C5\uBB34\uAC00 \uBA87\uBA87 \uBD80\uC11C\uC758 \uC77C\uC774 \uC544\uB2C8\uB77C \uC804\uCCB4 \uC0C1\uD669\uACFC \uAD00\uB828\uB41C \uADFC\uBCF8\uC801\uC778 \uC5C5\uBB34\uC784\uC744 \uAC15\uC870\uD558\uACE0 \uC788\uB2E4. \uC548\uC815\uC801\uC778 \uC0DD\uC0B0\uACFC \uACF5\uAE09\uC774 \uC5C6\uC73C\uBA74 \uB9CE\uC740 \uBAA9\uD45C\uB97C \uC9C0\uC18D\uD560 \uC218 \uC5C6\uC2B5\uB2C8\uB2E4."},{q:"\uC2B9\uB9AC \uD6C4 \uAC00\uC7A5 \uD754\uD55C \uC2E4\uC218\uB294 \uC0C8\uB85C\uC6B4 \uC5B4\uB824\uC6C0\uC744 \uB108\uBB34 \uB2E8\uC21C\uD558\uAC8C \uC0DD\uAC01\uD558\uB294 \uAC83\uC785\uB2C8\uB2E4.",s:"\uC8FC\uC81C\uB294 \u300E\uD56D\uC77C\uC804\uC7C1 \uC2B9\uB9AC \uD6C4 \uD604\uD669\uACFC \uC6B0\uB9AC\uC758 \uC815\uCC45\u300F(1945\uB144 8\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uD558\uC600\uB2E4.",e:"\uC0C1\uD669\uC774 \uC804\uD658\uC810\uC5D0 \uC788\uC744 \uB54C, \uADF8 \uAE30\uC0AC\uB294 \uC0AC\uB78C\uB4E4\uC5D0\uAC8C \uAE68\uC5B4 \uC788\uC73C\uB77C\uACE0 \uC77C\uAE68\uC6CC \uC90D\uB2C8\uB2E4. \uC804\uBC18\uC801\uC778 \uC0C1\uD669\uC774 \uC9C4\uC804\uB428\uC5D0 \uB530\uB77C \uD45C\uBA74\uC801\uC778 \uAE30\uD68C\uC640 \uC7A5\uAE30\uC801\uC778 \uC704\uD5D8\uC744 \uAD6C\uBCC4\uD558\uB294 \uAC83\uC774 \uB354\uC6B1 \uC911\uC694\uD574\uC84C\uC2B5\uB2C8\uB2E4."},{q:"\uB354 \uC774\uC0C1 \uD798\uC774 \uACE0\uB974\uAC8C \uBD84\uBC30\uB418\uC9C0 \uC54A\uACE0 \uACB0\uACFC\uAC00 \uACB0\uC815\uB418\uB294 \uC911\uC694\uD55C \uC21C\uAC04\uC5D0 \uC7A5\uC810\uC774 \uC9D1\uC911\uB429\uB2C8\uB2E4.",s:'\uC8FC\uC81C\uB294 "\uC6B0\uC138\uD55C \uBCD1\uB825\uC744 \uC9D1\uC911\uC2DC\uCF1C \uC801\uC744 \uAC1C\uBCC4\uC801\uC73C\uB85C \uC12C\uBA78\uD558\uB77C"(1946\uB144 9\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uD55C \uAC83\uC774\uB2E4.',e:"\uC774 \uAE00\uC5D0\uC11C\uB294 \uC5B4\uB514\uC5D0\uC11C\uB098 \uD798\uC744 \uC5BB\uC73C\uB824\uACE0 \uC560\uC4F0\uB294 \uAC83\uC774 \uC544\uB2C8\uB77C, \uAC00\uC7A5 \uD655\uC2E4\uD55C \uC810\uC5D0 \uC9D1\uC911\uD558\uB77C\uB294 \uC810\uC744 \uAC15\uC870\uD55C\uB2E4. \uC790\uC6D0\uC774 \uC81C\uD55C\uB418\uC5B4 \uC788\uC73C\uBA74 \uBB34\uBAA8\uD568\uBCF4\uB2E4 \uC120\uD0DD\uC774 \uB354 \uC911\uC694\uD569\uB2C8\uB2E4."},{q:"\uD300\uC744 \uC774\uB044\uB294 \uC0AC\uB78C\uC740 \uBAA8\uB4E0 \uC77C\uC744 \uC2A4\uC2A4\uB85C \uD558\uAE30\uBCF4\uB2E4\uB294 \uBA3C\uC800 \uC0AC\uB78C\uB4E4\uC744 \uC6C0\uC9C1\uC774\uAC8C \uD574\uC57C \uD569\uB2C8\uB2E4.",s:"\uC8FC\uC81C\uB294 \u300E\uB2F9\uC704\uC6D0\uD68C\uC758 \uC0AC\uC5C5\uBC29\uC2DD\u300F(1949\uB144 3\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC",e:"\uAE30\uC0AC\uB294 \uBE44\uC11C\uB97C \uBD84\uB300\uC7A5\uC5D0 \uBE44\uC720\uD558\uACE0 \uC5C5\uBB34 \uBD84\uB2F4, \uD611\uB825, \uD658\uAE30 \uBC0F \uC9D1\uB2E8\uC801 \uC758\uC0AC \uACB0\uC815\uC744 \uAC15\uC870\uD588\uC2B5\uB2C8\uB2E4. \uB9AC\uB354\uC2ED\uC740 \uAC1C\uC778\uC758 \uB2A5\uB825\uC77C \uBFD0\uB9CC \uC544\uB2C8\uB77C, \uC77C\uC744 \uC644\uC218\uD558\uAE30 \uC704\uD574 \uB2E4\uB978 \uC0AC\uB78C\uB4E4\uC744 \uC870\uC9C1\uD558\uB294 \uB2A5\uB825\uC774\uAE30\uB3C4 \uD569\uB2C8\uB2E4."},{q:"\uC0C8 \uC815\uAD8C\uC774 \uAD73\uAC74\uD788 \uC11C\uAE30 \uC704\uD574\uC11C\uB294 \uAD6D\uBBFC\uC758 \uC785\uC7A5\uBFD0 \uC544\uB2C8\uB77C \uB2E4\uC218\uC758 \uC774\uC775\uC744 \uBCF4\uD638\uD560 \uC218 \uC788\uB294 \uC81C\uB3C4\uC801 \uC7A5\uCE58\uB3C4 \uAC16\uCDB0\uC57C \uD55C\uB2E4.",s:"\uC8FC\uC81C\uB294 \u300E\uC778\uBBFC\uBBFC\uC8FC\uB3C5\uC7AC\uC5D0 \uB300\uD558\uC5EC\u300F(1949\uB144 6\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC",e:"\uC774 \uAE00\uC740 \uAD6D\uAC00\uC758 \uC131\uACA9, \uAD6D\uBBFC\uC758 \uC9C0\uC704, \uC815\uCE58\uAD8C\uB825\uC758 \uAE30\uCD08\uB97C \uB17C\uD558\uACE0 \uC788\uB2E4. \uD575\uC2EC\uC740 \uC2DC\uC2A4\uD15C\uC744 \uD65C\uC6A9\uD574 \uB300\uB2E4\uC218 \uAD6D\uBBFC\uC758 \uAD00\uC2EC\uACFC \uC870\uC9C1, \uD589\uB3D9 \uB2A5\uB825\uC744 \uC548\uC815\uC2DC\uD0A4\uB294 \uAC83\uC774\uB2E4."},{q:"\uC5EC\uAC74\uC774 \uC88B\uC544\uC9C8\uC218\uB85D \uC6B0\uB9AC\uB294 \uCC3D\uC5C5\uD560 \uB54C \uAC00\uC84C\uB358 \uC808\uC81C\uC640 \uB2E8\uC21C\uD568, \uB048\uAE30\uB97C \uAE30\uC5B5\uD574\uC57C \uD569\uB2C8\uB2E4.",s:"\uC8FC\uC81C\uB294 \u300A\uD56D\uC0C1 \uD22C\uC7C1\uC2DD\uC744 \uACAC\uC9C0\uD558\uB77C\u300B(1949\uB144 10\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC",e:"\uC774 \uAE30\uC0AC\uC5D0\uC11C \uC0C1\uAE30\uC2DC\uD0A4\uB294 \uB0B4\uC6A9\uC740 \uB9E4\uC6B0 \uC9C1\uC811\uC801\uC785\uB2C8\uB2E4. \uD658\uACBD\uC774 \uAC1C\uC120\uB41C \uD6C4\uC5D0 \uC0AC\uB78C\uB4E4\uC740 \uAE34\uC7A5\uC744 \uD480\uACE0 \uACFC\uC2DC\uD558\uACE0 \uC790\uC2E0\uC758 \uC9C4\uC815\uD55C \uBAA8\uC2B5\uC744 \uC78A\uC5B4\uBC84\uB9B4 \uAC00\uB2A5\uC131\uC774 \uB192\uC2B5\uB2C8\uB2E4. \uC5F4\uC2EC\uD788 \uC77C\uD558\uB294 \uAC83\uC740 \uBB34\uC5C7\uBCF4\uB2E4\uB3C4 \uC77C\uC885\uC758 \uC815\uC2E0\uC801 \uC5B5\uC81C\uC785\uB2C8\uB2E4."},{q:"\uC0C1\uD669\uC774 \uC548\uC815\uB418\uBA74 \uACF3\uACF3\uC5D0 \uC801\uC744 \uB9CC\uB4DC\uB294 \uAC83\uC740 \uBC14\uB78C\uC9C1\uD558\uC9C0 \uC54A\uC2B5\uB2C8\uB2E4. \uBA3C\uC800 \uC9C8\uC11C\uB97C \uC548\uC815\uC2DC\uD0A4\uACE0 \uC6B0\uC120\uC21C\uC704\uB97C \uAD6C\uBCC4\uD574\uC57C \uD569\uB2C8\uB2E4.",s:'\uC8FC\uC81C\uB294 "\uC0AC\uBC29\uC744 \uACF5\uACA9\uD558\uC9C0 \uB9D0\uB77C"(1950\uB144 6\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uD55C \uAC83\uC785\uB2C8\uB2E4.',e:"\uC774 \uAE30\uC0AC\uB294 \uC0C8\uB85C\uC6B4 \uC0C1\uD669\uC5D0\uC11C\uC758 \uC804\uB7B5\uC801 \uB9AC\uB4EC\uC744 \uAC15\uC870\uD569\uB2C8\uB2E4. \uBAA8\uB4E0 \uBAA8\uC21C\uC744 \uB3D9\uC2DC\uC5D0 \uADF9\uB2E8\uC73C\uB85C \uBC00\uC5B4\uBD99\uC77C \uC218\uB294 \uC5C6\uC9C0\uB9CC, \uBA3C\uC800 \uC8FC\uC694 \uBB38\uC81C\uB97C \uD30C\uC545\uD558\uACE0 \uB354 \uB9CE\uC740 \uD798\uC744 \uD558\uB098\uB85C \uBB49\uCE60 \uC218 \uC788\uB3C4\uB85D \uB178\uB825\uD574\uC57C \uD569\uB2C8\uB2E4."},{q:"\uC7AC\uC815\uACFC \uACBD\uC81C \uC0C1\uD669\uC744 \uAC1C\uC120\uD558\uB824\uBA74 \uC5F4\uC815\uC5D0\uB9CC \uC758\uC874\uD560 \uC218 \uC5C6\uC73C\uBA70 \uC9C8\uC11C\uC640 \uD68C\uBCF5, \uC810\uC9C4\uC801 \uBC18\uC804\uC5D0\uB3C4 \uC9D1\uC911\uD574\uC57C \uD569\uB2C8\uB2E4.",s:"\uC8FC\uC81C\uB294 \u300A\uAD6D\uAC00\uC7AC\uC815\uACBD\uC81C\uC801\uD615\uC138\uC758 \uADFC\uBCF8\uC801 \uAC1C\uC120\uC744 \uC704\uD55C \uD22C\uC7C1\u300B(1950\uB144 6\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uD558\uC600\uB2E4.",e:"\uC774 \uAE00\uC740 \uAD6D\uBBFC\uACBD\uC81C\uC758 \uD68C\uBCF5\uC774 \uB2E8\uACC4\uC801\uC73C\uB85C \uC774\uB8E8\uC5B4\uC838\uC57C \uD568\uC744 \uAC15\uC870\uD558\uACE0, \uD0DC\uB9CC\uD568\uACFC \uAE30\uBCF8\uC5D0\uC11C \uC774\uD0C8\uB41C \uC131\uAE09\uD558\uACE0 \uC131\uAE09\uD55C \uC9C4\uC804\uC744 \uBC18\uB300\uD55C\uB2E4."},{q:"\uAD6D\uAC00\uB97C \uAC74\uC124\uD55C\uB2E4\uB294 \uAC83\uC740 \uC5B4\uB290 \uD55C \uCABD\uC5D0\uB9CC \uC9D1\uC911\uD558\uB294 \uAC83\uC774 \uC544\uB2C8\uB77C, \uAD6D\uAC00\uC758 \uC6B0\uC120\uC21C\uC704, \uC5F0\uC548\uACFC \uB0B4\uB959, \uC911\uC559\uACFC \uC9C0\uBC29\uC790\uCE58\uB2E8\uCCB4, \uAC1C\uC778\uC774 \uC870\uD654\uB97C \uC774\uB8E8\uB294 \uAC83\uC785\uB2C8\uB2E4.",s:'\uC8FC\uC81C\uB294 "10\uB300 \uAD00\uACC4\uC5D0 \uAD00\uD558\uC5EC"(1956\uB144 4\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uB418\uC5C8\uC2B5\uB2C8\uB2E4.',e:"\uC774 \uAE30\uC0AC\uC758 \uAC00\uCE58\uB294 \uBCF5\uC7A1\uD55C \uAD00\uACC4\uB97C \uB2E4\uB8E8\uB294 \uB370 \uC788\uC2B5\uB2C8\uB2E4. \uC9C4\uC815\uC73C\uB85C \uC131\uC219\uD55C \uAC70\uBC84\uB10C\uC2A4\uB294 \uB2E8\uC21C\uD788 \uD55C\uCABD \uD3B8\uC744 \uB4DC\uB294 \uAC83\uC774 \uC544\uB2C8\uB77C \uB2E4\uC591\uD55C \uAE34\uC7A5 \uC0AC\uC774\uC758 \uADE0\uD615\uC744 \uCC3E\uACE0 \uBAA8\uB4E0 \uB2F9\uC0AC\uC790\uC758 \uC5F4\uC815\uC744 \uD65C\uC131\uD654\uD558\uB294 \uAC83\uC785\uB2C8\uB2E4."},{q:"\uC0AC\uD68C\uC5D0\uB294 \uB2E4\uC591\uD55C \uC131\uACA9\uC758 \uAC08\uB4F1\uC774 \uC788\uC73C\uBA70, \uC774\uB97C \uCC98\uB9AC\uD558\uB294 \uBC29\uBC95\uC740 \uD1B5\uCE58\uC790\uC640 \uD568\uAED8 \uCE21\uC815\uD560 \uC218 \uC5C6\uC2B5\uB2C8\uB2E4.",s:"\uC8FC\uC81C\uB294 \u300A\uC778\uBBFC\uC911\uC758 \uBAA8\uC21C\uC744 \uC633\uAC8C \uCC98\uB9AC\uD568\uC5D0 \uB300\uD558\uC5EC\u300B(1957\uB144 2\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uD55C \uAC83\uC785\uB2C8\uB2E4.",e:"\uC774 \uAE00\uC740 \uBAA8\uC21C\uC758 \uBCF8\uC9C8\uC744 \uAD6C\uBCC4\uD558\uB294 \uAC83\uC744 \uAC15\uC870\uD558\uACE0 \uB2E8\uC21C\uD654\uB41C \uCC98\uB9AC\uC5D0 \uBC18\uB300\uD569\uB2C8\uB2E4. \uB9CE\uC740 \uBB38\uC81C\uAC00 \uBD80\uC801\uC808\uD558\uAC8C \uCC98\uB9AC\uB418\uBA74 \uC870\uC815\uB420 \uC218 \uC788\uB294 \uC77C\uC774 \uBC18\uB300 \uBC29\uD5A5\uC73C\uB85C \uBC00\uB824\uB0A0 \uAC83\uC785\uB2C8\uB2E4."},{q:"\uAC74\uC124\uC744 \uD560 \uB54C \uC6B0\uB9AC\uB294 \uB300\uBD80\uBD84\uC758 \uC0AC\uB78C\uB4E4\uC758 \uC5F4\uC815\uC744 \uB3D9\uC6D0\uD574\uC57C \uD558\uBA70, \uADF8 \uBC94\uC704\uB97C \uC810\uC810 \uB354 \uCD95\uC18C\uD574\uC11C\uB294 \uC548 \uB429\uB2C8\uB2E4.",s:"\uC8FC\uC81C\uB294 \u300A\uC778\uBBFC\uC911\uC758 \uBAA8\uC21C\uC744 \uC633\uAC8C \uCC98\uB9AC\uD568\uC5D0 \uB300\uD558\uC5EC\u300B(1957\uB144 2\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uD55C \uAC83\uC785\uB2C8\uB2E4.",e:"\uC774 \uAE30\uC0AC\uC5D0\uC11C\uB294 \uC804\uBC18\uC801\uC778 \uACE0\uB824 \uC0AC\uD56D\uACFC \uC801\uC808\uD55C \uC870\uCE58\uB97C \uC81C\uC548\uD569\uB2C8\uB2E4. \uD070 \uC77C\uC744 \uD558\uAE30 \uC704\uD574\uC11C\uB294 \uC18C\uC218\uC758 \uC5F0\uACB0\uACE0\uB9AC\uC5D0\uB9CC \uC11C\uBE44\uC2A4\uB97C \uC81C\uACF5\uD560 \uC218 \uC788\uB294 \uAC83\uC774 \uC544\uB2C8\uB77C \uB354 \uB9CE\uC740 \uC0AC\uB78C\uB4E4\uC758 \uC218\uC6A9\uACFC \uCC38\uC5EC\uB97C \uACE0\uB824\uD574\uC57C \uD569\uB2C8\uB2E4."},{q:"\uC800\uCD95\uC740 \uBE60\uB978 \uD574\uACB0\uCC45\uC774 \uC544\uB2C8\uB77C \uC790\uC6D0\uC774 \uC81C\uD55C\uB418\uC5B4 \uC788\uC744 \uB54C \uC7A5\uAE30\uC801\uC73C\uB85C \uD6A8\uACFC\uC801\uC778 \uC791\uC5C5 \uBC29\uBC95\uC785\uB2C8\uB2E4.",s:"\uC8FC\uC81C\uB294 \u300A\uC778\uBBFC\uC911\uC758 \uBAA8\uC21C\uC744 \uC633\uAC8C \uCC98\uB9AC\uD568\uC5D0 \uB300\uD558\uC5EC\u300B(1957\uB144 2\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uD55C \uAC83\uC785\uB2C8\uB2E4.",e:"\uC774 \uAE30\uC0AC\uB294 \uBCF4\uC874\uC744 \uAD6D\uAC00 \uAC74\uC124\uC758 \uC7A5\uAE30\uC801 \uC870\uAC74\uC5D0 \uD3EC\uD568\uC2DC\uD0B5\uB2C8\uB2E4. \uB300\uADDC\uBAA8 \uAC74\uC124\uC77C\uC218\uB85D \uC0AC\uCE58\uC640 \uAD00\uB8CC\uC8FC\uC758, \uACE0\uB3C4\uC18C\uBE44\uC5D0 \uBC18\uB300\uD574\uC57C \uD569\uB2C8\uB2E4."},{q:"\uB2E4\uB978 \uC0AC\uB78C\uC5D0\uAC8C\uC11C \uBC30\uC6B4\uB2E4\uACE0 \uD574\uC11C \uB530\uB77C\uD558\uB294 \uAC83\uC740 \uC544\uB2D9\uB2C8\uB2E4. \uC9C4\uC815\uD55C \uAE30\uC220\uC740 \uB2E4\uB978 \uC0AC\uB78C\uC758 \uC7A5\uC810\uC744 \uC790\uC2E0\uC758 \uC7A5\uC810\uC73C\uB85C \uBC14\uAFB8\uB294 \uAC83\uC785\uB2C8\uB2E4.",s:'\uC8FC\uC81C\uB294 "10\uB300 \uAD00\uACC4\uC5D0 \uAD00\uD558\uC5EC"(1956\uB144 4\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uB418\uC5C8\uC2B5\uB2C8\uB2E4.',e:"\uC774 \uAE30\uC0AC\uC5D0\uC11C\uB294 \uC678\uAD6D \uACBD\uD5D8\uC744 \uD1B5\uD574 \uBC30\uC6CC\uC57C \uD558\uC9C0\uB9CC \uB3C5\uB9BD\uC801\uC778 \uD310\uB2E8\uB825\uC744 \uC783\uC9C0 \uB9D0\uC544\uC57C \uD568\uC744 \uAC15\uC870\uD569\uB2C8\uB2E4. \uBCF5\uC0AC\uB294 \uAC00\uC7A5 \uC27D\uC9C0\uB9CC \uC790\uC2E0\uC758 \uC870\uAC74\uC5D0 \uAC00\uC7A5 \uBD80\uC801\uD569\uD55C \uACBD\uC6B0\uAC00 \uB9CE\uC2B5\uB2C8\uB2E4."},{q:"\uAC04\uBD80\uC640 \uB300\uC911 \uC0AC\uC774\uC758 \uAD00\uACC4\uAC00 \uAE34\uBC00\uD560\uC218\uB85D \uAC89\uBCF4\uAE30\uC5D0 \uB2E4\uB8E8\uAE30 \uD798\uB4E0 \uAC83\uCC98\uB7FC \uBCF4\uC774\uB294 \uB9CE\uC740 \uBB38\uC81C\uC5D0 \uB300\uD55C \uD574\uACB0\uCC45\uC744 \uCC3E\uB294 \uAC83\uC774 \uB354 \uC26C\uC6CC\uC9C8 \uAC83\uC785\uB2C8\uB2E4.",s:"\uC8FC\uC81C\uB294 \u300A\uD798\uB4E0 \uD22C\uC7C1\uC744 \uACAC\uC9C0\uD558\uBA70 \uB300\uC911\uACFC \uAE34\uBC00\uD788 \uC811\uCD09\uD558\uB77C\u300B(1957\uB144 3\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uD55C \uAC83\uC774\uB2E4.",e:"\uC774\uB7F0 \uC5F0\uC124\uC740 \uB3D9\uC77C\uD55C \uC791\uC5C5 \uB2E8\uC11C\uB97C \uC774\uC5B4\uAC11\uB2C8\uB2E4. \uC2A4\uD0C0\uC77C\uC740 \uC2AC\uB85C\uAC74\uC774 \uC544\uB2C8\uB77C \uD604\uC7A5\uC5D0 \uAE4A\uC219\uC774 \uB4E4\uC5B4\uAC00\uC11C \uC2E4\uC81C \uBAA9\uC18C\uB9AC\uB97C \uB4E3\uACE0 \uC7A5\uBCBD\uC744 \uC904\uC77C \uC218 \uC788\uB294\uC9C0 \uC5EC\uBD80\uC785\uB2C8\uB2E4."},{q:"\uC0C1\uD669\uC774 \uBCC0\uD560 \uB54C \uAC00\uC7A5 \uB450\uB824\uC6B4 \uAC83\uC740 \uC5B4\uC81C\uC758 \uB208\uC73C\uB85C \uC624\uB298\uC758 \uC0C1\uD669\uC744 \uBCF4\uB294 \uAC83\uC774\uB2E4.",s:'\uC8FC\uC81C\uB294 "Things Are Changing"(1957\uB144 5\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uB418\uC5C8\uC2B5\uB2C8\uB2E4.',e:"\uC0C1\uD669\uC774 \uBC14\uB00C\uBA74 \uAE30\uC874 \uD310\uB2E8\uC740 \uC989\uC2DC \uC4F8\uBAA8\uC5C6\uAC8C \uB420 \uC218 \uC788\uC2B5\uB2C8\uB2E4. \uC774 \uAE30\uC0AC\uB294 \uC0AC\uB78C\uB4E4\uC5D0\uAC8C \uC801\uC2DC\uC5D0 \uC790\uC2E0\uC758 \uC774\uD574\uB97C \uC218\uC815\uD558\uACE0, \uB290\uB9AC\uAC70\uB098 \uBD84\uC11D \uB300\uC2E0 \uAC10\uC815\uC744 \uC0AC\uC6A9\uD558\uC9C0 \uB9D0\uB77C\uACE0 \uC0C1\uAE30\uC2DC\uD0B5\uB2C8\uB2E4."},{q:"\uC120\uC804 \uD65C\uB3D9\uC758 \uAC00\uCE58\uB294 \uB354 \uD070 \uC18C\uB9AC\uB97C \uB0B4\uB294 \uAC83\uC774 \uC544\uB2C8\uB77C, \uC0AC\uB78C\uB4E4\uC774 \uBC1B\uC544\uB4E4\uC77C \uC218 \uC788\uB294 \uACF3\uAE4C\uC9C0 \uC9C4\uC2E4\uC744 \uC124\uBA85\uD560 \uC218 \uC788\uB294 \uAC83\uC785\uB2C8\uB2E4.",s:'\uC8FC\uC81C\uB294 "\uC911\uAD6D\uACF5\uC0B0\uB2F9 \uC804\uAD6D\uC120\uC804\uC0AC\uC5C5\uD68C\uC758 \uC5F0\uC124"(1957\uB144 3\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uD55C \uAC83\uC785\uB2C8\uB2E4.',e:"\uC774\uB7EC\uD55C \uB17C\uC758\uB294 \uD64D\uBCF4\uC640 \uAD50\uC721\uC774 \uB300\uC0C1\uC758\uC2DD\uACFC \uBC29\uBC95\uC744 \uAC00\uC838\uC57C \uD568\uC744 \uAC15\uC870\uD55C\uB2E4. \uC790\uC138\uB9CC\uC744 \uCD94\uAD6C\uD558\uACE0 \uD6A8\uACFC\uB97C \uC2E0\uACBD\uC4F0\uC9C0 \uC54A\uC73C\uBA74 \uACB0\uAD6D \uC18C\uC678\uB9CC \uB354 \uCEE4\uC9C8 \uBFD0\uC785\uB2C8\uB2E4."},{q:"\uC758\uACAC\uC774 \uB2E4\uB97C \uACBD\uC6B0 \uBA3C\uC800 \uC633\uACE0 \uADF8\uB984\uACFC \uADF8 \uC131\uACA9\uC744 \uAD6C\uBCC4\uD55C \uB2E4\uC74C \uADF8\uAC83\uC774 \uC8FC\uC7A5\uC778\uC9C0, \uB3C4\uC6C0\uC778\uC9C0, \uC81C\uD55C\uC778\uC9C0 \uACB0\uC815\uD558\uC2ED\uC2DC\uC624.",s:'\uC8FC\uC81C\uB294 "10\uB300 \uAD00\uACC4\uC5D0 \uAD00\uD558\uC5EC"(1956\uB144 4\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uB418\uC5C8\uC2B5\uB2C8\uB2E4.',e:"\uAE30\uC0AC\uB294 \uB2F9\uACFC \uBE44\uB2F9, \uAD8C\uB9AC\uC640 \uBE44\uC758 \uAD00\uACC4\uB97C \uB2E4\uB8F0 \uB54C \uC6D0\uCE59\uC744 \uC900\uC218\uD558\uB418 \uC11C\uB85C \uB2E4\uB978 \uC758\uACAC\uC744 \uD45C\uD604\uD558\uACE0 \uC218\uC815\uD560 \uC218 \uC788\uB294 \uC5EC\uC9C0\uB97C \uB0A8\uACA8\uB450\uC5B4\uC57C \uD55C\uB2E4\uACE0 \uAC15\uC870\uD55C\uB2E4."},{q:"\uB098\uC05C \uC77C\uC774 \uB354 \uC2EC\uD574\uC9C0\uB294 \uAC83\uC774 \uC544\uB2D0 \uC218\uB3C4 \uC788\uC2B5\uB2C8\uB2E4. \uAD00\uAC74\uC740 \uADF8\uB4E4\uC5D0\uAC8C\uC11C \uAD50\uD6C8\uC744 \uCC3E\uC544 \uC81C\uB54C\uC5D0 \uB3CC\uC544\uC124 \uC218 \uC788\uB290\uB0D0 \uD558\uB294 \uAC83\uC774\uB2E4.",s:"\uC8FC\uC81C\uB294 \u300A\uC778\uBBFC\uC911\uC758 \uBAA8\uC21C\uC744 \uC633\uAC8C \uCC98\uB9AC\uD568\uC5D0 \uB300\uD558\uC5EC\u300B(1957\uB144 2\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uD55C \uAC83\uC785\uB2C8\uB2E4.",e:"\uC774 \uAE00\uC740 \uBAA8\uC21C\uACFC \uC0AC\uAC74\uC758 \uBCC0\uD615\uC801 \uC131\uACA9\uC744 \uAC15\uC870\uD569\uB2C8\uB2E4. \uC62C\uBC14\uB974\uAC8C \uCC98\uB9AC\uB418\uB294 \uD55C \uC88C\uC808, \uAC08\uB4F1, \uC2EC\uC9C0\uC5B4 \uD63C\uB3C8\uB3C4 \uAC1C\uC120\uC744 \uAC00\uC838\uC62C \uC218 \uC788\uC2B5\uB2C8\uB2E4."},{q:"\uD55C \uC790\uB9AC\uC5D0 \uC11C\uB294 \uAC83\uC740 \uBCF4\uC218\uC801\uC73C\uB85C \uD558\uB294 \uAC83\uC774 \uC544\uB2C8\uB77C, \uD798\uC744 \uBAA8\uC544 \uAFB8\uC900\uD558\uAC8C \uD589\uB3D9\uD558\uB294 \uAC83\uC785\uB2C8\uB2E4.",s:'\uC8FC\uC81C\uB294 "\uC9D5\uAC15\uC0B0 \uD22C\uC7C1"(1928\uB144 11\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uB418\uC5C8\uC2B5\uB2C8\uB2E4.',e:"\uC774 \uAE00\uC740 \uAE30\uC9C0\uC9C0\uC5ED\uACFC \uAD70\uB300, \uB300\uC911\uC758 \uAD00\uACC4\uC5D0 \uCD08\uC810\uC744 \uB9DE\uCDB0 \uB2E8\uAE30\uC801\uC778 \uAE30\uB3D9\uC791\uC804\uC744 \uCD94\uAD6C\uD558\uAE30\uBCF4\uB2E4\uB294 \uD22C\uC7C1 \uC911\uC5D0 \uAC74\uC124\uD574\uC57C \uD55C\uB2E4\uB294 \uC810\uC744 \uAC15\uC870\uD588\uB2E4."},{q:"\uC815\uCC45\uC774 \uC0DD\uC0B0\uC744 \uD68C\uBCF5\uD558\uACE0 \uAD50\uD658\uC744 \uC6D0\uD65C\uD558\uAC8C \uD558\uC9C0 \uBABB\uD55C\uB2E4\uBA74 \uB9CE\uC740 \uBAA9\uD45C\uAC00 \uBB34\uC0B0\uB420 \uAC83\uC785\uB2C8\uB2E4.",s:"\uC8FC\uC81C\uB294 \uC6B0\uB9AC\uC758 \uACBD\uC81C \uC815\uCC45(1934\uB144 1\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uB418\uC5C8\uC2B5\uB2C8\uB2E4.",e:"\uC774 \uAE00\uC740 \uACBD\uC81C\uC815\uCC45\uC774 \uAD6D\uBBFC\uC758 \uAE30\uBCF8\uC801\uC778 \uC0DD\uD65C\uC744 \uB3CC\uBCFC \uBFD0\uB9CC \uC544\uB2C8\uB77C \uC804\uBC18\uC801\uC778 \uC0C1\uD669\uC5D0 \uB3C4\uC6C0\uC774 \uB418\uC5B4\uC57C \uD55C\uB2E4\uACE0 \uAC15\uC870\uD569\uB2C8\uB2E4. \uAD6C\uD638\uB9CC \uC774\uC57C\uAE30\uD558\uACE0 \uC790\uC6D0\uACFC \uC9C8\uC11C\uB97C \uBB34\uC2DC\uD560 \uC218\uB294 \uC5C6\uC2B5\uB2C8\uB2E4."},{q:"\uB300\uC804\uB7B5\uC744 \uD310\uB2E8\uD558\uB824\uBA74 \uC989\uAC01\uC801\uC778 \uC555\uB825\uBFD0\uB9CC \uC544\uB2C8\uB77C \uC800\uD56D\uC774 \uAD6D\uAC00\uC758 \uD798\uC73C\uB85C \uB2E8\uACB0\uD560 \uC218 \uC788\uB294\uC9C0\uB3C4 \uC0B4\uD3B4\uBD10\uC57C \uD569\uB2C8\uB2E4.",s:"\uC8FC\uC81C\uB294 \u300E\uC77C\uBCF8\uC758 \uACF5\uC138\uB97C \uBC18\uB300\uD558\uB294 \uC6D0\uCE59, \uBC29\uBC95 \uBC0F \uC804\uB9DD\u300F(1937\uB144 7\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC",e:"\uC774 \uAE00\uC740 \uC804\uBA74 \uC800\uD56D \uC804\uC7C1\uC744 \uC55E\uB454 \uC0C1\uD669\uC5D0 \uB300\uD55C \uD310\uB2E8\uC5D0 \uCD08\uC810\uC744 \uB9DE\uCD94\uACE0 \uBCF5\uC7A1\uD55C \uC704\uD611\uC5D0 \uB9DE\uC11C \uBA3C\uC800 \uC774\uD574\uB97C \uD1B5\uC77C\uD55C \uB2E4\uC74C \uD55C\uB9C8\uC74C\uC73C\uB85C \uD589\uB3D9\uD574\uC57C \uD568\uC744 \uAC15\uC870\uD569\uB2C8\uB2E4."},{q:"\uD070 \uC77C\uC774 \uC624\uBA74 \uAC00\uC7A5 \uC911\uC694\uD55C \uAC83\uC740 \uD769\uC5B4\uC838 \uC788\uB294 \uC778\uB825\uACFC \uC790\uC6D0\uC744 \uB3D9\uC6D0\uD558\uB294 \uAC83\uC774\uB2E4.",s:"\uC8FC\uC81C\uB294 \u300A\uD56D\uC77C\uC804\uC7C1\uC2B9\uB9AC\uB97C \uC704\uD55C \uC804\uAD70\uB3D9\uC6D0\uD22C\uC7C1\u300B(1937\uB144 8\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uD55C \uAC83\uC774\uB2E4.",e:"\uAE30\uC0AC\uC5D0\uC11C\uB294 \uC800\uD56D\uC804\uC7C1\uC774 \uC18C\uC218\uC758 \uBB38\uC81C\uAC00 \uC544\uB2C8\uB77C \uC0AC\uD68C \uC804\uCCB4\uC758 \uC870\uC9C1\uC801\uC778 \uD589\uB3D9\uC774 \uB418\uC5B4\uC57C \uD568\uC744 \uAC15\uC870\uD558\uACE0 \uC788\uB2E4."},{q:"\uD611\uB825\uC774 \uC2DC\uC791\uB41C \uD6C4 \uC2E4\uC81C \uD14C\uC2A4\uD2B8\uAC00 \uC2DC\uC791\uB418\uC5C8\uC2B5\uB2C8\uB2E4.",s:'\uC8FC\uC81C\uB294 "\uAD6D\uBBFC\uB2F9\uACFC \uACF5\uC0B0\uB2F9 \uD569\uC791 \uC774\uD6C4\uC758 \uC2DC\uAE09\uD55C \uACFC\uC5C5"(1937\uB144 9\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uD55C \uAC83\uC774\uB2E4.',e:"\uC774 \uAE30\uC0AC\uB294 \uACF5\uB3D9\uC804\uC120\uC744 \uAD6C\uCD95\uD55C\uB2E4\uACE0 \uD574\uC11C \uBB38\uC81C\uAC00 \uC800\uC808\uB85C \uD574\uACB0\uB418\uB294 \uAC83\uC740 \uC544\uB2C8\uB77C\uB294 \uC810\uC744 \uC0C1\uAE30\uC2DC\uD0A8\uB2E4. \uB354\uC6B1 \uC911\uC694\uD55C \uAC83\uC740 \uC2E4\uC81C \uC5C5\uBB34\uC640 \uC2E4\uD589 \uC218\uC900\uAE4C\uC9C0 \uD611\uB825\uC774 \uC774\uB8E8\uC5B4\uC838\uC57C \uD55C\uB2E4\uB294 \uC810\uC774\uB2E4."},{q:"\uC790\uC2E0\uC744 \uC678\uBD80 \uC138\uACC4\uC5D0 \uC124\uBA85\uD558\uB294 \uAC83\uC740 \uC774\uD574\uB97C \uC704\uD574 \uB178\uB825\uD558\uB294 \uAC83\uBFD0\uB9CC \uC544\uB2C8\uB77C \uC8FC\uB3C4\uC131\uC744 \uC704\uD574 \uB178\uB825\uD558\uB294 \uAC83\uC785\uB2C8\uB2E4.",s:'\uC8FC\uC81C\uB294 "\uC601\uAD6D \uC5B8\uB860\uC778 \uBCA0\uB974\uD2B8\uB791\uACFC\uC758 \uB300\uD654"(1937\uB144 10\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uD55C \uAC83\uC785\uB2C8\uB2E4.',e:"\uC774\uB7EC\uD55C \uC720\uD615\uC758 \uB300\uD654 \uD14D\uC2A4\uD2B8\uB294 \uAD6D\uC81C \uC5EC\uB860 \uBC0F \uC138\uACC4 \uD328\uD134\uC758 \uB9E5\uB77D\uC5D0\uC11C \uAD6D\uB0B4 \uD22C\uC7C1\uC744 \uD45C\uD604\uD558\uB294 \uB2A5\uB825\uC744 \uBC18\uC601\uD569\uB2C8\uB2E4."},{q:"\uC0C1\uD669\uC774 \uAE09\uBC15\uD574\uC9C8\uC218\uB85D \uC190\uC2E4\uC5D0\uB9CC \uC9D1\uC911\uD560 \uC218 \uC5C6\uAC8C \uB418\uBA70 \uD5A5\uD6C4 \uBC18\uACA9\uC744 \uC5B4\uB5BB\uAC8C \uC870\uC9C1\uD560 \uAC83\uC778\uC9C0\uB3C4 \uACE0\uB824\uD558\uAC8C \uB429\uB2C8\uB2E4.",s:"\uC8FC\uC81C\uB294 \u300E\uC0C1\uD574\uC640 \uD0DC\uC6D0 \uD568\uB77D \uC774\uD6C4 \uD56D\uC77C\uC804\uC7C1\uC758 \uC815\uC138\uC640 \uACFC\uC81C\u300F(1937\uB144 11\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uD558\uC600\uB2E4.",e:"\uC774 \uAE00\uC740 \uB300\uD328 \uD6C4\uC5D0\uB3C4 \uC804\uC7C1\uC5D0 \uC800\uD56D\uD558\uACE0 \uB3D9\uC6D0\uC744 \uACC4\uC18D\uD558\uACA0\uB2E4\uB294 \uACE0\uC9D1\uC744 \uAC70\uB4ED \uAC15\uC870\uD558\uACE0, \uC77C\uC2DC\uC801\uC778 \uC190\uC2E4\uB85C \uC778\uD55C \uC804\uBC18\uC801\uC778 \uBE44\uAD00\uB860\uC5D0 \uBC18\uB300\uD55C\uB2E4."},{q:"\uC57D\uD55C \uCABD\uC740 \uACF5\uAC04, \uC9C8\uB7C9, \uC774\uB3D9\uC131\uC744 \uC790\uC2E0\uC758 \uBB34\uAE30\uB85C \uBC14\uAFD4\uC57C \uD569\uB2C8\uB2E4.",s:"\uC8FC\uC81C\uB294 \u300E\uD56D\uC77C\uC720\uACA9\uC804\uC758 \uC804\uB7B5\uC801 \uBB38\uC81C\u300F(1938\uB144 5\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC",e:"\uC774 \uAE30\uC0AC\uB294 \uAC8C\uB9B4\uB77C\uC804\uC774 \uC5B4\uB5BB\uAC8C \uC804\uBC18\uC801\uC778 \uC804\uB7B5\uC5D0 \uAE30\uC5EC\uD558\uB294\uC9C0 \uCCB4\uACC4\uC801\uC73C\uB85C \uB17C\uC758\uD558\uBA70, \uC720\uC5F0\uD55C \uC804\uC7C1\uC740 \uB2E8\uD3B8\uC801\uC778 \uC2DC\uB3C4\uAC00 \uC544\uB2C8\uB77C\uB294 \uC810\uC744 \uBCF4\uC5EC\uC90D\uB2C8\uB2E4."},{q:"\uB9AC\uB354\uC2ED \uC5ED\uD560\uC744 \uB9E1\uACE0 \uC2F6\uB2E4\uBA74 \uBA3C\uC800 \uAC00\uC7A5 \uC5B4\uB824\uC6B4 \uACF3\uC5D0\uC11C \uC2E4\uC9C8\uC801\uC778 \uCC45\uC784\uC744 \uC838\uC57C \uD569\uB2C8\uB2E4.",s:'\uC8FC\uC81C\uB294 "\uAD6D\uB0B4\uC804\uC7C1\uC5D0\uC11C\uC758 \uC911\uAD6D\uACF5\uC0B0\uB2F9\uC758 \uC785\uC7A5"(1938\uB144 10\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uD55C \uAC83\uC785\uB2C8\uB2E4.',e:"\uC774 \uAE00\uC740 \uB2F9\uC758 \uC704\uC0C1\uC774 \uC790\uAE30\uC120\uC5B8\uBCF4\uB2E4\uB294 \uC2E4\uC81C \uD22C\uC7C1\uC5D0\uC11C\uC758 \uCC45\uC784\uACFC \uC131\uACFC\uC5D0\uC11C \uB098\uC628\uB2E4\uB294 \uC810\uC744 \uAC15\uC870\uD55C\uB2E4."},{q:"\uC9C4\uC815\uC73C\uB85C \uC601\uD5A5\uB825\uC744 \uBBF8\uCE60 \uC218 \uC788\uB294 \uCCAD\uB144\uC6B4\uB3D9\uC740 \uC0AC\uD68C\uC758 \uC804\uBC18\uC801\uC778 \uBC29\uD5A5\uACFC \uC5F0\uACB0\uB418\uC5B4\uC57C \uD55C\uB2E4.",s:'\uC8FC\uC81C\uB294 "5\xB74\uC6B4\uB3D9"(1939\uB144 5\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC',e:"\uC774 \uAE00\uC740 5\xB74\uC6B4\uB3D9 \uAE30\uB150\uC744 \uD1B5\uD574 \uCCAD\uB144\uB4E4\uC774 \uACE0\uB9BD\uB41C \uC9D1\uB2E8\uC774 \uC544\uB2C8\uBA70, \uC774\uB4E4\uC758 \uBC29\uD5A5\uC740 \uAD6D\uAC00\uC801\xB7\uC0AC\uD68C\uC801 \uBCC0\uD654\uC758 \uB9E5\uB77D\uC5D0\uC11C \uD310\uB2E8\uB418\uC5B4\uC57C \uD568\uC744 \uC124\uBA85\uD55C\uB2E4."},{q:"\uC80A\uC74C\uC758 \uAC00\uC7A5 \uC18C\uC911\uD55C \uAC83\uC740 \uC5F4\uC815 \uADF8 \uC790\uCCB4\uAC00 \uC544\uB2C8\uB77C \uC5F4\uC815\uC744 \uC62C\uBC14\uB978 \uBC29\uD5A5\uC73C\uB85C \uB098\uC544\uAC00\uAC8C \uD558\uB294 \uAC83\uC774\uB2E4",s:"\uC8FC\uC81C\uB294 \u300E\uCCAD\uB144\uC6B4\uB3D9\uC758 \uBC29\uD5A5\u300F(1939\uB144 5\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC",e:"\uC774 \uAE00\uC740 \uCCAD\uB144\uC131\uC7A5\uACFC \uC2DC\uB300\uC801 \uACFC\uC81C\uC758 \uAD00\uACC4\uB97C \uAC15\uC870\uD558\uACE0 \uBC29\uD5A5\uC131\uC774 \uC5C6\uB294 \uBAB8\uC9D3\uC5D0\uB9CC \uBC18\uB300\uD55C\uB2E4."},{q:"\uC0C1\uD669\uC740 \uBCC0\uD558\uACE0 \uC788\uC73C\uBA70, \uC5C5\uBB34\uB3C4 \uBCC0\uD574\uC57C \uD569\uB2C8\uB2E4. \uC6B0\uB9AC\uB294 \uC624\uB798\uB41C \uACBD\uD5D8\uC5D0 \uC9D1\uCC29\uD560 \uC218 \uC5C6\uC2B5\uB2C8\uB2E4.",s:"\uC8FC\uC81C\uB294 \u300E\uB2F9\uC758 \uC815\uC138\uC640 \uACFC\uC5C5\u300F(1939\uB144 10\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC",e:"\uAE30\uC0AC\uC5D0\uC11C\uB294 \uC0C8\uB85C\uC6B4 \uC0C1\uD669\uC5D0 \uB530\uB77C \uC5C5\uBB34 \uC6B0\uC120\uC21C\uC704\uB97C \uC870\uC815\uD558\uACE0 \uD310\uB2E8\uACFC \uC2E4\uD589\uC744 \uC5F0\uACB0\uD574\uC57C \uD55C\uB2E4\uACE0 \uAC15\uC870\uD569\uB2C8\uB2E4."},{q:"\uBE44\uC988\uB2C8\uC2A4 \uADDC\uBAA8\uAC00 \uD074\uC218\uB85D \uB3D9\uC77C\uD55C \uBC30\uACBD\uACFC \uB3D9\uC77C\uD55C \uC720\uD615\uC758 \uACBD\uD5D8\uC744 \uAC00\uC9C4 \uC0AC\uB78C\uB4E4\uC5D0\uAC8C\uB9CC \uC758\uC874\uD560 \uC218\uB294 \uC5C6\uC2B5\uB2C8\uB2E4.",s:'\uC8FC\uC81C\uB294 "\uB9CE\uC740 \uC9C0\uC2DD\uC778 \uD761\uC218"(1939 \uB144 12 \uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uB418\uC5C8\uC2B5\uB2C8\uB2E4.',e:"\uC774 \uAE30\uC0AC\uB294 \uC9C0\uC2DD\uC778\uC744 \uD3ED\uB113\uAC8C \uD761\uC218\uD558\uB294 \uAC83\uC758 \uC911\uC694\uC131\uC744 \uAC15\uC870\uD569\uB2C8\uB2E4. \uD575\uC2EC\uC740 \uACF5\uB3D9 \uBAA9\uD45C\uC5D0 \uB354 \uB9CE\uC740 \uC804\uBB38 \uC778\uB825\uC744 \uCC38\uC5EC\uC2DC\uD0A4\uB294 \uAC83\uC785\uB2C8\uB2E4."},{q:"\uD601\uBA85\uC744 \uC774\uD574\uD558\uB824\uBA74 \uBA3C\uC800 \uB098\uB77C\uC758 \uB825\uC0AC\uC801\uC870\uAC74\uACFC \uD604\uC2E4\uAD6C\uC870\uB97C \uC774\uD574\uD574\uC57C \uD569\uB2C8\uB2E4.",s:'\uC8FC\uC81C\uB294 "\uC911\uAD6D \uD601\uBA85\uACFC \uC911\uAD6D \uACF5\uC0B0\uB2F9"(1939\uB144 12\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uB418\uC5C8\uC2B5\uB2C8\uB2E4.',e:"\uC774 \uAE00\uC740 \uC911\uAD6D\uC0AC\uD68C\uC758 \uC131\uACA9\uACFC \uD601\uBA85\uB300\uC0C1, \uBB34\uB300\uACFC\uC81C\uB97C \uCCB4\uACC4\uC801\uC73C\uB85C \uC815\uB9AC\uD558\uACE0, \uAD6D\uAC00\uC801 \uC0C1\uD669\uC5D0 \uB530\uB978 \uAE38 \uC774\uD574\uB97C \uAC15\uC870\uD558\uACE0 \uC788\uB2E4."},{q:"\uACFC\uB3C4\uAE30 \uB2E8\uACC4\uB294 \uD55C \uBB38\uC7A5\uC73C\uB85C \uC815\uB9AC\uD560 \uC218 \uC5C6\uC2B5\uB2C8\uB2E4. \uC2DC\uC2A4\uD15C \uC124\uACC4\uB294 \uC2E4\uC81C \uC870\uAC74\uACFC \uC77C\uCE58\uD574\uC57C \uD569\uB2C8\uB2E4.",s:'\uC8FC\uC81C\uB294 "\uC2E0\uBBFC\uC8FC\uC8FC\uC758\uC5D0 \uB300\uD558\uC5EC"(1940\uB144 1\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC',e:"\uC774 \uAE00\uC5D0\uC11C\uB294 \uD601\uBA85\uB2E8\uACC4\uC640 \uC815\uCE58\uBB38\uD654\uC758 \uBC29\uD5A5\uC744 \uB17C\uD558\uACE0, \uC0C8\uB85C\uC6B4 \uB2E8\uACC4\uC5D0\uB294 \uCCB4\uC81C\uC640 \uC0AC\uC0C1\uC801 \uD45C\uD604\uC758 \uC870\uD654\uAC00 \uD544\uC694\uD558\uB2E4\uB294 \uC810\uC744 \uAC15\uC870\uD55C\uB2E4."},{q:"\uC815\uCE58\uC801 \uD615\uD0DC\uC5D0 \uC788\uC5B4\uC11C \uC911\uC694\uD55C \uAC83\uC740 \uC774\uB984\uC774 \uC544\uB2C8\uB77C \uADF8\uAC83\uC774 \uB2E4\uC218 \uAD6D\uBBFC\uC758 \uC774\uC775\uC744 \uC804\uB2EC\uD560 \uC218 \uC788\uB294\uC9C0 \uC5EC\uBD80\uC774\uB2E4.",s:'\uC8FC\uC81C\uB294 "\uC2E0\uBBFC\uC8FC\uC8FC\uC758 \uC785\uD5CC\uC815\uBD80"(1940\uB144 2\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC',e:"\uC774 \uAE00\uC740 \uC785\uD5CC\uC8FC\uC758\uB97C \uB17C\uD560 \uB54C \uD615\uC2DD\uC801\uC778 \uBAA8\uBC29\uC5D0 \uADF8\uCE58\uC9C0 \uC54A\uACE0 \uC815\uCE58 \uCCB4\uC81C\uAC00 \uC9C4\uC815\uD55C \uC0AC\uD68C \uBCC0\uD654\uC5D0 \uAE30\uC5EC\uD574\uC57C \uD55C\uB2E4\uB294 \uC810\uC744 \uAC15\uC870\uD55C\uB2E4."},{q:"\uAE30\uC9C0 \uC9C0\uC5ED\uC740 \uAD70\uB300\uBFD0 \uC544\uB2C8\uB77C \uB300\uC911\uC774 \uC778\uC815\uD560 \uC218 \uC788\uB294 \uC815\uCE58\uC801 \uBC30\uCE58\uB3C4 \uC548\uC815\uC801\uC73C\uB85C \uC774\uB8E8\uC5B4\uC838\uC57C \uD569\uB2C8\uB2E4.",s:"\uC8FC\uC81C\uB294 \u300E\uD56D\uC77C\uADFC\uAC70\uC9C0 \uC9C0\uC5ED\uC758 \uC815\uCE58\uAD8C\uB825\uC758 \uBB38\uC81C\u300F(1940\uB144 3\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC",e:"\uC774 \uAE00\uC740 \uC815\uCE58 \uAD8C\uB825 \uAD6C\uC131, \uB300\uD45C\uC131, \uAC70\uBC84\uB10C\uC2A4 \uBC29\uC2DD\uC5D0 \uCD08\uC810\uC744 \uB9DE\uCDB0 \uC870\uC9C1 \uD615\uD0DC\uAC00 \uB300\uC911\uC758 \uC9C0\uC9C0 \uAE30\uBC18\uB9CC\uD07C \uC911\uC694\uD558\uB2E4\uACE0 \uC124\uBA85\uD588\uB2E4."},{q:"\uACF5\uB3D9\uC804\uC120\uC758 \uC804\uB7B5\uC740 \uBAA8\uB4E0 \uC0AC\uB78C\uC744 \uAE30\uC058\uAC8C \uD558\uB294 \uAC83\uC774 \uC544\uB2C8\uB77C \uC6D0\uCE59\uACFC \uB9AC\uB4EC\uC744 \uACAC\uC2E4\uD558\uAC8C \uC720\uC9C0\uD558\uB294 \uAC83\uC785\uB2C8\uB2E4.",s:"\uC8FC\uC81C\uB294 \u300A\uD604 \uD56D\uC77C\uD1B5\uC77C\uC804\uC120\uC758 \uC804\uB7B5\uC801 \uBB38\uC81C\u300B(1940\uB144 3\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uD55C \uAC83\uC785\uB2C8\uB2E4.",e:"\uAE30\uC0AC\uC5D0\uC11C\uB294 \uD611\uB825\uACFC \uD22C\uC7C1\uC774 \uACF5\uC874\uD558\uB294 \uD658\uACBD\uC5D0\uC11C\uB294 \uD568\uBD80\uB85C \uC804\uC9C4\uD560 \uC218\uB3C4, \uC9C0\uC704\uB97C \uC783\uC744 \uC218\uB3C4 \uC5C6\uC74C\uC744 \uAC15\uC870\uD55C\uB2E4."},{q:"\uC5B5\uC555\uC5D0 \uC9C1\uBA74\uD588\uC744 \uB54C \uAC00\uC7A5 \uD6A8\uACFC\uC801\uC778 \uB300\uC751\uC740 \uD6C4\uD1F4\uD558\uB294 \uAC83\uC774 \uC544\uB2C8\uB77C \uC790\uC2E0\uC758 \uD798\uC744 \uB354\uC6B1 \uD655\uACE0\uD558\uAC8C \uD0A4\uC6B0\uB294 \uAC83\uC77C \uB54C\uAC00 \uB9CE\uC2B5\uB2C8\uB2E4.",s:'\uC8FC\uC81C\uB294 "\uBC18\uC77C\uC138\uB825\uC744 \uD3EC\uAE30\uD558\uACE0 \uBC18\uACF5\uAC15\uC0AC\uB4E4\uC758 \uACF5\uACA9\uC5D0 \uC800\uD56D\uD558\uB77C"(1940\uB144 5\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uD55C \uAC83\uC774\uB2E4.',e:"\uAE30\uC0AC\uC5D0\uC11C\uB294 \uC2A4\uD2B8\uB808\uC2A4\uAC00 \uB9CE\uC740 \uD658\uACBD \uC18D\uC5D0\uC11C\uB3C4 \uC18C\uADF9\uC801 \uC0C1\uD669\uC744 \uC801\uADF9\uC801\uC73C\uB85C \uD574\uACB0\uD558\uAE30 \uC704\uD574\uC11C\uB294 \uB300\uC911 \uAE30\uBC18\uACFC \uC870\uC9C1 \uC5ED\uB7C9\uC744 \uD655\uB300\uD558\uB294 \uAC83\uC774 \uC5EC\uC804\uD788 \uD544\uC694\uD558\uB2E4\uACE0 \uAC15\uC870\uD558\uACE0 \uC788\uB2E4."},{q:"\uC9C4\uC815\uD55C \uC5F0\uD569\uC740 \uC77C\uC2DC\uC801\uC778 \uC870\uD654\uAC00 \uC544\uB2C8\uB77C \uC7A5\uAE30\uC801\uC778 \uC555\uBC15 \uC18D\uC5D0\uC11C\uB3C4 \uC9C0\uC18D\uB418\uB294 \uAC83\uC785\uB2C8\uB2E4.",s:'\uC8FC\uC81C\uB294 "United to the End"(1940\uB144 7\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uB418\uC5C8\uC2B5\uB2C8\uB2E4.',e:"\uAE30\uC0AC\uC5D0\uC11C\uB294 \uB2E8\uACB0\uC744 \uACE0\uC218\uD558\uB824\uBA74 \uC6D0\uCE59\uBFD0 \uC544\uB2C8\uB77C \uC778\uB0B4\uC640 \uC9C0\uC18D\uC131\uB3C4 \uD544\uC694\uD558\uB2E4\uB294 \uC810\uC744 \uAC15\uC870\uD569\uB2C8\uB2E4."},{q:"\uC815\uCC45\uC740 \uCD94\uC0C1\uC801\uC778 \uC120\uD638\uAC00 \uC544\uB2C8\uB77C \uC2E4\uC81C \uAC08\uB4F1\uC744 \uB2E4\uB8E8\uB294 \uAD6C\uCCB4\uC801\uC778 \uBC29\uBC95\uC785\uB2C8\uB2E4.",s:'\uC8FC\uC81C\uB294 "\uC815\uCC45\uC5D0 \uAD00\uD558\uC5EC"(1940\uB144 12\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC',e:"\uC774 \uAE30\uC0AC\uB294 \uC0AC\uB78C\uB4E4\uC5D0\uAC8C \uC62C\uBC14\uB978 \uACBD\uB85C\uB97C \uAC16\uB294 \uAC83\uB9CC\uC73C\uB85C\uB294 \uCDA9\uBD84\uD558\uC9C0 \uC54A\uACE0 \uC774\uB97C \uB2E4\uC591\uD55C \uC9C0\uC5ED\uACFC \uAC1C\uCCB4\uC5D0 \uC801\uC751\uD558\uB294 \uC815\uCC45\uC73C\uB85C \uC804\uD658\uD558\uB294 \uAC83 \uB610\uD55C \uC0C1\uAE30\uC2DC\uCF1C \uC90D\uB2C8\uB2E4."},{q:"\uCDA9\uACA9\uC744 \uACAC\uB51C \uB54C\uB9C8\uB2E4 \uACBD\uD5D8\uC744 \uBBF8\uB798\uC5D0 \uC0AC\uC6A9\uD560 \uC218 \uC788\uB294 \uBC29\uBC95\uC73C\uB85C \uC694\uC57D\uD574\uC57C \uD569\uB2C8\uB2E4.",s:"\uC8FC\uC81C\uB294 \u300E\uC81C2\uCC28 \uBC18\uACF5\uB300\uC870 \uD0C0\uD30C\uC694\uC57D\u300F(1941\uB144 5\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uD55C \uAC83\uC774\uB2E4.",e:"\uAE30\uC0AC\uC5D0\uC11C\uB294 \uC815\uCE58\uC801, \uAD70\uC0AC\uC801 \uC555\uB825\uC5D0 \uB300\uC751\uD558\uC5EC \uB2E8\uAE30\uC801\uC778 \uC190\uC775\uC5D0\uB9CC \uCD08\uC810\uC744 \uB458 \uAC83\uC774 \uC544\uB2C8\uB77C \uC7AC\uD604 \uAC00\uB2A5\uD55C \uB300\uC751 \uACBD\uD5D8\uB3C4 \uD0A4\uC6CC\uC57C \uD55C\uB2E4\uACE0 \uAC15\uC870\uD569\uB2C8\uB2E4."},{q:"\uAD6D\uC81C\uC815\uC138\uB97C \uBCFC \uB54C \uD53C\uC0C1\uC801\uC778 \uC218\uC0AC\uC5D0\uB9CC \uADC0\uB97C \uAE30\uC6B8\uC77C \uAC83\uC774 \uC544\uB2C8\uB77C, \uB204\uAC00 \uD3C9\uD654\uB77C\uB294 \uC774\uB984\uC73C\uB85C \uB354 \uD070 \uC704\uAE30\uB97C \uC8FC\uACE0\uBC1B\uACE0 \uC788\uB294\uC9C0 \uC0B4\uD3B4\uBCF4\uC544\uC57C \uD55C\uB2E4.",s:'\uC8FC\uC81C\uB294 "\uADF9\uB3D9 \uC9C0\uC5ED\uC758 \uBB8C\uD5E8 \uC74C\uBAA8 \uD3ED\uB85C"(1941\uB144 5\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uB418\uC5C8\uC2B5\uB2C8\uB2E4.',e:"\uC774 \uAE00\uC740 \uAD6D\uC81C\uC815\uCE58\uC5D0\uC11C \uD0C0\uD611\uACFC \uC591\uBCF4\uB97C \uD655\uC778\uD558\uB294 \uAC83\uC744 \uAC15\uC870\uD558\uACE0 \uC591\uBCF4\uB97C \uC548\uC815\uC73C\uB85C \uCC29\uAC01\uD558\uB294 \uAC83\uC5D0 \uBC18\uB300\uD569\uB2C8\uB2E4."},{q:"\uD070 \uACF5\uB3D9\uC758 \uC801\uC774 \uB098\uD0C0\uB098\uBA74 \uB354 \uB113\uC740 \uBC94\uC704\uC5D0\uC11C \uBB49\uCE60 \uC218 \uC788\uB294 \uC138\uB825\uC744 \uCC3E\uB294 \uBC95\uC744 \uBC30\uC6CC\uC57C \uD55C\uB2E4",s:'\uC8FC\uC81C\uB294 "\uD30C\uC2DC\uC998\uC5D0 \uBC18\uB300\uD558\uB294 \uAD6D\uC81C \uC5F0\uD569 \uC804\uC120\uC5D0 \uAD00\uD558\uC5EC"(1941\uB144 6\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uB418\uC5C8\uC2B5\uB2C8\uB2E4.',e:"\uC774 \uAE30\uC0AC\uB294 \uAD6D\uB0B4 \uD22C\uC7C1\uC744 \uAD6D\uC81C\uC801\uC778 \uBC18\uD30C\uC2DC\uC2A4\uD2B8 \uD328\uD134\uC5D0 \uD3EC\uD568\uC2DC\uD0A4\uACE0 \uACF5\uB3D9\uC758 \uC774\uC775\uC774 \uB354 \uD070 \uB3D9\uB9F9\uC744 \uD615\uC131\uD560 \uC218 \uC788\uC74C\uC744 \uAC15\uC870\uD569\uB2C8\uB2E4."},{q:"\uAC70\uBC84\uB10C\uC2A4 \uB2A5\uB825\uC740 \uCD94\uC0C1\uC801\uC778 \uBA85\uCE6D\uC774 \uC544\uB2C8\uB2E4. \uADF8\uAC83\uC740 \uADF8 \uC7A5\uC18C\uAC00 \uC9C4\uC815\uC73C\uB85C \uC870\uC9C1\uD654\uB420 \uC218 \uC788\uB294\uC9C0\uC5D0 \uB2EC\uB824 \uC788\uB2E4.",s:'\uC8FC\uC81C\uB294 "\uC0B0\uC2DC-\uAC04\uC464-\uB2DD\uC0E4 \uAD6D\uACBD \uC9C0\uC5ED \uD68C\uC758 \uC5F0\uC124"(1941\uB144 11\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uB418\uC5C8\uC2B5\uB2C8\uB2E4.',e:"\uC774\uB7EC\uD55C \uC720\uD615\uC758 \uC5F0\uC124\uC740 \uAD6D\uACBD\uC9C0\uC5ED\uC758 \uC815\uCE58\uAD8C\uB825 \uAD6C\uCD95\uC5D0 \uC788\uC5B4\uC11C \uB300\uD45C\uC131, \uC9C8\uC11C, \uC2E4\uCC9C\uC801 \uD6A8\uACFC\uB97C \uAC15\uC870\uD558\uB294 \uAC83\uC744 \uBC18\uC601\uD55C\uB2E4."},{q:"\uD575\uC2EC\uC815\uCC45\uC744 \uC62C\uBC14\uB974\uAC8C \uD30C\uC545\uD558\uBA74 \uAD6D\uC138 \uC804\uCCB4\uB97C \uBCC0\uD654\uC2DC\uD0AC \uC218 \uC788\uB2E4.",s:'\uC8FC\uC81C\uB294 "\uB9E4\uC6B0 \uC911\uC694\uD55C \uC815\uCC45"(1942\uB144 9\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uB418\uC5C8\uC2B5\uB2C8\uB2E4.',e:"\uC774 \uAE30\uC0AC\uC5D0\uC11C\uB294 \uBCF5\uC7A1\uD55C \uC791\uC5C5\uC5D0\uC11C \uACB0\uC815\uC801\uC778 \uB9C1\uD06C\uB97C \uC2DD\uBCC4\uD558\uACE0 \uBA87 \uAC00\uC9C0 \uC8FC\uC694 \uC815\uCC45\uC744 \uD65C\uC6A9\uD558\uC5EC \uC804\uBC18\uC801\uC778 \uAC1C\uC120\uC744 \uD65C\uC6A9\uD558\uB294 \uAC83\uC744 \uAC15\uC870\uD569\uB2C8\uB2E4."},{q:"\uC9C4\uC815\uD55C \uC804\uD658\uC810\uC740 \uD798\uC758 \uADE0\uD615\uACFC \uC0AC\uB78C\uB4E4\uC758 \uAE30\uB300\uAC00 \uB3D9\uC2DC\uC5D0 \uB2E4\uC2DC \uC4F0\uC5EC\uC9C8 \uB54C \uBC1C\uC0DD\uD558\uB294 \uACBD\uC6B0\uAC00 \uB9CE\uC2B5\uB2C8\uB2E4.",s:'\uC8FC\uC81C\uB294 "\uC81C2\uCC28 \uC138\uACC4\uB300\uC804\uC758 \uC804\uD658\uC810"(1942\uB144 10\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uB418\uC5C8\uC2B5\uB2C8\uB2E4.',e:"\uC774 \uAE30\uC0AC\uB294 \uC138\uACC4\uB300\uC804 \uC0C1\uD669\uC758 \uBCC0\uD654\uB97C \uC774\uC6A9\uD558\uC5EC \uC804\uD658\uC810\uC744 \uD310\uB2E8\uD560 \uB54C \uD55C\uB450 \uBC88\uC758 \uC804\uD22C\uB9CC \uBCFC \uAC83\uC774 \uC544\uB2C8\uB77C \uC804\uBC18\uC801\uC778 \uCD94\uC138\uB97C \uBCF4\uC544\uC57C \uD55C\uB2E4\uB294 \uC810\uC744 \uC0AC\uB78C\uB4E4\uC5D0\uAC8C \uC0C1\uAE30\uC2DC\uD0B5\uB2C8\uB2E4."},{q:"\uC7AC\uC815\uC774 \uD63C\uB780\uC5D0 \uBE60\uC9C0\uBA74 \uB9CE\uC740 \uC815\uCE58\uC801, \uAD70\uC0AC\uC801 \uBAA9\uD45C\uAC00 \uC601\uD5A5\uC744 \uBC1B\uAC8C \uB429\uB2C8\uB2E4.",s:"\uC8FC\uC81C\uB294 \u300E\uD56D\uC77C\uC804\uC7C1 \uC911\uC758 \uACBD\uC81C\uAE08\uC735\uBB38\uC81C\u300F(1942\uB144 12\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC",e:"\uC774 \uAE30\uC0AC\uB294 \uC804\uC2DC \uAE08\uC735\uACFC \uACBD\uC81C \uC5C5\uBB34\uB97C \uCCB4\uACC4\uC801\uC73C\uB85C \uB17C\uC758\uD558\uBA74\uC11C \uC0DD\uC0B0, \uBD84\uBC30, \uBD80\uB2F4\uC774 \uC9C0\uC18D \uAC00\uB2A5\uD55C \uAD00\uACC4\uB97C \uD615\uC131\uD574\uC57C \uD55C\uB2E4\uB294 \uC810\uC744 \uAC15\uC870\uD569\uB2C8\uB2E4."},{q:"\uC77C\uBD80 \uBB38\uC81C\uB294 \uBAA8\uD638\uD558\uAC8C \uCC98\uB9AC\uB420 \uC218 \uC5C6\uC2B5\uB2C8\uB2E4. \uC9C8\uBB38\uC744 \uD560 \uB54C\uC5D0\uB294 \uCC45\uC784\uC744 \uBA85\uD655\uD788 \uBA85\uC2DC\uD574\uC57C \uD569\uB2C8\uB2E4.",s:'\uC8FC\uC81C\uB294 "\uAD6D\uBBFC\uB2F9\uC5D0 \uB300\uD55C \uC9C8\uBB38"(1943\uB144 7\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uB418\uC5C8\uC2B5\uB2C8\uB2E4.',e:"\uC774 \uAE00\uC740 \uBAA8\uC21C\uC744 \uACF5\uAC1C\uC801\uC73C\uB85C \uD3ED\uB85C\uD558\uACE0, \uC815\uCE58\uC801 \uD22C\uC7C1\uC5D0\uC11C \uC0C1\uB300\uBC29\uC774 \uC785\uC7A5\uC744 \uCDE8\uD558\uB3C4\uB85D \uAC15\uC694\uD558\uB294 \uC804\uB7B5\uC744 \uB2F4\uACE0 \uC788\uB2E4."},{q:"\uAE30\uC9C0\uC9C0\uC5ED\uC744 \uC9C4\uC815\uC73C\uB85C \uC548\uC815\uC2DC\uD0A4\uB824\uBA74 \uACBD\uC81C\uC640 \uAD70\uBBFC\uAD00\uACC4, \uC778\uBBFC\uB300\uC911\uC758 \uB9AC\uC775\uC744 \uC911\uC2DC\uD558\uC5EC\uC57C \uD569\uB2C8\uB2E4.",s:"\uC8FC\uC81C\uB294 \u300A\uAE30\uC9C0\uC758 \uC784\uB300\uB8CC \uC778\uD558, \uC0DD\uC0B0, \uC9C0\uC6D0, \uC560\uBBFC \uC6B4\uB3D9\uC744 \uC804\uAC1C\uD560\uB370\u300B(1943\uB144 10\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uD558\uC600\uB2E4.",e:"\uAE30\uC0AC\uC5D0\uC11C\uB294 \uBD84\uC0B0\uB418\uC5B4 \uC788\uB294 \uAC83\uCC98\uB7FC \uBCF4\uC774\uB294 \uC5EC\uB7EC \uC791\uC5C5\uC774 \uC2E4\uC81C\uB85C \uC11C\uB85C\uB97C \uC9C0\uC6D0\uD558\uBA70 \uB2E8\uB3C5\uC73C\uB85C \uCD94\uC9C4\uD560 \uC218 \uC5C6\uB2E4\uB294 \uC810\uC744 \uAC15\uC870\uD569\uB2C8\uB2E4."},{q:"\uC8FC\uC5B4\uC9C4 \uC0C1\uD669\uC5D0 \uB300\uCC98\uD558\uC9C0 \uBABB\uD558\uBA74 \uC544\uBB34\uB9AC \uC5F4\uC2EC\uD788 \uACF5\uBD80\uD574\uB3C4 \uC2E4\uD328\uD558\uAE30 \uC27D\uC2B5\uB2C8\uB2E4.",s:'\uC8FC\uC81C\uB294 "\uD559\uC2B5\uACFC \uC2DC\uC0AC"(1944\uB144 4\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uB418\uC5C8\uC2B5\uB2C8\uB2E4.',e:"\uC774 \uAE30\uC0AC\uB294 \uD559\uC2B5\uC744 \uD604\uC7AC \uC0C1\uD669\uACFC \uC5F0\uACB0\uD558\uACE0 \uC774\uB860\uC801 \uAC1C\uC120\uC774 \uD604\uC2E4\uC801\uC778 \uD310\uB2E8\uACFC \uC2E4\uC81C \uC791\uC5C5\uC5D0 \uB3C4\uC6C0\uC774 \uB418\uC5B4\uC57C \uD568\uC744 \uAC15\uC870\uD569\uB2C8\uB2E4."},{q:"\uC815\uCE58\uC801\uC778 \uBC1C\uC5B8\uC744 \uB4E4\uC744 \uB54C\uB294 \uADF8 \uB9D0\uC774 \uC88B\uC740\uC9C0 \uC544\uB2CC\uC9C0 \uBFD0\uB9CC \uC544\uB2C8\uB77C \uBB34\uC5C7\uC744 \uD53C\uD558\uB294\uC9C0\uB3C4 \uB4E4\uC5B4\uC57C \uD569\uB2C8\uB2E4.",s:'\uC8FC\uC81C\uB294 "\uC7A5\uAC1C\uC11D\uC758 \uC774\uC911\uC2ED\uC77C \uC5F0\uC124\uC5D0 \uB300\uD55C \uB17C\uD3C9"(1944\uB144 10\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uD55C \uAC83\uC785\uB2C8\uB2E4.',e:"\uAE00\uC740 \uC0C1\uB300\uBC29\uC758 \uB9D0\uC744 \uBD84\uC11D\uD568\uC73C\uB85C\uC368 \uC0AC\uB78C\uB4E4\uC5D0\uAC8C \uADF8 \uACF5\uBC31\uACFC \uD68C\uD53C, \uBAA8\uC21C \uC18D\uC5D0\uC11C \uBB38\uC81C\uC758 \uBCF8\uC9C8\uC744 \uBCF4\uB3C4\uB85D \uC77C\uAE68\uC6CC\uC900\uB2E4."},{q:"\uBB38\uD654 \uBD84\uC57C\uC5D0\uB3C4 \uB178\uC870\uC640 \uBD84\uD30C\uAC00 \uC788\uB2E4. \uD1B5\uC77C\uC804\uC120\uC744 \uC774\uB8E8\uB294 \uAC83\uC740 \uC804\uC7C1\uD130\uC640 \uC815\uCE58\uBB34\uB300\uB9CC\uC774 \uC544\uB2C8\uB2E4.",s:'\uC8FC\uC81C\uB294 "\uBB38\uD654 \uC0AC\uC5C5\uC758 \uD1B5\uC77C \uC804\uC120"(1944\uB144 10\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uB418\uC5C8\uC2B5\uB2C8\uB2E4.',e:"\uAE30\uC0AC\uC5D0\uC11C\uB294 \uBB38\uD654\uC0AC\uC5C5\uC774 \uD558\uCC2E\uC740 \uBB38\uC81C\uAC00 \uC544\uB2C8\uB77C \uC815\uCE58\uC801 \uBC29\uD5A5, \uC0AC\uD68C\uC801 \uB3D9\uC6D0\uACFC \uBC00\uC811\uD558\uAC8C \uC5F0\uAD00\uB418\uC5B4 \uC788\uB2E4\uACE0 \uC124\uBA85\uD558\uACE0 \uC788\uB2E4."},{q:"\uC0C1\uD669\uC774 \uB098\uC060\uC218\uB85D \uC6B0\uB9AC\uB294 \uADF8 \uACA9\uCC28 \uC18D\uC5D0\uC11C \uC0DD\uC0B0\uC744 \uC870\uC9C1\uD558\uB294 \uBC95\uC744 \uB354 \uB9CE\uC774 \uBC30\uC6CC\uC57C \uD569\uB2C8\uB2E4.",s:'"\uC720\uACA9\uB300\uC5D0\uC11C\uB3C4 \uC0DD\uC0B0\uC774 \uAC00\uB2A5\uD558\uB2E4"(1945\uB144 1\uC6D4)\uB77C\uB294 \uC8FC\uC81C\uC5D0\uC11C \uBC1C\uCDCC',e:"\uAE30\uC0AC\uC5D0\uC11C\uB294 \uC5B4\uB824\uC6B4 \uBD80\uBD84\uC774 \uB2E8\uC9C0 \uC18C\uBE44\uB9CC\uC744 \uC704\uD55C \uAC83\uC774 \uC544\uB2C8\uB77C\uB294 \uC810\uC744 \uAC15\uC870\uD569\uB2C8\uB2E4. \uBC29\uBC95\uC774 \uC62C\uBC14\uB978 \uD55C, \uC0DD\uC0B0 \uB2A5\uB825\uC740 \uC5EC\uC804\uD788 \u200B\u200B\uC720\uC9C0\uB418\uACE0 \uD68C\uBCF5\uB420 \uC218 \uC788\uC2B5\uB2C8\uB2E4."},{q:"\uD070 \uBD84\uAE30\uC810\uC5D0 \uC9C1\uBA74\uD588\uC744 \uB54C \uC911\uC694\uD55C \uAC83\uC740 \uC2B9\uD328\uC758 \uC138\uBD80 \uC0AC\uD56D\uC774 \uC544\uB2C8\uB77C \uBBF8\uB798\uB97C \uB098\uD0C0\uB0B4\uB294 \uACBD\uB85C\uAC00 \uBB34\uC5C7\uC778\uC9C0\uC785\uB2C8\uB2E4.",s:'\uC8FC\uC81C\uB294 "\uB450 \uC911\uAD6D\uC758 \uC6B4\uBA85"(1945\uB144 4\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uB418\uC5C8\uC2B5\uB2C8\uB2E4.',e:"\uAE30\uC0AC\uB294 \uB450 \uAC00\uC9C0 \uC804\uB9DD\uC744 \uD568\uAED8 \uBE44\uAD50\uD558\uBA70, \uC5B4\uB5A4 \uAE38\uC744 \uC120\uD0DD\uD558\uB290\uB0D0\uC5D0 \uB530\uB77C \uAD6D\uAC00\uC758 \uC6B4\uBA85\uC774 \uACB0\uC815\uB41C\uB2E4\uB294 \uC810\uC744 \uAC15\uC870\uD55C\uB2E4."},{q:"\uC870\uC9C1\uC758 \uADDC\uBAA8\uAC00 \uD074\uC218\uB85D \uC2A4\uD0C0\uC77C\uACFC \uACF5\uAE09 \uBAA8\uB450\uC5D0 \uB354 \uB9CE\uC740 \uB178\uB825\uC744 \uAE30\uC6B8\uC5EC\uC57C \uD569\uB2C8\uB2E4.",s:"\uC8FC\uC81C\uB294 \u300E\uAD70\uC218\uC0DD\uC0B0\uC758 \uC790\uB9BD\uACFC \uC815\uC815\uACFC \uC0DD\uC0B0\uC758 \uC591\uB300\uC6B4\uB3D9\uC758 \uC758\uC758\uC5D0 \uB300\uD558\uC5EC\u300F(1945\uB144 4\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uD55C \uAC83\uC774\uB2E4.",e:"\uAE30\uC0AC\uC5D0\uC11C\uB294 \uC5C5\uBB34 \uBC29\uC2DD\uC744 \uBC14\uB85C\uC7A1\uB294 \uAC83\uACFC \uC0DD\uC0B0\uC744 \uAC1C\uC120\uD558\uB294 \uAC83\uC774 \uBCC4\uAC1C\uC758 \uBB38\uC81C\uAC00 \uC544\uB2C8\uB77C\uACE0 \uC9C0\uC801\uD569\uB2C8\uB2E4. \uC774\uB4E4\uC740 \uD300\uC758 \uC9C0\uC18D \uAC00\uB2A5\uC131\uC744 \uACF5\uB3D9\uC73C\uB85C \uACB0\uC815\uD569\uB2C8\uB2E4."},{q:"\uACF5\uC5F0\uC744 \uBCF4\uC2E0 \uD6C4 \uC65C \uACF5\uC5F0\uC744 \uD560 \uC218 \uC5C6\uB294\uC9C0 \uD310\uB2E8\uD558\uB294 \uAC83\uC774 \uB354 \uC911\uC694\uD569\uB2C8\uB2E4.",s:'\uC8FC\uC81C\uB294 "Hurley\uC640 \uC7A5\uAC1C\uC11D\uC758 \uC774\uC911 \uD589\uC704\uAC00 \uAE68\uC84C\uC2B5\uB2C8\uB2E4"(1945\uB144 7\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uB418\uC5C8\uC2B5\uB2C8\uB2E4.',e:"\uAE30\uC0AC\uB294 \uC815\uCE58\uC801 \uC131\uACFC\uC758 \uD30C\uD0C4\uC744 \uD3ED\uB85C\uD558\uBA74\uC11C \uAD8C\uB825\uC758 \uADE0\uD615\uACFC \uC5EC\uB860\uC758 \uAE30\uBC18\uC774 \uACB0\uC815\uC801 \uC694\uC778\uC784\uC744 \uAC15\uC870\uD55C\uB2E4."},{q:"\uB9C8\uC9C0\uB9C9 \uC21C\uAC04\uC740 \uC9D1\uC911\uB825\uC744 \uC2DC\uD5D8\uD558\uB294 \uAC00\uC7A5 \uD070 \uC21C\uAC04\uC785\uB2C8\uB2E4. \uC2B9\uB9AC\uAC00 \uAC00\uAE4C\uC6CC\uC84C\uB2E4\uACE0 \uD574\uC11C \uAE34\uC7A5\uC744 \uD480\uC9C0 \uB9C8\uC2ED\uC2DC\uC624.",s:'\uC8FC\uC81C\uB294 "\uC77C\uBCF8 \uCE68\uB7B5\uC790\uB4E4\uACFC\uC758 \uCD5C\uD6C4\uC758 \uC804\uD22C"(1945\uB144 8\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uB418\uC5C8\uC2B5\uB2C8\uB2E4.',e:"\uAE30\uC0AC\uC5D0\uC11C\uB294 \uC2B9\uB9AC\uAC00 \uB2E4\uAC00\uC62C \uB54C\uC5D0\uB3C4 \uC5EC\uC804\uD788 \uC870\uC9C1\uACFC \uD589\uB3D9\uC744 \uC720\uC9C0\uD558\uACE0 \uB9C8\uC9C0\uB9C9 \uB2E8\uACC4\uB97C \uCC29\uC2E4\uD558\uAC8C \uC9C4\uD589\uD574\uC57C \uD55C\uB2E4\uACE0 \uAC15\uC870\uD569\uB2C8\uB2E4."},{q:"\uB0A8\uB4E4\uC774 \uC0C1\uD669\uC744 \uC545\uD654\uC2DC\uD0A4\uBA74 \uBA3C\uC800 \uC790\uC2E0\uC758 \uCC45\uC784\uACFC \uC9C4\uC2E4\uC744 \uBC1D\uD600\uC57C \uD569\uB2C8\uB2E4.",s:'\uC8FC\uC81C\uB294 "\uC7A5\uAC1C\uC11D\uC774 \uB0B4\uC804\uC744 \uB3C4\uBC1C\uD558\uACE0 \uC788\uB2E4"(1945\uB144 8\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uD55C \uAC83\uC785\uB2C8\uB2E4.',e:"\uC774 \uAE00\uC740 \uB0B4\uC804\uC744 \uB3C4\uBC1C\uD55C \uCC45\uC784\uC758 \uADC0\uC778\uC744 \uBC1D\uD600 \uC815\uCE58\uC801 \uC8FC\uB3C4\uC131\uACFC \uC0AC\uD68C\uC801 \uD310\uB2E8\uC744 \uB3C4\uBAA8\uD558\uACE0\uC790 \uD55C\uB2E4."},{q:"\uACF5\uACA9\uC744 \uC2DD\uBCC4\uD558\uB824\uBA74 \uAD6C\uB450\uB85C \uB9D0\uD55C \uB0B4\uC6A9\uBFD0\uB9CC \uC544\uB2C8\uB77C \uAD70\uB300\uC758 \uD798, \uBC30\uCE58 \uBC0F \uD589\uB3D9\uB3C4 \uC0B4\uD3B4\uBCF4\uC2ED\uC2DC\uC624.",s:'\uC8FC\uC81C\uB294 "\uAD6D\uBBFC\uB2F9 \uACF5\uC138\uC758 \uC9C4\uC2E4"(1945\uB144 11\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uD55C \uAC83\uC785\uB2C8\uB2E4.',e:"\uAE30\uC0AC\uC5D0\uC11C\uB294 \uC0C1\uD669\uD310\uB2E8\uC740 \uC0AC\uC2E4\uC5D0 \uADFC\uAC70\uD574\uC57C \uD558\uBA70, \uD3EC\uC7A5\uB41C \uB2E8\uC5B4\uB85C \uD3B8\uD5A5\uB418\uC5B4\uC11C\uB294 \uC548 \uB41C\uB2E4\uB294 \uC810\uC744 \uAC15\uC870\uD55C\uB2E4."},{q:"\uC9C0\uC5ED\uC744 \uC9C0\uD0A4\uB294 \uAC83\uC740 \uC2F8\uC6B0\uB294 \uAC83\uBFD0\uB9CC \uC544\uB2C8\uB77C \uC0AC\uB78C\uB4E4\uC758 \uC0B6\uC744 \uD3B8\uC548\uD558\uAC8C \uB9CC\uB4DC\uB294 \uAC83\uC5D0\uB3C4 \uB2EC\uB824 \uC788\uC2B5\uB2C8\uB2E4.",s:"\uC8FC\uC81C\uB294 \u201C\uC9C0\uB300\uAC10\uCD95\uACFC \uC0DD\uC0B0\uC740 \uD574\uBC29\uC9C0\uC5ED\uC218\uD638\uC758 \uC591\uB300\uC0AC\uBCC0\u201D(1945\uB144 11\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uD55C \uAC83\uC774\uB2E4.",e:"\uAE30\uC0AC\uB294 \uC784\uB300\uB8CC \uC778\uD558\uC640 \uC0DD\uC0B0\uC744 \uC804\uB7B5\uC801 \uCC28\uC6D0\uC73C\uB85C \uB04C\uC5B4\uC62C\uB824 \uACBD\uC81C\uC640 \uBBFC\uC0DD\uC774 \uBC29\uC5B4\uC120\uC758 \uC77C\uBD80\uB77C\uACE0 \uC124\uBA85\uD588\uB2E4."},{q:"\uC0C8\uD574\uB97C \uC2DC\uC791\uD558\uAE30 \uC804\uC5D0 \uBA3C\uC800 \uBC29\uD5A5\uACFC \uC21C\uC11C, \uC6B0\uC120\uC21C\uC704\uB97C \uC815\uD574\uC57C \uB098\uC911\uC5D0 \uC27D\uAC8C \uB9DD\uAC00\uC9C0\uC9C0 \uC54A\uC2B5\uB2C8\uB2E4.",s:"\uC8FC\uC81C\uB294 \u300E1946\uB144 \uD574\uBC29\uAD6C\uC0AC\uC5C5\uC6D0\uCE59\u300F(1945\uB144 12\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uD55C \uAC83\uC774\uB2E4.",e:"\uC774 \uAE30\uC0AC\uC5D0\uC11C\uB294 \uB2E8\uACC4\uBCC4 \uC815\uCC45\uC758 \uC911\uC694\uC131\uC744 \uAC15\uC870\uD558\uACE0 \uBA85\uD655\uD55C \uC791\uC5C5 \uBC30\uC5F4\uC744 \uC0AC\uC6A9\uD558\uC5EC \uC804\uBC18\uC801\uC778 \uC870\uC815\uC744 \uAC1C\uC120\uD569\uB2C8\uB2E4."},{q:"\uD575\uC2EC\uC9C0\uC5ED \uC9C4\uC785 \uD6C4 \uD655\uACE0\uD55C \uAE30\uBC18\uC744 \uBA3C\uC800 \uBAA8\uC0C9\uD55C \uD6C4 \uD655\uC7A5\uC744 \uB17C\uC758\uD55C\uB2E4.",s:'\uC8FC\uC81C\uB294 "\uAC15\uD55C \uB3D9\uBD81\uAE30\uC9C0 \uAC74\uC124"(1945\uB144 12\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uD55C \uAC83\uC785\uB2C8\uB2E4.',e:"\uC774 \uAE30\uC0AC\uB294 \uC0C8\uB85C\uC6B4 \uC601\uC5ED\uC5D0\uC11C \uC791\uC5C5\uD560 \uB54C \uC18D\uB3C4\uC5D0\uB9CC \uCD08\uC810\uC744 \uB9DE\uCD94\uB294 \uAC83\uC774 \uC544\uB2C8\uB77C \uB300\uADDC\uBAA8 \uC791\uC5C5, \uAD70\uC0AC \uBC30\uCE58 \uBC0F \uAC70\uBC84\uB10C\uC2A4 \uAE30\uBC18\uB3C4 \uACE0\uB824\uD574\uC57C \uD568\uC744 \uC0C1\uAE30\uC2DC\uCF1C \uC90D\uB2C8\uB2E4."},{q:"\uC18C\uADF9\uC801\uC778 \uC0C1\uD669\uC5D0 \uC788\uC744 \uB54C\uB294 \uC8FC\uB3C4\uAD8C\uC744 \uB418\uB3CC\uB9B4 \uBC29\uBC95\uB3C4 \uCC3E\uC544\uC57C \uD569\uB2C8\uB2E4.",s:'\uC8FC\uC81C\uB294 "\uC7A5\uC81C\uC2A4\uC758 \uACF5\uC138\uB97C \uC790\uC704\uC804\uC7C1\uC73C\uB85C \uBD84\uC1C4\uD558\uB2E4"(1946\uB144 7\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uD55C \uAC83\uC785\uB2C8\uB2E4.',e:"\uAE30\uC0AC\uC5D0\uC11C\uB294 \uBC29\uC5B4\uC804\uC5D0\uC11C\uB3C4 \uC62C\uBC14\uB978 \uC870\uC9C1\uACFC \uC804\uC7A5 \uC120\uD0DD\uC744 \uD1B5\uD574 \uC0C1\uD669\uC744 \uC5ED\uC804\uC2DC\uD0AC \uC218 \uC788\uB2E4\uACE0 \uAC15\uC870\uD569\uB2C8\uB2E4."},{q:"\uC77C\uBD80 \uC911\uC7AC\uB294 \uBB38\uC81C\uB97C \uD574\uACB0\uD558\uAE30 \uC704\uD55C \uAC83\uC774 \uC544\uB2C8\uB77C \uC790\uC2E0\uC5D0\uAC8C \uC720\uC775\uD55C \uC0C1\uD669\uC744 \uC870\uC131\uD558\uAE30 \uC704\uD55C \uAC83\uC785\uB2C8\uB2E4.",s:`\uC8FC\uC81C\uB294 "\uBBF8\uAD6D\uC758 '\uC911\uC7AC'\uC5D0 \uAD00\uD55C \uC9C4\uC2E4\uACFC \uC911\uAD6D \uB0A8\uBD81\uC804\uC7C1\uC758 \uC804\uB9DD"(1946\uB144 9\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uD55C \uAC83\uC785\uB2C8\uB2E4.`,e:"\uC774 \uAE30\uC0AC\uB294 \uC0AC\uB78C\uB4E4\uC5D0\uAC8C \uC678\uBD80 \uAC1C\uC785 \uB4A4\uC5D0 \uC788\uB294 \uC774\uD574\uAD00\uACC4\uC758 \uB17C\uB9AC\uB97C \uD655\uC778\uD558\uACE0 \uD615\uC2DD\uC801 \uC911\uB9BD\uC744 \uC9C4\uC815\uD55C \uC911\uB9BD\uC73C\uB85C \uAC04\uC8FC\uD558\uC9C0 \uB9D0 \uAC83\uC744 \uC0C1\uAE30\uC2DC\uD0B5\uB2C8\uB2E4."},{q:"\uC0C1\uD669\uC774 \uAD50\uCC29\uC0C1\uD0DC\uC5D0 \uC788\uC744 \uB54C\uB294 \uAC10\uC815\uC801 \uD310\uB2E8\uBCF4\uB2E4 \uB2E8\uACC4\uC694\uC57D\uC774 \uB354 \uC2E0\uB8B0\uB3C4\uAC00 \uB192\uB2E4",s:'\uC8FC\uC81C\uB294 "3\uAC1C\uC6D4 \uC694\uC57D"(1946\uB144 10\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uB418\uC5C8\uC2B5\uB2C8\uB2E4.',e:"\uC774 \uAE30\uC0AC\uC5D0\uB294 \uACC4\uC18D\uB418\uB294 \uD22C\uC7C1\uC5D0\uC11C \uD300 \uD310\uB2E8\uACFC \uC218\uC815 \uBC29\uBC95\uC744 \uC548\uC815\uD654\uD558\uAE30 \uC704\uD574 \uBB34\uB300 \uAC80\uD1A0\uB97C \uC0AC\uC6A9\uD55C\uB2E4\uB294 \uC544\uC774\uB514\uC5B4\uAC00 \uAD6C\uCCB4\uD654\uB418\uC5B4 \uC788\uC2B5\uB2C8\uB2E4."},{q:"\uD074\uB77C\uC774\uB9E5\uC2A4\uB294 \uC678\uCE58\uB294 \uAC83\uC774 \uC544\uB2C8\uB77C, \uC77C\uC815 \uC218\uC900\uAE4C\uC9C0 \uC313\uC778 \uB4A4 \uC194\uC120\uD574\uC11C \uB9DE\uC774\uD558\uB294 \uAC83\uC774\uB2E4.",s:'\uC8FC\uC81C\uB294 "\uC911\uAD6D \uD601\uBA85\uC758 \uC0C8\uB85C\uC6B4 \uACE0\uC870\uB97C \uD658\uC601\uD569\uB2C8\uB2E4"(1947\uB144 2\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uB418\uC5C8\uC2B5\uB2C8\uB2E4.',e:"\uAE30\uC0AC\uC5D0\uC11C\uB294 \uC0C1\uD669\uC774 \uB354\uC6B1 \uC545\uD654\uB420 \uB54C \uAE30\uD68C\uB97C \uBCFC \uBFD0\uB9CC \uC544\uB2C8\uB77C \uB354 \uD070 \uCC45\uC784\uC744 \uB9E1\uC744 \uC900\uBE44\uB3C4 \uD574\uC57C \uD55C\uB2E4\uACE0 \uAC15\uC870\uD569\uB2C8\uB2E4."},{q:"\uC9C4\uC815\uD55C \uD3EC\uC704 \uACF5\uACA9\uC740 \uB2E8\uC9C0 \uAD70\uC0AC\uC801\uC778 \uAC83\uC774 \uC544\uB2C8\uB77C \uC815\uCE58\uC801, \uC0AC\uD68C\uC801\uC774\uB2E4",s:'\uC8FC\uC81C\uB294 "\uC7A5\uAC1C\uC11D \uC815\uBD80\uB294 \uC804\uBBFC\uC5D0 \uB458\uB7EC\uC2F8\uC5EC \uC788\uB2E4"(1947\uB144 5\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uB418\uC5C8\uC2B5\uB2C8\uB2E4.',e:"\uC774 \uAE30\uC0AC\uB294 \uB300\uC911\uC801 \uAE30\uBC18\uACFC \uC0AC\uD68C\uC801 \uAD00\uACC4\uC758 \uAD00\uC810\uC5D0\uC11C \uBC18\uB300\uC790\uB4E4\uC774 \uC810\uC810 \uB354 \uACE0\uB9BD\uB418\uB294 \uC774\uC720\uB97C \uC124\uBA85\uD569\uB2C8\uB2E4."},{q:"\uC804\uC7C1\uC774 \uC0C8\uB85C\uC6B4 \uB2E8\uACC4\uB85C \uC811\uC5B4\uB4E4\uBA74\uC11C \uBC29\uBC95\uB3C4 \uC5C5\uADF8\uB808\uC774\uB4DC\uB418\uC5B4\uC57C \uD569\uB2C8\uB2E4.",s:"\uC8FC\uC81C\uB294 \u300E\uD574\uBC29\uC804\uC7C1 2\uB144 \uC804\uB7B5\uC9C0\uCE68\u300F(1947\uB144 9\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC",e:"\uC774 \uAE30\uC0AC\uB294 2\uB144\uCC28\uC758 \uC804\uB7B5\uC801 \uBC30\uCE58\uC5D0 \uCD08\uC810\uC744 \uB9DE\uCD94\uBA70, \uB2E8\uACC4 \uC804\uD658\uC5D0\uB294 \uBC18\uBCF5\uC774 \uC544\uB2CC \uC0C8\uB85C\uC6B4 \uBC30\uCE58\uAC00 \uD544\uC694\uD558\uB2E4\uB294 \uC810\uC744 \uAC15\uC870\uD569\uB2C8\uB2E4."},{q:"\uAD70\uB300\uAC00 \uBA40\uB9AC \uAC00\uACE0 \uC2F6\uB2E4\uBA74 \uC65C \uC2F8\uC6B0\uB294\uC9C0 \uBA85\uD655\uD558\uAC8C \uC124\uBA85\uD574\uC57C \uD569\uB2C8\uB2E4.",s:'\uC8FC\uC81C\uB294 "\uC911\uAD6D \uC778\uBBFC \uD574\uBC29\uAD70 \uC120\uC5B8"(1947\uB144 10\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uD55C \uAC83\uC785\uB2C8\uB2E4.',e:"\uC120\uC5B8\uBB38\uC758 \uC911\uC694\uC131\uC740 \uBAA9\uD45C, \uACBD\uACC4, \uADDC\uC728\uC744 \uD1B5\uD569\uD558\uACE0 \uD589\uB3D9\uC5D0 \uBA85\uD655\uD55C \uC815\uCE58\uC801 \uBC29\uD5A5\uC744 \uC81C\uC2DC\uD558\uB294 \uB370 \uC788\uC2B5\uB2C8\uB2E4."},{q:"\uC791\uC5C5\uC744 \uBA85\uD655\uD558\uAC8C \uBCF8\uB2E4\uB294 \uAC83\uC740 \uBB34\uC5C7\uC744 \uD574\uC57C \uD560\uC9C0 \uC544\uB294 \uAC83\uBFD0\uB9CC \uC544\uB2C8\uB77C \uBB34\uC5C7\uC744 \uBA3C\uC800 \uD574\uC57C \uD560\uC9C0 \uC544\uB294 \uAC83\uC744 \uC758\uBBF8\uD569\uB2C8\uB2E4.",s:'\uC8FC\uC81C\uB294 "\uD604\uC7AC \uC0C1\uD669\uACFC \uC6B0\uB9AC\uC758 \uACFC\uC81C"(1947\uB144 12\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uB418\uC5C8\uC2B5\uB2C8\uB2E4.',e:"\uC774 \uAE30\uC0AC\uB294 \uC804\uBC18\uC801\uC778 \uC0C1\uD669\uC774 \uC88B\uC744 \uB54C \uC6B0\uC120\uC21C\uC704\uB97C \uAD6C\uBCC4\uD558\uACE0 \uC9C0\uC5ED\uC801 \uBCF5\uC7A1\uC131\uC774 \uC804\uBC18\uC801\uC778 \uBC29\uD5A5\uC744 \uBC29\uD574\uD558\uC9C0 \uC54A\uB3C4\uB85D \uD558\uB294 \uAC83\uC774 \uD6E8\uC52C \uB354 \uC911\uC694\uD558\uB2E4\uACE0 \uAC15\uC870\uD569\uB2C8\uB2E4."},{q:"\uC870\uC9C1\uC758 \uADDC\uBAA8\uAC00 \uD074\uC218\uB85D \uC2DC\uAE30\uC801\uC808\uD558\uACE0 \uC815\uD655\uD558\uBA70 \uBE44\uAD50 \uAC00\uB2A5\uD55C \uC815\uBCF4\uC758 \uBC18\uD658\uC774 \uB354\uC6B1 \uBD88\uAC00\uB2A5\uD574\uC9D1\uB2C8\uB2E4.",s:"\uC8FC\uC81C\uB294 \u300E\uBCF4\uACE0\uCCB4\uACC4 \uD655\uB9BD\uC5D0 \uB300\uD558\uC5EC\u300F(1948\uB144 1\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC",e:"\uC774 \uAE30\uC0AC\uC5D0\uC11C\uB294 \uBCF4\uACE0 \uC2DC\uC2A4\uD15C\uC758 \uAC00\uCE58\uAC00 \uC0C1\uC0C1\uC774 \uC544\uB2CC \uC2E4\uC81C \uC0C1\uD669\uC5D0 \uAE30\uCD08\uD558\uC5EC \uACB0\uC815\uC744 \uB0B4\uB9AC\uB294 \uAC83\uC784\uC744 \uAC15\uC870\uD569\uB2C8\uB2E4."},{q:"\uC815\uCC45\uC758 \uD3B8\uCC28\uAC00 \uC81C\uB54C \uBA85\uD655\uD558\uC9C0 \uC54A\uC73C\uBA74 \uAD6C\uD604 \uC218\uC900\uC774 \uC810\uC810 \uB354 \uB2E8\uD3B8\uD654\uB429\uB2C8\uB2E4.",s:"\uC8FC\uC81C\uB294 \u300E\uD604\uB2F9\uC815\uCC45\uC758 \uBA87 \uAC00\uC9C0 \uC911\uC694\uD55C \uBB38\uC81C\u300F(1948\uB144 1\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC",e:"\uC774 \uAE30\uC0AC\uB294 \uD1B5\uC77C\uB41C \uD589\uB3D9\uC5D0 \uB300\uD55C \uD1B5\uC77C\uB41C \uC774\uD574\uC758 \uC911\uC694\uC131\uC744 \uBC18\uC601\uD558\uC5EC \uBA87 \uAC00\uC9C0 \uD575\uC2EC \uBB38\uC81C\uB97C \uBA85\uD655\uD788 \uC124\uBA85\uD569\uB2C8\uB2E4."},{q:"\uD300 \uB0B4 \uC5F4\uC815\uC740 \uBA85\uB839\uC5D0 \uAE30\uCD08\uD560 \uBFD0\uB9CC \uC544\uB2C8\uB77C \uCC38\uC5EC\uAC10\uACFC \uC2E0\uB8B0\uC5D0 \uB2EC\uB824 \uC788\uC2B5\uB2C8\uB2E4.",s:"\uC8FC\uC81C\uB294 \u300E\uAD70\uB0B4\uBBFC\uC8FC\uC6B4\uB3D9\u300F(1948\uB144 1\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC",e:"\uC774 \uAE30\uC0AC\uB294 \uAD70\uB300 \uB0B4\uC5D0\uC11C \uBBFC\uC8FC\uC8FC\uC758\uC758 \uC5ED\uD560\uC744 \uB17C\uC758\uD558\uBA70 \uADF8\uAC83\uC774 \uB2E8\uACB0, \uAD50\uC721 \uBC0F \uC804\uD22C \uD6A8\uC728\uC131\uC744 \uC81C\uACF5\uD55C\uB2E4\uB294 \uC810\uC744 \uAC15\uC870\uD569\uB2C8\uB2E4."},{q:"\uB3D9\uC77C\uD55C \uC815\uCC45\uC774 \uB2E4\uB978 \uC9C0\uC5ED\uC5D0 \uC801\uC6A9\uB418\uB294 \uACBD\uC6B0 \uC811\uADFC \uBC29\uC2DD\uC774 \uC644\uC804\uD788 \uC77C\uB960\uC801\uC77C \uC218\uB294 \uC5C6\uC2B5\uB2C8\uB2E4.",s:'\uC8FC\uC81C\uB294 "\uB2E4\uC591\uD55C \uC9C0\uC5ED\uC758 \uD1A0\uC9C0\uBC95 \uC2DC\uD589\uC744 \uC704\uD55C \uB2E4\uC591\uD55C \uC804\uB7B5"(1948\uB144 2\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uB418\uC5C8\uC2B5\uB2C8\uB2E4.',e:"\uC774 \uAE30\uC0AC\uC5D0\uC11C\uB294 \uC815\uCC45 \uAD6C\uD604\uC774 \uC9C0\uC5ED\uC801 \uCC28\uC774\uB97C \uC874\uC911\uD558\uACE0 \uC77C\uAD00\uB41C \uC6D0\uCE59\uC744 \uC720\uC9C0\uD558\uBA74\uC11C \uC804\uB7B5\uC801 \uC720\uC5F0\uC131\uC744 \uC720\uC9C0\uD574\uC57C \uD55C\uB2E4\uACE0 \uAC15\uC870\uD569\uB2C8\uB2E4."},{q:"\uC120\uC804\uC774 \uB108\uBB34 \uC9C0\uB098\uCE58\uBA74 \uC6D0\uB798 \uD1B5\uC81C\uD560 \uC218 \uC788\uC5C8\uB358 \uBB38\uC81C\uB97C \uC65C\uACE1\uD558\uB294 \uACBD\uC6B0\uAC00 \uB9CE\uC2B5\uB2C8\uB2E4.",s:`\uC8FC\uC81C\uB294 "\uB18D\uC9C0\uAC1C\uD601 \uC120\uC804\uC758 '\uC88C\uD30C' \uC624\uB958\uB97C \uBC14\uB85C\uC7A1\uB2E4"(1948\uB144 2\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uD55C \uAC83\uC785\uB2C8\uB2E4.`,e:"\uC774 \uAE30\uC0AC\uB294 \uB300\uB7C9 \uC791\uC5C5\uC5D0\uC11C \uB2E8\uC21C\uD654\uC640 \uACFC\uC7A5\uC744 \uD53C\uD558\uACE0 \uADDC\uBAA8\uAC10\uC744 \uC720\uC9C0\uD574\uC57C \uD568\uC744 \uC0C1\uAE30\uC2DC\uD0B5\uB2C8\uB2E4."},{q:"\uAC1C\uD601\uC744 \uC218\uD589\uD558\uAE30 \uC704\uD574 \uC0C8\uB85C\uC6B4 \uC601\uC5ED\uC5D0 \uB4E4\uC5B4\uAC08 \uB54C \uBA3C\uC800 \uACBD\uACC4, \uB2E8\uACC4 \uBC0F \uC694\uC810\uC744 \uBA85\uD655\uD558\uAC8C \uC124\uBA85\uD558\uC2ED\uC2DC\uC624.",s:"\uC8FC\uC81C\uB294 \u300E\uC2E0\uD574\uBC29\uC9C0\uC5ED \uB18D\uC9C0\uAC1C\uD601\uC758 \uC694\uC810\u300F(1948\uB144 2\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC",e:"\uC774 \uAE00\uC740 \uC2DC\uD589 \uC65C\uACE1\uC744 \uBC29\uC9C0\uD558\uAE30 \uC704\uD574 \uC0C8\uB85C \uD574\uBC29\uB41C \uC9C0\uC5ED\uC758 \uB18D\uC9C0\uAC1C\uD601\uC758 \uAE30\uBCF8 \uC6D0\uCE59\uC744 \uC815\uB9AC\uD558\uB294 \uB370 \uC911\uC810\uC744 \uB450\uACE0 \uC788\uB2E4."},{q:"\uC0B0\uC5C5\uC0C1, \uC0C1\uC5C5 \uBB38\uC81C\uB97C \uB2E4\uB8F0 \uB54C \uC6B0\uB9AC\uC758 \uC785\uC7A5\uB9CC \uBCF4\uC544\uC57C \uD560 \uAC83\uC774 \uC544\uB2C8\uB77C, \uADF8\uAC83\uC774 \uC804\uCCB4 \uC0C1\uD669\uC5D0 \uB3C4\uC6C0\uC774 \uB418\uB294\uC9C0\uB3C4 \uC0B4\uD3B4\uC57C \uD569\uB2C8\uB2E4.",s:'\uC8FC\uC81C\uB294 "\uACF5\uC5C5 \uBC0F \uC0C1\uC5C5 \uC815\uCC45\uC5D0 \uAD00\uD558\uC5EC"(1948\uB144 2\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC',e:"\uC774 \uAE30\uC0AC\uB294 \uC0DD\uC0B0 \uBC1C\uC804, \uC9C8\uC11C \uC548\uC815, \uC815\uCC45 \uBC29\uD5A5 \uC0AC\uC774\uC758 \uADE0\uD615\uC744 \uCC3E\uC544\uC57C \uD55C\uB2E4\uACE0 \uAC15\uC870\uD569\uB2C8\uB2E4."},{q:"\uBCF5\uC7A1\uD55C \uC0C1\uD669\uC5D0\uC11C\uB294 \uB808\uBCA8\uC744 \uAD6C\uBCC4\uD558\uB294 \uBC29\uBC95\uC744 \uBC30\uC6B0\uACE0 \uBAA8\uB4E0 \uAC1C\uCCB4\uB97C \uD558\uB098\uC758 \uBC94\uC8FC\uB85C \uBB36\uC9C0 \uC54A\uB294 \uBC29\uBC95\uC744 \uBC30\uC6CC\uC57C \uD569\uB2C8\uB2E4.",s:'\uC8FC\uC81C\uB294 "\uBBFC\uC871 \uBD80\uB974\uC8FC\uC544\uC9C0\uC640 \uACC4\uBABD\uB41C \uC2E0\uC0AC\uC758 \uBB38\uC81C"(1948\uB144 3\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uB418\uC5C8\uC2B5\uB2C8\uB2E4.',e:"\uC774 \uAE30\uC0AC\uB294 \uACF5\uB3D9\uC804\uC120 \uD65C\uB3D9\uC5D0\uC11C \uCC28\uBCC4\uC774 \uAC00\uB2A5\uD558\uB2E4\uB294 \uC810\uC744 \uAC15\uC870\uD558\uACE0 \uB2E4\uC591\uD55C \uC0AC\uD68C \uC138\uB825\uC744 \uB2E8\uC21C\uD558\uAC8C \uBCF4\uB294 \uAC83\uC5D0 \uBC18\uB300\uD569\uB2C8\uB2E4."},{q:"\uAC04\uBD80\uB4E4\uC774 \uAC00\uC7A5 \uB450\uB824\uC6CC\uD558\uB294 \uAC83\uC740 \uBC14\uC05C \uAC83\uC774 \uC544\uB2C8\uB77C \uAD70\uC911\uC758 \uD589\uB82C\uC744 \uB530\uB974\uC9C0 \uC54A\uACE0 \uC624\uB7AB\uB3D9\uC548 \uBC14\uC05C \uAC83\uC774\uB2E4.",s:'\uC8FC\uC81C\uB294 "\uC0B0\uC2DC-\uC464\uC774\uC704\uC548 \uAC04\uBD80\uD68C\uC758 \uC5F0\uC124"(1948\uB144 4\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uB418\uC5C8\uC2B5\uB2C8\uB2E4.',e:"\uC5F0\uC124\uC740 \uD1A0\uC9C0, \uC815\uCC45, \uAC04\uBD80 \uC2A4\uD0C0\uC77C\uC5D0 \uCD08\uC810\uC744 \uB9DE\uCDB0 \uBAA8\uB4E0 \uC0AC\uC5C5\uC774 \uAD81\uADF9\uC801\uC73C\uB85C \uB300\uC911\uC758 \uAE30\uCD08\uB85C \uB3CC\uC544\uAC00\uC57C \uD55C\uB2E4\uB294 \uC810\uC744 \uAC15\uC870\uD588\uC2B5\uB2C8\uB2E4."},{q:"\uC2E0\uBB38\uC744 \uC6B4\uC601\uD55C\uB2E4\uB294 \uAC83\uC740 \uD63C\uC7A3\uB9D0\uC744 \uD558\uB294 \uAC83\uC774 \uC544\uB2C8\uB77C \uC815\uB9D0\uB85C \uC911\uC694\uD55C \uAC83\uB4E4\uC744 \uB300\uC911\uC5D0\uAC8C \uBD84\uBA85\uD558\uAC8C \uC804\uB2EC\uD558\uB294 \uAC83\uC785\uB2C8\uB2E4.",s:"\uC8FC\uC81C\uB294 \u300E\uC9C4\uC218\uC77C\uBCF4 \uD3B8\uC9D1\uC9C4\uACFC\uC758 \uB300\uD654\u300F(1948\uB144 4\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC",e:"\uC774 \uAE30\uC0AC\uB294 \uC800\uB110\uB9AC\uC998\uC774 \uC5B4\uB5BB\uAC8C \uC2E4\uC81C \uD22C\uC7C1\uC5D0 \uAE30\uC5EC\uD558\uB294\uC9C0, \uC5B8\uC5B4, \uC785\uC7A5, \uC0AC\uBB3C\uC758\uC2DD\uC744 \uAC15\uC870\uD558\uB294 \uBC29\uBC95\uC744 \uB17C\uC758\uD569\uB2C8\uB2E4."},{q:"\uC0C8\uB85C\uC6B4 \uBD84\uC57C\uC5D0\uC11C \uC77C\uD560 \uB54C \uAC00\uC7A5 \uC911\uC694\uD55C \uAC83\uC740 \uB2E8\uBC88\uC5D0 \uC18D\uB3C4\uB97C \uCD94\uAD6C\uD558\uAE30\uBCF4\uB2E4\uB294 \uC548\uC815\uC801\uC774\uACE0 \uC815\uD655\uD558\uBA70 \uB2E8\uACC4\uBCC4\uB85C \uC9C4\uD589\uD558\uB294 \uAC83\uC785\uB2C8\uB2E4.",s:"\uC8FC\uC81C\uB294 \u300E\uC2E0\uD574\uBC29\uC9C0\uC5ED \uB18D\uCD0C\uC0AC\uC5C5\uC758 \uC804\uB7B5\uC801 \uBB38\uC81C\u300F(1948\uB144 5\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uD558\uC600\uB2E4.",e:"\uC774 \uAE00\uC740 \uACBD\uD5D8\uC758 \uBAA8\uBC29\uACFC \uC131\uAE09\uD55C \uBC1C\uC804\uC744 \uB9C9\uAE30 \uC704\uD574 \uB18D\uCD0C\uC77C\uC758 \uB9AC\uB4EC\uACFC \uC804\uB7B5\uC744 \uAC15\uC870\uD55C\uB2E4."},{q:"\uAC1C\uD601\uC774 \uBE60\uB974\uAC8C \uC9C4\uD589\uB420\uC218\uB85D \uD300 \uC790\uCCB4\uB97C \uB3D9\uC2DC\uC5D0 \uBC14\uB85C\uC7A1\uB294 \uAC83\uC774 \uD544\uC694\uD558\uB2E4",s:"\uC8FC\uC81C\uB294 \u300E1948\uB144 \uB18D\uC9C0\uAC1C\uD601\uC0AC\uC5C5\uACFC \uB2F9\uAC15\uD654\uC0AC\uC5C5\u300F(1948\uB144 5\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC",e:"\uC774 \uAE00\uC5D0\uC11C\uB294 \uB18D\uC9C0\uAC1C\uD601\uACFC \uC815\uB2F9\uD1B5\uD569\uC744 \uD568\uAED8 \uC5B8\uAE09\uD558\uACE0 \uC788\uB294\uB370, \uC774\uB294 \uC815\uCC45\uC758 \uC131\uD328\uAC00 \uC870\uC9C1\uC758 \uC21C\uC218\uC131\uACFC \uC2E4\uD589\uB825\uACFC \uBD88\uAC00\uBD84\uC758 \uAD00\uACC4\uC784\uC744 \uC2DC\uC0AC\uD55C\uB2E4."},{q:"\uC0AC\uC6B4\uB4DC \uC2DC\uC2A4\uD15C\uC758 \uAC00\uCE58\uB294 \uC911\uC694\uD55C \uC21C\uAC04\uC5D0 \uD604\uC7A5\uC5D0\uC11C \uAD6C\uBA4D\uC744 \uBA54\uC6B0\uAE30 \uC704\uD574 \uAC1C\uC778\uC5D0\uAC8C \uC758\uC874\uD558\uC9C0 \uC54A\uB294 \uB370 \uC788\uC2B5\uB2C8\uB2E4.",s:"\uC8FC\uC81C\uB294 \u300A\uB2F9\uC704\uC6D0\uD68C \uC81C\uB3C4\uB97C \uAC1C\uC120\uD560 \uB370 \uB300\uD558\uC5EC\u300B(1948\uB144 9\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uD558\uC600\uB2E4.",e:"\uAE30\uC0AC\uC5D0\uC11C\uB294 \uB2F9\uC704\uC6D0\uD68C \uC81C\uB3C4\uAC00 \uD615\uC2DD\uC801\uC778 \uAC83\uC774 \uC544\uB2C8\uB77C \uC9D1\uD569\uC801 \uC9C0\uB3C4\uB825\uC774 \uC9C4\uC815\uC73C\uB85C \uC548\uC815\uC801\uC73C\uB85C \uC6B4\uC601\uB418\uAE30 \uC704\uD55C \uC7A5\uCE58\uC784\uC744 \uAC15\uC870\uD558\uACE0 \uC788\uB2E4."},{q:"\uACF5\uB3D9\uC758 \uC5B5\uC555\uC5D0 \uB9DE\uC11C \uC9C0\uC5ED \uAC04 \uB2E8\uACB0\uC740 \uADF8 \uC790\uCCB4\uB85C \uD798\uC774\uB2E4",s:"\uC8FC\uC81C\uB294 \u300A\uC138\uACC4 \uD601\uBA85\uC138\uB825\uC774 \uB2E8\uACB0\uD558\uC5EC \uC81C\uAD6D\uC8FC\uC758\uCE68\uB7B5\uC744 \uBC18\uB300\uD55C\uB2E4\u300B(1948\uB144 11\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uD55C \uAC83\uC774\uB2E4.",e:"\uC774 \uAE30\uC0AC\uB294 \uAD6D\uC81C\uC801 \uAD00\uC810\uC5D0\uC11C \uBC18\uC81C\uAD6D\uC8FC\uC758 \uD22C\uC7C1\uC758 \uACF5\uD1B5\uC131\uC744 \uAC15\uC870\uD558\uACE0 \uBBFC\uC871 \uC6B4\uB3D9\uC744 \uACE0\uB9BD\uC801\uC73C\uB85C \uBCF4\uB294 \uAC83\uC5D0 \uBC18\uB300\uD569\uB2C8\uB2E4."},{q:"\uD070 \uBCC0\uD654\uAC00 \uC624\uBA74 \uAD6D\uBD80\uC801\uC778 \uC138\uBD80 \uC0AC\uD56D\uC5D0 \uC5F0\uC5F0\uD558\uAE30\uBCF4\uB2E4 \uBA3C\uC800 \uCD94\uC138\uB97C \uC815\uD655\uD558\uAC8C \uD310\uB2E8\uD558\uB294 \uAC83\uC774 \uB354 \uC911\uC694\uD569\uB2C8\uB2E4.",s:'\uC8FC\uC81C\uB294 "\uC911\uAD6D \uAD70\uC0AC \uC815\uC138\uC758 \uC8FC\uC694 \uBCC0\uD654"(1948\uB144 11\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uB418\uC5C8\uC2B5\uB2C8\uB2E4.',e:"\uAE30\uC0AC\uB294 \uAD70 \uC0C1\uD669\uC744 \uC0B0\uBC1C\uC801\uC778 \uACB0\uACFC\uC5D0 \uC774\uB04C\uB9AC\uAE30\uBCF4\uB2E4\uB294 \uC804\uCCB4\uC801\uC778 \uC804\uB825 \uBCC0\uD654\uC758 \uAD00\uC810\uC5D0\uC11C \uBCF4\uC544\uC57C \uD55C\uB2E4\uACE0 \uAC15\uC870\uD55C\uB2E4."},{q:"\uB9CE\uC740 \uC9C1\uC5C5\uC5D0\uC11C \uAC00\uC7A5 \uC5B4\uB824\uC6B4 \uC810\uC740 \uC2DC\uC791\uC774 \uC544\uB2C8\uB77C \uC784\uACC4\uC810\uC5D0 \uB3C4\uB2EC\uD588\uC744 \uB54C \uB05D\uAE4C\uC9C0 \uACC4\uC18D\uD560 \uC218 \uC788\uB294\uC9C0 \uC5EC\uBD80\uC785\uB2C8\uB2E4.",s:"\uC8FC\uC81C\uB294 \u300A\uD601\uBA85\uC744 \uB05D\uAE4C\uC9C0 \uD5A5\uD558\uC5EC\u300B(1948\uB144 12\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uD55C \uAC83\uC785\uB2C8\uB2E4.",e:"\uC774 \uAE30\uC0AC\uC5D0\uC11C\uB294 \uC2B9\uB9AC\uAC00 \uAC00\uAE4C\uC6CC\uC9C8 \uB54C \uACB0\uB2E8\uB825\uACFC \uC5F0\uC18D\uC131\uC744 \uC720\uC9C0\uD558\uACE0 \uC911\uAC04\uC5D0 \uC77C\uC2DC \uC911\uC9C0\uB97C \uBC29\uC9C0\uD558\uB294 \uAC83\uC744 \uAC15\uC870\uD569\uB2C8\uB2E4."},{q:"\uD55C \uC2DC\uB300\uAC00 \uC815\uB9D0\uB85C \uD55C \uD398\uC774\uC9C0\uB97C \uB118\uAE30\uBA74 \uB300\uBD80\uBD84\uC758 \uC0AC\uB78C\uB4E4\uC774 \uAD6D\uAC00\uB97C \uC790\uC2E0\uC758 \uC0AC\uC5C5\uC73C\uB85C \uC5EC\uAE30\uAE30 \uC2DC\uC791\uD55C\uB2E4\uB294 \uC2E0\uD638\uC785\uB2C8\uB2E4.",s:'\uC8FC\uC81C\uB294 "\uC911\uAD6D \uC778\uBBFC\uC774 \uC77C\uC5B4\uC11C\uB2E4"(1949\uB144 9\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uD55C \uAC83\uC785\uB2C8\uB2E4.',e:"\uC774\uBC88 \uC5F0\uC124\uC740 \uC2E0\uC911\uAD6D \uAC74\uAD6D\uC758 \uC5ED\uC0AC\uC801 \uC758\uC758\uB97C \uC911\uC2EC\uC73C\uB85C, \uC9C0\uBC30\uC801 \uC9C0\uC704\uC640 \uC2DC\uB300\uC801 \uC804\uD658\uC744 \uAC15\uC870\uD588\uB2E4."},{q:"\uC704\uB300\uD55C \uB2E8\uACB0\uC740 \uCD94\uC0C1\uC801\uC778 \uD5CC\uC0AC\uAC00 \uC544\uB2C8\uB77C \uC0C8\uB85C\uC6B4 \uB098\uB77C\uC758 \uAC00\uC7A5 \uAE30\uBCF8\uC801\uC778 \uC815\uCE58\uC801 \uC790\uC6D0\uC785\uB2C8\uB2E4.",s:'\uC8FC\uC81C\uB294 "\uC911\uAD6D \uC778\uBBFC\uC758 \uC704\uB300\uD55C \uB2E8\uACB0 \uB9CC\uC138"(1949\uB144 9\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uB418\uC5C8\uC2B5\uB2C8\uB2E4.',e:"\uC774 \uAE30\uC0AC\uB294 \uACF5\uD1B5\uC758 \uBAA9\uC801\uC744 \uC704\uD574 \uC11C\uB85C \uB2E4\uB978 \uC138\uB825\uC774 \uD568\uAED8 \uBAA8\uC774\uB294 \uAC83\uC758 \uC911\uC694\uC131\uC744 \uAC15\uC870\uD558\uACE0 \uAD6D\uAC00 \uAC74\uC124\uC758 \uAE30\uCD08\uB85C\uC11C \uB2E8\uACB0\uC744 \uAC15\uC870\uD569\uB2C8\uB2E4."},{q:"\uD655\uACE0\uD55C \uC785\uC7A5\uC740 \uB9D0\uB85C \uBA85\uD655\uD560 \uBFD0\uB9CC \uC544\uB2C8\uB77C, \uD575\uC2EC \uC0AC\uD56D\uC5D0\uC11C \uB05D\uAE4C\uC9C0 \uACE0\uC9D1\uD560 \uAC83\uC778\uC9C0\uC5D0\uB3C4 \uBC18\uC601\uB429\uB2C8\uB2E4.",s:"\uC8FC\uC81C\uB294 \u300E\uC644\uC804\uD55C \uD601\uBA85\uAC00\uAC00 \uB418\uC790\u300F(1950\uB144 6\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC",e:"\uC774 \uAE30\uC0AC\uB294 \uD601\uBA85\uAC00\uB4E4\uC758 \uC131\uC2E4\uC131\uC774 \uADF8\uB4E4\uC758 \uC77C\uAD00\uB41C \uD589\uB3D9, \uD655\uACE0\uD55C \uC2A4\uD0C0\uC77C \uBC0F \uCC45\uC784\uC5D0 \uBC18\uC601\uB41C\uB2E4\uB294 \uC810\uC744 \uAC15\uC870\uD569\uB2C8\uB2E4."},{q:"\uC9C4\uC815\uD55C \uB864\uBAA8\uB378\uC740 \uCE6D\uCC2C\uBC1B\uB294 \uC0AC\uB78C\uC774 \uC544\uB2C8\uB77C, \uB2E4\uB978 \uC0AC\uB78C\uB4E4\uC774 \uD568\uAED8 \uC790\uC2E0\uC758 \uAE30\uC900\uC744 \uB192\uC77C \uC218 \uC788\uB3C4\uB85D \uC774\uB04C\uC5B4 \uC904 \uC218 \uC788\uB294 \uC0AC\uB78C\uC785\uB2C8\uB2E4.",s:"\uC8FC\uC81C\uB294 \u300E\uB2F9\uC2E0\uC740 \uC628 \uBBFC\uC871\uC758 \uBAA8\uBC94\uC774\uC2ED\uB2C8\uB2E4\u300F(1950\uB144 9\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uD55C \uAC83\uC785\uB2C8\uB2E4.",e:"\uC774 \uC5F0\uC124\uC5D0\uC11C\uB294 \uC120\uC9C4 \uC778\uBB3C\uC758 \uC2DC\uC5F0\uACFC \uC911\uCD94\uC801 \uC5ED\uD560\uC744 \uAC15\uC870\uD558\uC5EC \uC5ED\uD560 \uBAA8\uB378\uC744 \uC870\uC9C1 \uB3D9\uC6D0\uC758 \uC77C\uBD80\uB85C \uC0BC\uC558\uC2B5\uB2C8\uB2E4."},{q:"\uB2F9\uC2E0\uC774 \uAC15\uD560\uC218\uB85D \uC790\uC81C\uB825\uC744 \uD589\uC0AC\uD558\uB294 \uBC29\uBC95\uC744 \uB354 \uB9CE\uC774 \uC54C\uC544\uC57C \uD558\uBA70, \uC804\uC7A5\uC5D0\uC11C \uC783\uC5B4\uBC84\uB824\uC57C \uD560 \uADDC\uC728\uC740 \uB354 \uC801\uC5B4\uC9D1\uB2C8\uB2E4.",s:"\uC8FC\uC81C\uB294 \u300A\uC911\uAD6D\uC778\uBBFC\uC9C0\uC6D0\uAD70\uC740 \uC870\uC120\uC758 \uC0B0\uC218\uBAA9\uC744 \uC9C0\uCF1C\uC57C \uD55C\uB2E4\u300B(1951\uB144 1\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uD55C \uAC83\uC774\uB2E4.",e:"\uC774 \uAE30\uC0AC\uB294 \uAD6D\uC81C\uC8FC\uC758, \uAD70\uC0AC \uADDC\uC728 \uBC0F \uB300\uC911 \uAD00\uACC4\uB97C \uC5F0\uACB0\uD558\uBA70 \uC2A4\uD0C0\uC77C\uB3C4 \uC804\uD22C \uD6A8\uC728\uC131\uC784\uC744 \uAC15\uC870\uD569\uB2C8\uB2E4."},{q:"\uCCA8\uC608\uD55C \uBB38\uC81C\uB97C \uB2E4\uB8F0 \uB54C\uB294 \uB300\uC911\uC5D0 \uB354 \uC758\uC874\uD558\uACE0 \uC0AC\uC2E4\uACFC \uC808\uCC28\uC5D0 \uC8FC\uBAA9\uD574\uC57C \uD55C\uB2E4.",s:'\uC8FC\uC81C\uB294 "\uBC18\uD601\uBA85\uC744 \uC9C4\uC555\uD558\uB824\uBA74 \uB2F9\uC758 \uB300\uC911\uB178\uC120\uC744 \uC2E4\uC2DC\uD574\uC57C \uD55C\uB2E4"(1951\uB144 5\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uD55C \uAC83\uC774\uB2E4.',e:"\uAE30\uC0AC\uB294 \uACE0\uC555\uC801\uC778 \uD22C\uC7C1 \uC18D\uC5D0\uC11C\uB3C4 \uB300\uC911\uB178\uC120\uACFC \uC870\uC0AC\xB7\uAC80\uC99D\uC5D0\uC11C \uBC97\uC5B4\uB0A0 \uC218 \uC5C6\uC74C\uC744 \uAC15\uC870\uD558\uACE0 \uC788\uB2E4."},{q:"\uB300\uADDC\uBAA8 \uCEA0\uD398\uC778\uC774 \uD6A8\uACFC\uC801\uC77C \uC218 \uC788\uB294\uC9C0 \uC5EC\uBD80\uB294 \uAC00\uC7A5 \uC2EC\uAC01\uD55C \uD559\uB300\uAC00 \uC788\uB294 \uACF3\uC5D0 \uB3C4\uB2EC\uD558\uB294\uC9C0 \uC5EC\uBD80\uC5D0 \uB2EC\uB824 \uC788\uC2B5\uB2C8\uB2E4.",s:'\uC8FC\uC81C\uB294 "\uC0BC\uC545\uB300\uC2B9\uB9AC"(1951\uB144 10\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uD55C \uAC83\uC785\uB2C8\uB2E4.',e:"\uC774 \uAE30\uC0AC\uB294 \uC5EC\uB7EC \uCEA0\uD398\uC778\uC758 \uACB0\uACFC\uB97C \uC694\uC57D\uD558\uACE0 \uBD80\uD328 \uBC29\uC9C0, \uD3D0\uAE30\uBB3C \uBC29\uC9C0 \uBC0F \uAD00\uB8CC\uC8FC\uC758 \uBC29\uC9C0\uC758 \uACF5\uB3D9 \uC911\uC694\uC131\uC744 \uAC15\uC870\uD569\uB2C8\uB2E4."},{q:"\uC624\uB798\uB41C \uD3D0\uD574\uB97C \uCCAD\uC0B0\uD558\uB294 \uAC83\uC740 \uB2E8\uC9C0 \uBA87 \uAC00\uC9C0 \uC0AC\uAC74\uC744 \uC870\uC0AC\uD558\uB294 \uB370\uB9CC \uC758\uC874\uD558\uB294 \uAC83\uC774 \uC544\uB2C8\uB77C \uB3C4\uB355\uACFC \uC9C8\uC11C\uB97C \uC7AC\uAC74\uD558\uB294 \uAE30\uD68C\uB97C \uAC16\uB294 \uAC83\uC785\uB2C8\uB2E4.",s:'\uC8FC\uC81C\uB294 ""3\uAC1C \uC548\uD2F0"\uC640 "5\uAC1C \uC548\uD2F0"\uC758 \uD22C\uC7C1\uC5D0 \uAD00\uD558\uC5EC(1951\uB144 11\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uB418\uC5C8\uC2B5\uB2C8\uB2E4.',e:"\uC774 \uAE00\uC740 \uD2B9\uC218\uD22C\uC7C1\uC744 \uC815\uCE58\uAD8C\uB825 \uAC74\uC124, \uACBD\uC81C\uC9C8\uC11C, \uAC04\uBD80\uC591\uC2DD\uACFC \uC5F0\uACB0\uC2DC\uD0A8\uB2E4."},{q:"\uC0C1\uD669\uC774 \uBCC0\uD558\uBA74 \uADF8\uC5D0 \uB530\uB77C \uC8FC\uC694 \uBAA8\uC21C\uB3C4 \uBCC0\uD560 \uAC83\uC774\uBA70, \uC6B0\uB9AC\uB294 \uD56D\uC0C1 \uC608\uC804\uC758 \uD310\uB2E8\uC744 \uACE0\uC218\uD560 \uC218\uB294 \uC5C6\uC2B5\uB2C8\uB2E4.",s:'\uC8FC\uC81C\uB294 "\uB178\uB3D9\uACC4\uAE09\uACFC \uBD80\uB974\uC8FC\uC544\uC9C0 \uC0AC\uC774\uC758 \uBAA8\uC21C\uC740 \uC8FC\uC694 \uAD6D\uB0B4 \uBAA8\uC21C\uC774\uB2E4"(1952\uB144 6\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uB418\uC5C8\uC2B5\uB2C8\uB2E4.',e:"\uAE30\uC0AC\uB294 \uC0AC\uD68C \uAD6C\uC870\uAC00 \uBCC0\uD654\uD568\uC5D0 \uB530\uB77C \uAC00\uC0AC \uB178\uB3D9\uC758 \uC8FC\uC694 \uBAA8\uC21C\uC744 \uC7AC\uD655\uC778\uD560 \uD544\uC694\uAC00 \uC788\uC74C\uC744 \uAC15\uC870\uD569\uB2C8\uB2E4."},{q:"\uD1B5\uC77C\uC740 \uD63C\uB780\uC2A4\uB7EC\uC6B4 \uD63C\uB780\uC774 \uC544\uB2D9\uB2C8\uB2E4. \uACBD\uACC4\uAC00 \uBA85\uD655\uD574\uC9C0\uBA74 \uD611\uB825\uC774 \uB354\uC6B1 \uC548\uC815\uC801\uC774 \uB429\uB2C8\uB2E4.",s:'\uC8FC\uC81C\uB294 "\uB2E8\uACB0\uD558\uC5EC \uC6B0\uB9AC\uC640 \uC801 \uC0AC\uC774\uC5D0 \uBA85\uD655\uD55C \uACBD\uACC4\uC120\uC744 \uADF8\uC73C\uB77C"(1952\uB144 8\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uD55C \uAC83\uC785\uB2C8\uB2E4.',e:"\uAE30\uC0AC\uC5D0\uC11C\uB294 \uB2E8\uACB0\uC744 \uC704\uD574 \uB178\uB825\uD558\uB294 \uB3D9\uC2DC\uC5D0 \uC6D0\uCE59\uC5D0 \uC785\uAC01\uD55C \uACBD\uACC4\uB97C \uC720\uC9C0\uD558\uACE0 \uD63C\uB780\uC2A4\uB7EC\uC6B4 \uB300\uC0C1\uC744 \uD53C\uD574\uC57C \uD55C\uB2E4\uACE0 \uAC15\uC870\uD569\uB2C8\uB2E4."},{q:"\uC870\uC9C1\uC774 \uD604\uC2E4\uACFC\uC758 \uC811\uCD09\uC744 \uC783\uC73C\uBA74 \uAC00\uC7A5 \uBA3C\uC800 \uCEE4\uC9C0\uB294 \uAC83\uC740 \uAD00\uB8CC\uC8FC\uC758\uC785\uB2C8\uB2E4.",s:'\uC8FC\uC81C\uB294 "\uAD00\uB8CC\uC8FC\uC758, \uBA85\uB839\uC8FC\uC758, \uBC95\uACFC \uADDC\uC728 \uBC18\uB300"(1953\uB144 1\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uB418\uC5C8\uC2B5\uB2C8\uB2E4.',e:"\uC774 \uAE00\uC740 \uC5EC\uB7EC \uAC00\uC9C0 \uC720\uD574\uD55C \uC2A4\uD0C0\uC77C\uC744 \uBE44\uD310\uD558\uB294 \uB370 \uCD08\uC810\uC744 \uB9DE\uCD94\uBA70, \uC815\uCE58\uAD8C\uB825 \uAC74\uC124\uC5D0 \uC788\uC5B4\uC11C \uD615\uC2DD\uC8FC\uC758\uC640 \uD63C\uB3C8\uC744 \uB9C9\uC544\uC57C \uD568\uC744 \uC0C1\uAE30\uC2DC\uD0A8\uB2E4."},{q:"\uC80A\uC740\uC774\uB4E4\uC744 \uC774\uB04C \uB54C \uB2E8\uC9C0 \uC61B \uB3D9\uC9C0\uB4E4\uCC98\uB7FC \uB418\uB77C\uACE0 \uC694\uAD6C\uD560 \uAC83\uC774 \uC544\uB2C8\uB77C \uADF8\uB4E4\uC758 \uB9AC\uB4EC\uACFC \uD2B9\uC131\uB3C4 \uC774\uD574\uD574\uC57C \uD569\uB2C8\uB2E4.",s:"\uC8FC\uC81C\uB294 \u300A\uCCAD\uB144\uB3D9\uB9F9\uC0AC\uC5C5\uC740 \uCCAD\uB144\uC758 \uD2B9\uC131\uC744 \uBC30\uB824\uD574\uC57C \uD55C\uB2E4\u300B(1953\uB144 6\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uD55C \uAC83\uC774\uB2E4.",e:"\uAE30\uC0AC\uC5D0\uC11C\uB294 \uCCAD\uC18C\uB144 \uD65C\uB3D9\uC744 \uD560 \uB54C \uB300\uC0C1 \uADF8\uB8F9 \uAC04\uC758 \uCC28\uC774\uB97C \uC874\uC911\uD558\uACE0 \uC801\uC808\uD55C \uBC29\uC2DD\uC73C\uB85C \uC870\uC9C1\uD558\uACE0 \uC9C0\uB3C4\uD574\uC57C \uD55C\uB2E4\uACE0 \uAC15\uC870\uD569\uB2C8\uB2E4."},{q:"\uC804\uD658\uD615\uC744 \uB2E4\uB8F0 \uB54C \uD575\uC2EC\uC740 \uC774\uB984\uC774 \uC21C\uC218\uD55C\uC9C0 \uC544\uB2CC\uC9C0\uAC00 \uC544\uB2C8\uB77C \uC804\uCCB4\uC801\uC778 \uBCC0\uD654\uC5D0 \uB3C4\uC6C0\uC774 \uB418\uB294\uC9C0 \uC5EC\uBD80\uC785\uB2C8\uB2E4.",s:'\uC8FC\uC81C\uB294 "\uAD6D\uAC00 \uC790\uBCF8\uC8FC\uC758\uC5D0 \uB300\uD558\uC5EC"(1953\uB144 7\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC',e:"\uC774 \uAE00\uC740 \uC804\uD658\uAE30\uC5D0\uC11C \uAD6D\uAC00\uC790\uBCF8\uC8FC\uC758\uC758 \uC5ED\uD560\uC744 \uB17C\uC758\uD558\uACE0, \uC2E4\uC81C \uACB0\uACFC\uB85C\uBD80\uD130 \uC815\uCC45\uC758 \uAC00\uCE58\uB97C \uD310\uB2E8\uD558\uB294 \uAC83\uC744 \uAC15\uC870\uD569\uB2C8\uB2E4."},{q:"\uB2E8\uACC4 \uC804\uD658 \uC774\uD6C4\uC5D0\uB294 \uBD84\uC0B0\uB41C \uC5C5\uBB34\uB97C \uD1B5\uD569\uD560 \uC218 \uC788\uB294 \uCD1D\uC120\uC774 \uC788\uC5B4\uC57C \uD55C\uB2E4.",s:"\uC8FC\uC81C\uB294 \u300E\uC804\uD658\uAE30 \uB2F9\uC758 \uCD1D\uB178\uC120\u300F(1953\uB144 8\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC",e:"\uC774 \uAE30\uC0AC\uC5D0\uC11C\uB294 \uC0B0\uC5C5\uD654, \uBCC0\uD601, \uAC74\uC124 \uC791\uC5C5\uC744 \uD1B5\uD569\uD558\uC5EC \uAC01\uC790\uAC00 \uC790\uC2E0\uC758 \uC77C\uC744 \uD558\uC9C0 \uC54A\uB3C4\uB85D \uC77C\uBC18 \uB178\uC120\uC744 \uC0AC\uC6A9\uD560 \uAC83\uC744 \uAC15\uC870\uD569\uB2C8\uB2E4."},{q:"\uC2B9\uB9AC\uC758 \uC758\uBBF8\uB294 \uC804\uC7C1\uC744 \uB05D\uB0B4\uB294 \uAC83\uBFD0\uB9CC \uC544\uB2C8\uB77C \uC55E\uC73C\uB85C \uC804\uC7C1\uC774 \uC5B4\uB5BB\uAC8C \uC9C4\uD589\uB420 \uAC83\uC778\uC9C0\uB97C \uBC14\uAFB8\uB294 \uAC83\uC774\uAE30\uB3C4 \uD569\uB2C8\uB2E4.",s:"\uC8FC\uC81C\uB294 \u300E\uD56D\uBBF8\uC6D0\uC870\uC804\uC7C1\uC5D0\uC11C\uC758 \uC704\uB300\uD55C \uC2B9\uB9AC\uC640 \uC7A5\uB798\uACFC\uC5C5\u300F(1953\uB144 9\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uD55C \uAC83\uC774\uB2E4.",e:"\uC774 \uAE00\uC740 \uBBF8\uAD6D\uC758 \uCE68\uB7B5\uC5D0 \uC800\uD56D\uD558\uACE0 \uD55C\uAD6D\uC744 \uC9C0\uC6D0\uD558\uB294 \uAC83\uC758 \uC815\uCE58\uC801, \uC804\uB7B5\uC801 \uC758\uBBF8\uB97C \uC694\uC57D\uD558\uB294 \uB3D9\uC2DC\uC5D0 \uC804\uD6C4 \uAC74\uC124\uACFC \uC900\uBE44\uC5D0 \uAD00\uC2EC\uC744 \uB3CC\uB9B0\uB2E4."},{q:"\uC81C\uB3C4\uC801 \uD14D\uC2A4\uD2B8\uC758 \uAC00\uCE58\uB294 \uD615\uC131\uB41C \uBC29\uD5A5\uC744 \uC548\uC815\uC2DC\uD0A4\uACE0 \uBA85\uD655\uD558\uAC8C \uD558\uB294 \uB370 \uC788\uB2E4.",s:'\uC8FC\uC81C\uB294 "\uC911\uD654\uC778\uBBFC\uACF5\uD654\uAD6D \uD5CC\uBC95\uCD08\uC548\uC5D0 \uB300\uD558\uC5EC"(1954\uB144 6\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC',e:"\uC774 \uAE30\uC0AC\uB294 \uD5CC\uBC95 \uCD08\uC548\uC744 \uC911\uC2EC\uC73C\uB85C \uAD6D\uAC00 \uC2DC\uC2A4\uD15C\uC758 \uC124\uACC4\uB97C \uBA85\uD655\uD788 \uD558\uACE0 \uC6D0\uCE59\uC801\uC778 \uBAA9\uD45C\uB97C \uC81C\uB3C4\uC801 \uD45C\uD604\uC73C\uB85C \uAD6C\uD604\uD569\uB2C8\uB2E4."},{q:"\uAC74\uC124\uAE30\uAC04\uC5D0 \uAC00\uC7A5 \uD544\uC694\uD55C \uAC83\uC740 \uB2E8\uC21C\uD55C \uC5F4\uC815\uC774 \uC544\uB2C8\uB77C \uC7A5\uAE30\uBAA9\uD45C\uB97C \uC9C0\uC18D\uC801\uC778 \uC2E4\uCC9C\uC73C\uB85C \uC804\uD658\uD558\uB294 \uAC83\uC785\uB2C8\uB2E4.",s:"\uC8FC\uC81C\uB294 \u300A\uC0AC\uD68C\uC8FC\uC758\uB300\uAD6D \uAC74\uC124\uC744 \uC704\uD55C \uD22C\uC7C1\u300B(1954\uB144 9\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uD55C \uAC83\uC774\uB2E4.",e:"\uC774 \uC5F0\uC124\uC740 \uAD6D\uAC00 \uAC74\uC124\uC758 \uC7A5\uAE30\uC801 \uC131\uACA9\uC744 \uAC15\uC870\uD558\uACE0 \uC815\uCE58\uC801 \uBAA9\uD45C, \uACBD\uC81C\uC801 \uC5C5\uBB34, \uC870\uC9C1 \uC5ED\uB7C9\uC758 \uD1B5\uD569\uC744 \uC694\uAD6C\uD588\uC2B5\uB2C8\uB2E4."},{q:"\uC544\uBB34\uB9AC \uD070 \uC704\uD611\uC774\uB77C \uD560\uC9C0\uB77C\uB3C4 \uC0AC\uB78C\uC758 \uB73B\uC744 \uAC81\uC8FC\uC9C0 \uBABB\uD558\uBA74 \uBBF8\uB798\uB3C4 \uAC81\uB0BC \uC218 \uC5C6\uC2B5\uB2C8\uB2E4.",s:'\uC8FC\uC81C\uB294 "\uC6D0\uC790\uD3ED\uD0C4\uC740 \uC911\uAD6D\uC778\uC744 \uB180\uB77C\uAC8C \uD560 \uC218 \uC5C6\uB2E4"(1955\uB144 1\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uB418\uC5C8\uC2B5\uB2C8\uB2E4.',e:"\uC774 \uAE30\uC0AC\uB294 \uD575 \uC704\uD611\uC5D0 \uC9C1\uBA74\uD558\uC5EC \uC804\uB7B5\uC801 \uD3C9\uC628\uC744 \uC720\uC9C0\uD560 \uD544\uC694\uC131\uC744 \uAC15\uC870\uD558\uACE0 \uB450\uB824\uC6C0 \uB54C\uBB38\uC5D0 \uB3C5\uB9BD\uC801\uC778 \uC785\uC7A5\uC744 \uD3EC\uAE30\uD558\uB294 \uAC83\uC5D0 \uBC18\uB300\uD569\uB2C8\uB2E4."},{q:"\uCEE8\uD37C\uB7F0\uC2A4\uB97C \uAC1C\uCD5C\uD55C\uB2E4\uB294 \uAC83\uC740 \uACB0\uB860\uC744 \uBC18\uBCF5\uD558\uB294 \uAC83\uC774 \uC544\uB2C8\uB77C, \uBB38\uC81C\uC640 \uBC29\uD5A5\uC744 \uD55C \uCC28\uC6D0 \uB354 \uC124\uBA85\uD560 \uC218 \uC788\uB294 \uAE30\uD68C\uB97C \uAC16\uB294 \uAC83\uC785\uB2C8\uB2E4.",s:'\uC8FC\uC81C\uB294 "\uC911\uAD6D\uACF5\uC0B0\uB2F9 \uC804\uAD6D\uB300\uD45C\uB300\uD68C \uC5F0\uC124"(1955\uB144 3\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uD55C \uAC83\uC785\uB2C8\uB2E4.',e:"\uC5F0\uC124\uC5D0\uC11C\uB294 \uC0C8\uB85C\uC6B4 \uAC74\uC124 \uD658\uACBD\uC5D0\uC11C \uC774\uD574\uB97C \uD1B5\uC77C\uD558\uACE0 \uC5C5\uBB34 \uBC29\uC2DD\uC744 \uBC14\uB85C\uC7A1\uC73C\uBA70 \uD575\uC2EC \uC5C5\uBB34\uB97C \uCD94\uC9C4\uD574\uC57C \uD55C\uB2E4\uACE0 \uAC15\uC870\uD588\uC2B5\uB2C8\uB2E4."},{q:"\uBD84\uC0B0\uB41C \uC18C\uADDC\uBAA8 \uC0DD\uC0B0\uC744 \uC870\uC9C1\uD654\uD558\uB294 \uC5F4\uC1E0\uB294 \uB354 \uAE09\uD558\uAC8C \uC11C\uB450\uB974\uB294 \uAC83\uC774 \uC544\uB2C8\uB77C, \uD0C8\uCD9C\uAD6C\uB97C \uC5F4\uC5B4\uC8FC\uB294 \uAC83\uC774\uB2E4.",s:"\uC8FC\uC81C\uB294 \u300E\uB18D\uC5C5\uD611\uB3D9\uC870\uD569\uC758 \uBB38\uC81C\uC5D0 \uB300\uD558\uC5EC\u300F(1955\uB144 7\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC",e:"\uC774 \uAE00\uC740 \uB18D\uC5C5\uD611\uB3D9\uC870\uD569 \uCD94\uC9C4\uC758 \uCC28\uC774\uC810\uC744 \uB17C\uC758\uD558\uACE0 \uBC29\uD5A5\uD310\uB2E8\uACFC \uB300\uC911\uC218\uC6A9\uC758 \uAD00\uACC4\uB97C \uAC15\uC870\uD55C\uB2E4."},{q:"\uBAA8\uB4E0 \uAC1C\uD601\uC740 \uAC00\uC7A5 \uBBFF\uC744 \uB9CC\uD55C \uB3D9\uC6D0\uB825\uC744 \uCC3E\uC544\uC57C \uD558\uBA70 \uBB38\uC11C\uB9CC\uC73C\uB85C\uB294 \uCD94\uC9C4\uD560 \uC218 \uC5C6\uC2B5\uB2C8\uB2E4.",s:'\uC8FC\uC81C\uB294 "\uB18D\uC5C5\uD611\uB825\uC740 \uB2F9\uC6D0, \uB3D9\uB9F9\uC6D0, \uBE48\uC911\uD558\uCE35 \uB18D\uBBFC\uC5D0 \uC758\uAC70\uD574\uC57C \uD55C\uB2E4"(1955\uB144 9\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uD55C \uAC83\uC774\uB2E4.',e:"\uC774 \uAE30\uC0AC\uC5D0\uC11C\uB294 \uD611\uB825\uC758 \uD798\uC5D0 \uC758\uC874\uD558\uB294 \uBB38\uC81C\uB97C \uAC15\uC870\uD558\uACE0 \uC870\uC9C1\uC758 \uBC1C\uC804\uC5D0\uB294 \uBA85\uD655\uD55C \uBCF8\uCCB4 \uAE30\uBC18\uC774 \uD544\uC694\uD558\uB2E4\uACE0 \uC124\uBA85\uD569\uB2C8\uB2E4."},{q:"\uD1A0\uB860\uC5D0\uC11C \uC815\uB9D0 \uC8FC\uBAA9\uD560 \uAC00\uCE58\uAC00 \uC788\uB294 \uAC83\uC740 \uADF8 \uC774\uBA74\uC5D0 \uB354 \uAE4A\uC740 \uC785\uC7A5 \uCC28\uC774\uAC00 \uBC18\uC601\uB418\uB294 \uAC83\uC785\uB2C8\uB2E4.",s:"\uC8FC\uC81C\uB294 \u300E\uB18D\uC5C5\uD611\uB3D9\uC870\uD569\uD654\uC5D0 \uAD00\uD55C \uB17C\uC7C1\uACFC \uD604\uD589\uACC4\uAE09\uD22C\uC7C1\u300F(1955\uB144 10\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uD55C \uAC83\uC774\uB2E4.",e:"\uC774 \uAE30\uC0AC\uB294 \uD611\uB825\uC5D0 \uB300\uD55C \uB17C\uC7C1\uC744 \uB354 \uD070 \uC0AC\uD68C\uC801 \uAC08\uB4F1\uC758 \uB9E5\uB77D\uC5D0 \uB450\uACE0 \uC758\uACAC \uCC28\uC774\uAC00 \uB2E8\uC9C0 \uAE30\uC220\uC801 \uB178\uC120\uC5D0 \uB300\uD55C \uB17C\uC7C1\uC774 \uC544\uB2C8\uB77C\uB294 \uC810\uC744 \uAC15\uC870\uD569\uB2C8\uB2E4."},{q:"\uC804\uD1B5 \uC0B0\uC5C5\uC744 \uBCC0\uD654\uC2DC\uD0A4\uB824\uBA74 \uBC29\uD5A5\uC744 \uC81C\uC2DC\uD574\uC57C \uD560 \uBFD0\uB9CC \uC544\uB2C8\uB77C \uC2E4\uBB34\uC790\uB4E4\uC774 \uBCC0\uD654 \uD6C4 \uC0DD\uC874\uD560 \uC218 \uC788\uB294 \uBC29\uBC95\uC744 \uBCFC \uC218 \uC788\uB3C4\uB85D \uD574\uC57C \uD569\uB2C8\uB2E4.",s:'\uC8FC\uC81C\uB294 "\uC218\uACF5\uC5C5\uC758 \uC0AC\uD68C\uC8FC\uC758\uC801 \uBCC0\uD601\uC744 \uAC00\uC18D\uD654\uD560 \uAC83"(1956\uB144 3\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uD558\uC600\uB2E4.',e:"\uC774 \uAE00\uC740 \uC218\uACF5\uC5C5 \uBCC0\uD601\uC758 \uD544\uC694\uC131\uACFC \uCD94\uC9C4\uBC29\uBC95\uC744 \uB17C\uD558\uBA70, \uAC1C\uD601\uC774 \uC2E4\uC0DD\uD65C\uACFC \uC5F0\uACB0\uB418\uC5B4\uC57C \uD568\uC744 \uAC15\uC870\uD55C\uB2E4."},{q:"\uC870\uC9C1\uC774 \uBA40\uB9AC \uB098\uC544\uAC04 \uD6C4\uC5D0\uB294 \uC5B4\uB5A4 \uC804\uD1B5\uC744 \uC783\uC5B4\uC11C\uB294 \uC548 \uB418\uB294\uC9C0 \uB418\uB3CC\uC544\uBCF4\uB294 \uAC83\uC774 \uB354\uC6B1 \uC911\uC694\uD569\uB2C8\uB2E4.",s:"\uC8FC\uC81C\uB294 \u300A\uB2F9\uB2E8\uACB0\uC744 \uAC15\uD654\uD558\uACE0 \uB2F9\uC804\uD1B5\uC744 \uACC4\uC2B9\uD55C\uB2E4\u300B(1956\uB144 8\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uD558\uC600\uB2E4.",e:"\uC774 \uAE30\uC0AC\uC5D0\uC11C\uB294 \uD654\uD569\uC774\uB780 \uCC28\uC774\uB97C \uC5C6\uC560\uB294 \uAC83\uC774 \uC544\uB2C8\uB77C \uACF5\uD1B5\uC758 \uC804\uD1B5\uACFC \uC6D0\uCE59\uC744 \uBC14\uD0D5\uC73C\uB85C \uC804\uCCB4\uC801\uC778 \uD654\uD569\uC744 \uC720\uC9C0\uD558\uB294 \uAC83\uC784\uC744 \uAC15\uC870\uD569\uB2C8\uB2E4."},{q:"\uC9C0\uC5ED \uC9C0\uB3C4\uC790\uC758 \uAC00\uC7A5 \uC911\uC694\uD55C \uAE30\uC220 \uC911 \uD558\uB098\uB294 \uC911\uC2EC \uC815\uC2E0\uC744 \uC9C0\uC5ED \uD604\uC2E4\uACFC \uC5F0\uACB0\uD558\uB294 \uAC83\uC785\uB2C8\uB2E4.",s:'\uC8FC\uC81C\uB294 "\uB3C4, \uC2DC, \uC790\uCE58\uAD6C \uB2F9\uC704\uC6D0\uD68C \uBE44\uC11C\uD68C\uC758 \uC5F0\uC124"(1957\uB144 1\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uD55C \uAC83\uC774\uB2E4.',e:"\uC5F0\uC124\uC5D0\uC11C\uB294 \uC911\uC559\uC815\uBD80\uC640 \uC9C0\uBC29\uC815\uBD80\uC758 \uC8FC\uB3C4\uAD8C\uC744 \uAC15\uC870\uD558\uBA74\uC11C \uAC01\uC9C0\uC5D0\uC11C\uC758 \uC5C5\uBB34\uCC98\uB9AC \uBC29\uC2DD\uACFC \uAD00\uACC4\uCC98\uB9AC\uC5D0 \uB300\uD574 \uB17C\uC758\uD588\uB2E4."},{q:"\uB9AC\uB354\uC2ED\uC758 \uD575\uC2EC\uC740 \uBA85\uBAA9\uC0C1\uC73C\uB85C \uC0AC\uB78C\uB4E4\uC744 \uAE08\uC9C0\uD558\uB294 \uAC83\uC774 \uC544\uB2C8\uB77C \uD575\uC2EC \uBB38\uC81C\uC5D0 \uB300\uD574 \uBAA8\uB4E0 \uC0AC\uB78C\uC744 \uC870\uC9C1\uD558\uB294 \uAC83\uC785\uB2C8\uB2E4.",s:'\uC8FC\uC81C\uB294 "\uC911\uAD6D\uACF5\uC0B0\uB2F9\uC740 \uC804\uC911\uAD6D\uC778\uBBFC\uC601\uB3C4\uC758 \uD575\uC2EC\uC774\uB2E4"(1957\uB144 5\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uD55C \uAC83\uC774\uB2E4.',e:"\uC774 \uAE30\uC0AC\uB294 \uB9AC\uB354\uC2ED\uC774 \uC5ED\uC0AC\uC801 \uC5ED\uD560\uACFC \uC2E4\uC81C \uB2A5\uB825\uC5D0\uC11C \uB098\uC628\uB2E4\uB294 \uC810\uC744 \uAC15\uC870\uD569\uB2C8\uB2E4. \uACB0\uAD6D \uC804\uCCB4\uC801\uC778 \uCC45\uC784\uC744 \uB9E1\uC744 \uC218 \uC788\uB290\uB0D0\uC5D0 \uB2EC\uB824 \uC788\uB2E4."},{q:"\uC9D1\uC911 \uACF5\uACA9\uC5D0 \uB9DE\uC11C\uB824\uBA74 \uBA3C\uC800 \uC790\uC2E0\uB9CC\uC758 \uC870\uC9C1\uB825\uACFC \uD310\uB2E8\uB825\uC744 \uD655\uB9BD\uD558\uC138\uC694.",s:"\u3008\uC6B0\uC775\uC758 \uB9F9\uACF5\uC744 \uBC18\uACA9\uD558\uAE30 \uC704\uD55C \uC870\uC9C1\uB825\u3009(1957\uB144 6\uC6D4)\uC5D0\uC11C \uC8FC\uC81C\uB97C \uBC1C\uCDCC",e:"\uC774 \uAE30\uC0AC\uB294 \uC774\uB150\uC801, \uC815\uCE58\uC801 \uD22C\uC7C1\uC5D0\uC11C \uB300\uC751\uC774 \uB290\uC2A8\uD558\uC9C0 \uC54A\uACE0 \uACC4\uD68D\uC801\uC73C\uB85C \uC870\uC9C1\uB418\uC5B4\uC57C \uD568\uC744 \uAC15\uC870\uD569\uB2C8\uB2E4."},{q:"\uB354 \uD070 \uAC10\uC815\uC73C\uB85C \uB9DE\uC11C\uB294 \uAC83\uC774 \uC544\uB2C8\uB77C, \uB354 \uBA85\uD655\uD55C \uACBD\uACC4\uC640 \uB354 \uC548\uC815\uC801\uC778 \uC870\uC9C1\uC73C\uB85C \uB9DE\uC11C\uC138\uC694.",s:'\uC8FC\uC81C\uB294 "\uBD80\uB974\uC8FC\uC544 \uC6B0\uC775\uC758 \uACF5\uACA9\uC744 \uACA9\uD1F4"(1957\uB144 7\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uD55C \uAC83\uC785\uB2C8\uB2E4.',e:"\uC774 \uAE00\uC740 \uC6B0\uC775\uC758 \uACF5\uC138\uC5D0 \uC5B4\uB5BB\uAC8C \uB300\uC751\uD560\uC9C0\uC5D0 \uCD08\uC810\uC744 \uB9DE\uCD94\uBA74\uC11C \uC8FC\uB3C4\uAD8C\uC740 \uBA85\uD655\uD55C \uD310\uB2E8\uACFC \uC870\uC9C1, \uC2E4\uD589\uC5D0\uC11C \uB098\uC628\uB2E4\uB294 \uC810\uC744 \uAC15\uC870\uD588\uB2E4."},{q:"\uC9C4\uBCF4\uB97C \uCD09\uC9C4\uD558\uB294 \uC0AC\uB78C\uB4E4\uC740 \uD6C4\uC9C4\uC131\uC5D0 \uBC18\uB300\uD560 \uBFD0\uB9CC \uC544\uB2C8\uB77C \uC0AC\uBB3C\uC744 \uC55E\uC73C\uB85C \uBC00\uC5B4\uB0C5\uB2C8\uB2E4.",s:'\uC8FC\uC81C\uB294 "\uD601\uBA85\uC758 \uCD09\uC9C4\uC790\uAC00 \uB418\uB2E4"(1957\uB144 10\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uD55C \uAC83\uC785\uB2C8\uB2E4.',e:"\uC774 \uAE30\uC0AC\uC5D0\uC11C\uB294 \uD601\uBA85\uAC00\uB4E4\uC740 \uBB38\uC81C\uB97C \uBE44\uD310\uD560 \uBFD0\uB9CC \uC544\uB2C8\uB77C \uAC74\uC124\uACFC \uD64D\uBCF4\uC758 \uCC45\uC784\uB3C4 \uC838\uC57C \uD55C\uB2E4\uACE0 \uAC15\uC870\uD569\uB2C8\uB2E4."},{q:"\uC18C\uC74C\uC774 \uB9CE\uC744 \uB54C \uC815\uB9D0 \uC911\uC694\uD55C \uAC83\uC740 \uB9CE\uC740 \uC0AC\uB78C\uB4E4\uC758 \uC2DC\uC120\uC744 \uB193\uCE58\uC9C0 \uC54A\uB294 \uAC83\uC785\uB2C8\uB2E4.",s:'\uC8FC\uC81C\uB294 "\uB300\uC911\uC758 \uB2E4\uC218\uB97C \uAD73\uAC8C \uBBFF\uC73C\uB77C"(1957\uB144 10\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uD55C \uAC83\uC785\uB2C8\uB2E4.',e:"\uC774 \uAE30\uC0AC\uC5D0\uC11C\uB294 \uB2E4\uC218\uC758 \uB300\uC911\uC744 \uBBFF\uB294 \uAC83\uC774 \uC815\uCE58\uC801 \uD310\uB2E8\uACFC \uC5C5\uBB34\uBC29\uC2DD\uC758 \uAE30\uBCF8 \uC804\uC81C\uC784\uC744 \uAC15\uC870\uD558\uACE0 \uC788\uB2E4."},{q:"\uD654\uD569\uC740 \uC11C\uB85C \uB2E4\uB978 \uC758\uACAC\uC774 \uC5C6\uB294 \uAC83\uC774 \uC544\uB2C8\uB77C, \uCC28\uC774\uC5D0\uB3C4 \uBD88\uAD6C\uD558\uACE0 \uACC4\uC18D \uD611\uB825\uD558\uB294 \uBC29\uBC95\uC744 \uC544\uB294 \uAC83\uC785\uB2C8\uB2E4.",s:"\uC8FC\uC81C\uB294 \u300E\uB2F9\uB0B4\uD1B5\uD569\uC758 \uBCC0\uC99D\uBC95\uC801 \uBC29\uBC95\u300F(1957\uB144 11\uC6D4)\uC5D0\uC11C \uBC1C\uCDCC\uD55C \uAC83\uC774\uB2E4.",e:"\uC774 \uAE30\uC0AC\uB294 \uB2F9\uB0B4 \uB2E8\uACB0 \uBC29\uBC95\uC744 \uB17C\uC758\uD558\uBA70 \uC6D0\uCE59 \uC900\uC218\uC640 \uAC08\uB4F1\uC744 \uC640\uD574\uB85C \uBAB0\uC544\uAC00\uC9C0 \uC54A\uB3C4\uB85D \uB17C\uC758\uB97C \uC218\uC6A9\uD558\uB294 \uAC83\uC744 \uAC15\uC870\uD569\uB2C8\uB2E4."},{q:"\uC6B0\uB9AC\uC758 \uC801\uC740 \uB204\uAD6C\uC785\uB2C8\uAE4C? \uC6B0\uB9AC\uC758 \uCE5C\uAD6C\uB294 \uB204\uAD6C\uC785\uB2C8\uAE4C? \uC774 \uC9C8\uBB38\uC740 \uD601\uBA85\uC758 \uC77C\uCC28\uC801\uC778 \uC9C8\uBB38\uC774\uB2E4",s:"\u3008\uC911\uAD6D \uC0AC\uD68C\uC758 \uACC4\uCE35 \uBD84\uC11D\u3009(1925\uB144 12\uC6D4)",e:"\uC774 \uBB38\uC7A5\uC740 \uD601\uBA85\uC801 \uD310\uB2E8\uC758 \uCD9C\uBC1C\uC810\uC744 \uB9E4\uC6B0 \uBD84\uBA85\uD558\uAC8C \uD574\uC90D\uB2C8\uB2E4. \uB178\uC120, \uB3D9\uB9F9, \uD22C\uC7C1 \uBC29\uBC95\uC744 \uACB0\uC815\uD558\uAE30 \uC804\uC5D0 \uBA3C\uC800 \uCE5C\uAD6C\uC640 \uC801 \uC0AC\uC774\uC758 \uC8FC\uC694 \uAD00\uACC4\uB97C \uAD6C\uBCC4\uD558\uC2ED\uC2DC\uC624."},{q:"\uC62C\uBC14\uB978 \uC815\uCE58\uC801 \uACAC\uD574\uAC00 \uC5C6\uC73C\uBA74 \uC601\uD63C\uB3C4 \uC5C6\uC2B5\uB2C8\uB2E4.",s:"\u300A\uB2F9\uB0B4 \uC798\uBABB\uB41C \uC0AC\uC0C1 \uBC14\uB85C\uC7A1\uAE30\uC5D0 \uB300\uD558\uC5EC\u300B(1929\uB144 12\uC6D4)",e:"\uC544\uBB34\uB9AC \uB2A5\uB825\uC774 \uB6F0\uC5B4\uB09C \uD300\uC774\uB77C\uB3C4 \uC62C\uBC14\uB978 \uC815\uCE58\uC801 \uC785\uC7A5\uACFC \uBC29\uD5A5\uC774 \uC5C6\uC73C\uBA74 \uD589\uB3D9\uC740 \uC27D\uAC8C \uD63C\uC744 \uC783\uACE0 \uBAA9\uD45C\uC5D0\uC11C \uBC97\uC5B4\uB098\uAC8C \uB429\uB2C8\uB2E4."},{q:"\uBAA8\uB4E0 \uC9C4\uC815\uD55C \uC9C0\uC2DD\uC740 \uC9C1\uC811\uC801\uC778 \uACBD\uD5D8\uC5D0\uC11C \uBE44\uB86F\uB429\uB2C8\uB2E4",s:'"\uC5F0\uC2B5 \uC911"(1937\uB144 7\uC6D4)',e:"\uC2E4\uC81C\uC801\uC774\uACE0 \uC2E0\uB8B0\uD560 \uC218 \uC788\uB294 \uC774\uD574\uB294 \uC0C1\uC0C1\uD558\uB294 \uAC83\uC774 \uC544\uB2C8\uB77C \uAC1C\uC778\uC801\uC778 \uC2E4\uCC9C\uACFC \uAD6C\uCCB4\uC801\uC778 \uACBD\uD5D8\uC744 \uD1B5\uD574 \uCC28\uADFC\uCC28\uADFC \uC5BB\uC5B4\uC9C0\uB294 \uAC83\uC785\uB2C8\uB2E4."},{q:"\uAD70\uC778\uACFC \uC778\uBBFC\uC740 \uC2B9\uB9AC\uC758 \uAE30\uCD08\uC774\uB2E4",s:'"\uC7A5\uAE30 \uC804\uC7C1\uC5D0 \uAD00\uD558\uC5EC"(1938\uB144 5\uC6D4)',e:"\uC804\uC7C1\uC758 \uC2B9\uD328\uB294 \uBB34\uAE30\uC5D0\uB9CC \uB2EC\uB824 \uC788\uB294 \uAC83\uC774 \uC544\uB2C8\uB77C \uC778\uBBFC\uC758 \uC870\uC9C1\uB825, \uAD70\uB300\uAC00 \uB300\uC911\uC758 \uC9C0\uC9C0\uB97C \uBC1B\uB294\uAC00\uC5D0 \uB2EC\uB824\uC788\uC2B5\uB2C8\uB2E4."},{q:"\uC815\uCC45\uACFC \uC804\uB7B5\uC740 \uB2F9\uC758 \uC0DD\uBA85\uC774\uB2E4",s:'"\uC815\uCC45\uC5D0 \uB300\uD558\uC5EC"(1940\uB144 12\uC6D4)',e:"\uACBD\uB85C\uC758 \uAD6C\uD604\uC740 \uC815\uCC45\uACFC \uC804\uB7B5\uC5D0 \uB530\uB77C \uB2EC\uB77C\uC9D1\uB2C8\uB2E4. \uBC29\uD5A5\uC774 \uC5B4\uAE0B\uB098\uBA74 \uC804\uCCB4 \uC791\uC5C5\uC758 \uD65C\uB825\uC774 \uC0AC\uB77C\uC9D1\uB2C8\uB2E4."},{q:"\uC0AC\uB78C, \uC0AC\uB78C\uB9CC\uC774 \uC138\uACC4 \uC5ED\uC0AC\uB97C \uCC3D\uC870\uD558\uB294 \uC6D0\uB3D9\uB825\uC785\uB2C8\uB2E4.",s:'"\uC5F0\uB9BD \uC815\uBD80\uC5D0 \uAD00\uD558\uC5EC"(1945\uB144 4\uC6D4)',e:"\uC5ED\uC0AC\uB294 \uC18C\uC218\uC758 \uC601\uC6C5\uB4E4\uC5D0 \uC758\uD574\uC11C\uB9CC \uD758\uB7EC\uAC00\uB294 \uAC83\uC774 \uC544\uB2D9\uB2C8\uB2E4. \uACB0\uC815\uC801\uC778 \uD798\uC740 \uC5B8\uC81C\uB098 \uAD6D\uBBFC\uC758 \uCC3D\uC870\uC640 \uD589\uB3D9\uC5D0\uC11C \uB098\uC635\uB2C8\uB2E4."},{q:"\uC6B0\uB9AC\uB294 \uB0A1\uC740 \uC138\uACC4\uB97C \uD30C\uAD34\uD558\uB294 \uB370 \uB2A5\uC219\uD560 \uBFD0\uB9CC \uC544\uB2C8\uB77C, \uC0C8\uB85C\uC6B4 \uC138\uACC4\uB97C \uAC74\uC124\uD558\uB294 \uB370\uB3C4 \uB2A5\uC219\uD560 \uAC83\uC785\uB2C8\uB2E4.",s:"\uC911\uAD6D\uACF5\uC0B0\uB2F9 \uC911\uC559\uC704\uC6D0\uD68C \uC81C7\uAE30 \uC81C2\uCC28\uC804\uC6D0\uD68C\uC758 \uBCF4\uACE0(1949\uB144 3\uC6D4)",e:"\uD601\uBA85\uC740 \uB0A1\uC740 \uCCB4\uC81C\uB97C \uC804\uBCF5\uD560 \uBFD0\uB9CC \uC544\uB2C8\uB77C, \uC0C8\uB85C\uC6B4 \uC9C8\uC11C, \uC0C8\uB85C\uC6B4 \uAD6D\uAC00, \uC0C8\uB85C\uC6B4 \uC0AC\uD68C\uC0DD\uD65C\uC744 \uAC74\uC124\uD560 \uC218 \uC788\uB294 \uB2A5\uB825\uB3C4 \uAC00\uC9C0\uACE0 \uC788\uC2B5\uB2C8\uB2E4."},{q:"\uACB8\uC190\uC740 \uC0AC\uB78C\uC744 \uC9C4\uBCF4\uD558\uAC8C \uD558\uACE0, \uAD50\uB9CC\uC740 \uC0AC\uB78C\uC744 \uB4A4\uCC98\uC9C0\uAC8C \uB9CC\uB4E0\uB2E4",s:'"\uC911\uAD6D\uACF5\uC0B0\uB2F9 \uC804\uAD6D\uB300\uD45C\uB300\uD68C \uC5F0\uC124"(1955\uB144 3\uC6D4)',e:"\uB2F9\uC2E0\uC774 \uC131\uCDE8\uD55C \uAC83\uC744 \uB354\uC6B1 \uACB8\uC190\uD558\uAC8C \uBC1B\uC544\uB4E4\uC77C\uC218\uB85D \uACC4\uC18D \uBC1C\uC804\uD558\uB294 \uAC83\uC774 \uB354 \uC26C\uC6CC\uC9C8 \uAC83\uC785\uB2C8\uB2E4. \uC77C\uB2E8 \uC548\uC8FC\uD558\uAC8C \uB418\uBA74 \uC815\uCCB4\uB418\uAC70\uB098 \uC2EC\uC9C0\uC5B4 \uD1F4\uBCF4\uD558\uB294 \uACBD\uC6B0\uAC00 \uB9CE\uC2B5\uB2C8\uB2E4."},{q:"\uC80A\uC740\uC774\uB4E4\uC740 \uC544\uCE68 8\uC2DC\uB098 9\uC2DC\uC758 \uD0DC\uC591\uCC98\uB7FC \uD65C\uB825\uC774 \uB118\uCE58\uACE0 \uC804\uC131\uAE30\uB97C \uB204\uB9AC\uACE0 \uC788\uC2B5\uB2C8\uB2E4.",s:'"\uBAA8\uC2A4\uD06C\uBC14\uC5D0\uC11C \uC911\uAD6D \uC720\uD559\uC0DD\uB4E4\uC744 \uB9CC\uB0AC\uC744 \uB54C\uC758 \uB300\uD654"(1957\uB144 11\uC6D4)',e:"\uC80A\uC740\uC774\uB4E4\uC5D0\uAC8C \uAC00\uC7A5 \uC18C\uC911\uD55C \uAC83\uC740 \uAC15\uD55C \uD65C\uB825\uACFC \uAFC8\uC744 \uD5A5\uD574 \uB098\uC544\uAC00\uB294 \uC57C\uB9DD\uC785\uB2C8\uB2E4. \uC774 \uD65C\uB825\uC740 \uC2F8\uC6B8 \uAC00\uCE58\uAC00 \uC788\uB294 \uB300\uC758\uB97C \uD5A5\uD574 \uC9C0\uD5A5\uB418\uC5B4\uC57C \uD569\uB2C8\uB2E4."},{q:"\uC138\uC0C1\uC5D0\uC11C \uAC00\uC7A5 \uB450\uB824\uC6B4 \uAC83\uC740 '\uC9C4\uC9C0\uD568'\uC774\uB77C\uB294 \uB2E8\uC5B4\uC774\uBA70, \uACF5\uC0B0\uB2F9\uC740 \uADF8\uAC83\uC5D0 \uB300\uD574 \uAC00\uC7A5 \uC2EC\uAC01\uD569\uB2C8\uB2E4.",s:'"\uBAA8\uC2A4\uD06C\uBC14 \uACF5\uC0B0\uB2F9 \uBC0F \uB178\uB3D9\uC790 \uB2F9 \uB300\uD68C \uC5F0\uC124"(1957\uB144 11\uC6D4)',e:"\uC77C\uC744 \uD560 \uB54C \uAC00\uC7A5 \uB450\uB824\uC6B4 \uAC83\uC740 \uD53C\uC0C1\uC131\uACFC \uD615\uC2DD\uC131\uC774\uB2E4. \uB05D\uAE4C\uC9C0 \uC9C4\uC2E4\uD558\uACE0 \uC131\uC2E4\uD574\uC57C \uB9CC \uC77C\uC774 \uC11C\uACE0 \uC131\uCDE8 \uB420 \uC218 \uC788\uC2B5\uB2C8\uB2E4."},{q:"\uB2F9\uC2E0\uC774 \uAE30\uAEBC\uC774 \uC624\uB974\uB294 \uD55C \uC138\uC0C1\uC5D0 \uC5B4\uB824\uC6B4 \uAC83\uC740 \uC5C6\uC2B5\uB2C8\uB2E4",s:'"Shui Tiao Ge Tou\uAC00 \uC9D5\uAC15\uC0B0\uC73C\uB85C \uB3CC\uC544\uC634"(1965\uB144 5\uC6D4)',e:"\uC544\uBB34\uB9AC \uC5B4\uB824\uC6B4 \uC77C\uC774 \uC788\uB354\uB77C\uB3C4 \uD55C \uB2E8\uACC4\uC529 \uC62C\uB77C\uAC00\uACA0\uB2E4\uB294 \uACB0\uC2EC\uACFC \uC758\uC9C0\uAC00 \uC788\uB2E4\uBA74 \uD56D\uC0C1 \uC55E\uC73C\uB85C \uB098\uC544\uAC08 \uAE38\uC744 \uCC3E\uC744 \uC218 \uC788\uC744 \uAC83\uC785\uB2C8\uB2E4."},{q:"\uC900\uBE44\uB418\uC9C0 \uC54A\uC740 \uC2F8\uC6C0\uC744 \uD558\uC9C0 \uB9D0\uACE0, \uBD88\uD655\uC2E4\uD55C \uC2F8\uC6C0\uC744 \uD558\uC9C0 \uB9D0\uB77C",s:'"\uC911\uAD6D \uD601\uBA85 \uC804\uC7C1\uC758 \uC804\uB7B5\uC801 \uBB38\uC81C"(1936\uB144 12\uC6D4)',e:"\uB9F9\uBAA9\uC801\uC73C\uB85C \uACF5\uACA9\uD558\uB294 \uAC83\uC740 \uB354 \uB192\uC740 \uB300\uAC00\uB97C \uCE58\uB974\uAC8C \uB420 \uBFD0\uC785\uB2C8\uB2E4. \uC9C4\uC815\uC73C\uB85C \uD6A8\uACFC\uC801\uC778 \uC870\uCE58\uB294 \uC801\uC808\uD55C \uC900\uBE44\uC640 \uD655\uC2E0\uC744 \uBC14\uD0D5\uC73C\uB85C \uC774\uB8E8\uC5B4\uC838\uC57C \uD569\uB2C8\uB2E4."},{q:"\uC790\uC2E0\uC744 \uAD6C\uD558\uACE0 \uC801\uB4E4\uC744 \uD30C\uAD34\uD558\uC138\uC694",s:'"\uC911\uAD6D \uD601\uBA85 \uC804\uC7C1\uC758 \uC804\uB7B5\uC801 \uBB38\uC81C"(1936\uB144 12\uC6D4)',e:"\uC804\uC7C1\uC9C0\uB3C4\uB294 \uBA3C\uC800 \uC720\uD6A8\uC804\uB825\uC744 \uBCF4\uC874\uD558\uACE0, \uADF8 \uB2E4\uC74C \uC801\uC744 \uC12C\uBA78\uD560 \uAE30\uD68C\uB97C \uD3EC\uCC29\uD574\uC57C \uD55C\uB2E4. \uC774\uAC83\uC774 \uACF5\uACA9\uACFC \uBC29\uC5B4\uC758 \uAD00\uACC4\uB97C \uB2E4\uB8E8\uB294 \uAE30\uBCF8 \uC6D0\uCE59\uC774\uB2E4."},{q:"\uBC30\uC6C0\uC758 \uC801\uC740 \uC790\uC2E0\uC758 \uB9CC\uC871\uC774\uB2E4",s:'"\uC6B0\uB9AC\uC758 \uD559\uC2B5\uC744 \uBCC0\uD654\uC2DC\uD0A4\uB2E4"(1941\uB144 5\uC6D4)',e:'\uD559\uC2B5\uC740 "\uC774\uBBF8 \uC774\uD574\uD588\uC2B5\uB2C8\uB2E4"\uB85C \uC778\uD574 \uAC00\uC7A5 \uC27D\uAC8C \uC911\uB2E8\uB429\uB2C8\uB2E4. \uC548\uC77C\uD568\uC744 \uBC84\uB9AC\uB294 \uAC83\uB9CC\uC774 \uB2F9\uC2E0\uC758 \uC9C0\uC2DD\uACFC \uD310\uB2E8\uB825\uC744 \uACC4\uC18D\uD574\uC11C \uC131\uC7A5\uC2DC\uD0AC \uC218 \uC788\uC2B5\uB2C8\uB2E4.'},{q:"\uC6B0\uB9AC \uC0AC\uC5C5\uC744 \uC9C0\uB3C4\uD558\uB294 \uD575\uC2EC\uB825\uB7C9\uC740 \uC911\uAD6D\uACF5\uC0B0\uB2F9\uC774\uBA70 \uC6B0\uB9AC\uC758 \uC0AC\uC0C1\uC744 \uC9C0\uB3C4\uD558\uB294 \uB9AC\uB860\uC801\uAE30\uCD08\uB294 \uB9C8\uB974\uD06C\uC2A4-\uB808\uB2CC\uC8FC\uC758\uC774\uB2E4",s:'"\uC911\uD654\uC778\uBBFC\uACF5\uD654\uAD6D \uC81C1\uCC28 \uC804\uAD6D\uC778\uBBFC\uB300\uD45C\uB300\uD68C \uC81C1\uCC28 \uD68C\uC758 \uAC1C\uD68C\uC0AC"(1954\uB144 9\uC6D4)',e:"\uC774 \uBB38\uC7A5\uC740 \uC2E0\uC911\uAD6D\uC758 \uC815\uCE58\uC801 \uBC29\uD5A5\uC758 \uD575\uC2EC, \uC989 \uC5B4\uB5A4 \uD798\uC744 \uC0AC\uC6A9\uD558\uC5EC \uB300\uC758\uB97C \uC774\uB04C\uC5B4\uC57C \uD558\uB294\uC9C0, \uC5B4\uB5A4 \uC774\uB860\uC744 \uC774\uB150\uC801 \uAE30\uBC18\uC73C\uB85C \uC0AC\uC6A9\uD574\uC57C \uD558\uB294\uC9C0\uB97C \uC694\uC57D\uD558\uACE0 \uC788\uC2B5\uB2C8\uB2E4."},{q:"\uBB34\uB987 \uC801\uC774 \uBC18\uB300\uD558\uB294 \uAC83\uC740 \uC6B0\uB9AC\uAC00 \uC639\uD638\uD574\uC57C \uD558\uACE0, \uBB34\uB987 \uC801\uC774 \uC639\uD638\uD558\uB294 \uAC83\uC740 \uC6B0\uB9AC\uAC00 \uBC18\uB300\uD574\uC57C \uD55C\uB2E4",s:'"\uC911\uC559\uC0AC\xB7\uC18C\uD0D5\uBCF4\xB7\uC2E0\uBBFC\uBCF4 \uC138 \uAE30\uC790\uC640\uC758 \uB2F4\uD654"(1939\uB144 9\uC6D4)',e:"\uC774\uB294 \uC801\uACFC \uC6B0\uB9AC\uB97C \uAC00\uB974\uB294 \uC18C\uBC15\uD55C \uAE30\uC900\uC774\uB2E4. \uC911\uB300\uD55C \uC2DC\uBE44 \uC55E\uC5D0\uC11C, \uC801\uC758 \uD0DC\uB3C4 \uC790\uCCB4\uAC00 \uC5ED\uBC29\uD5A5\uC758 \uC88C\uD45C\uAC00 \uB418\uC5B4 \uC6B0\uB9AC\uC758 \uC785\uC7A5\uC744 \uD655\uC778\uD558\uB294 \uB370 \uB3C4\uC6C0\uC774 \uB41C\uB2E4."},{q:"\uC6B0\uB9AC\uB294 \uAD70\uC911\uC744 \uBBFF\uC5B4\uC57C \uD558\uACE0, \uC6B0\uB9AC\uB294 \uB2F9\uC744 \uBBFF\uC5B4\uC57C \uD55C\uB2E4. \uC774\uAC83\uC774 \uB450 \uAC00\uC9C0 \uADFC\uBCF8 \uC6D0\uB9AC\uC774\uB2E4",s:'"\uB18D\uC5C5\uD611\uB3D9\uD654 \uBB38\uC81C\uC5D0 \uAD00\uD558\uC5EC"(1955\uB144 7\uC6D4)',e:"\uC911\uB300\uD55C \uACB0\uC815\uC5D0\uC11C \uAD70\uC911\uC744 \uBBFF\uB294 \uAC83\uC740 \uD798\uC758 \uC6D0\uCC9C\uC774\uACE0, \uB2F9\uC744 \uBBFF\uB294 \uAC83\uC740 \uC870\uC9C1\uC758 \uBCF4\uC99D\uC774\uB2E4. \uB458 \uC911 \uC5B4\uB290 \uD558\uB098\uB3C4 \uBE60\uC9C8 \uC218 \uC5C6\uC73C\uBA70, \uBAA8\uB4E0 \uC0AC\uC5C5\uC758 \uAE30\uBCF8 \uC804\uC81C\uC774\uB2E4."},{q:"\uC0AC\uB78C\uC740 \uC57D\uAC04\uC758 \uC815\uC2E0\uC774 \uC788\uC5B4\uC57C \uD55C\uB2E4",s:'"\uC911\uAD6D\uACF5\uC0B0\uB2F9 \uC804\uAD6D\uB300\uD45C\uD68C\uC758\uC5D0\uC11C\uC758 \uC5F0\uC124"(1955\uB144 3\uC6D4)',e:"\uBB3C\uC9C8\uC801 \uC870\uAC74 \uC678\uC5D0 \uC0AC\uB78C\uC5D0\uAC8C \uAC00\uC7A5 \uBE60\uC9C8 \uC218 \uC5C6\uB294 \uAC83\uC740 \uC77C\uC885\uC758 \uC815\uC2E0 \uC0C1\uD0DC\uC774\uB2E4. \uC21C\uACBD\uC774\uB4E0 \uC5ED\uACBD\uC774\uB4E0 \uC774 \uAE30\uAC1C\uB9CC \uB0A8\uC544 \uC788\uB2E4\uBA74 \uC77C\uC740 \uACC4\uC18D\uB420 \uC218 \uC788\uB2E4."},{q:"\uD601\uBA85\uC804\uC7C1\uC740 \uAD70\uC911\uC758 \uC804\uC7C1\uC774\uBA70, \uC624\uC9C1 \uAD70\uC911\uC744 \uB3D9\uC6D0\uD574\uC57C\uB9CC \uC804\uC7C1\uC744 \uC9C4\uD589\uD560 \uC218 \uC788\uACE0, \uC624\uC9C1 \uAD70\uC911\uC5D0 \uC758\uC9C0\uD574\uC57C\uB9CC \uC804\uC7C1\uC744 \uC9C4\uD589\uD560 \uC218 \uC788\uB2E4",s:'"\uAD70\uC911\uC0DD\uD65C\uC5D0 \uAD00\uC2EC\uC744 \uAC16\uACE0, \uC0AC\uC5C5\uBC29\uBC95\uC5D0 \uC8FC\uC758\uB97C \uAE30\uC6B8\uC5EC\uB77C"(1934\uB144 1\uC6D4)',e:"\uC804\uC7C1 \uC2B9\uD328\uC758 \uADFC\uBCF8\uC740 \uAD70\uC911\uC5D0 \uC788\uB2E4. \uC2B9\uB9AC\uD558\uB824\uBA74 \uAD70\uC911\uC744 \uC9C4\uC815\uC73C\uB85C \uB3D9\uC6D0\uD558\uACE0 \uC870\uC9C1\uD558\uBA70 \uC758\uC9C0\uD574\uC57C \uD558\uBA70, \uAD70\uC911\uC744 \uB5A0\uB098\uC11C\uB294 \uC544\uBB34\uAC83\uB3C4 \uC774\uB8F0 \uC218 \uC5C6\uB2E4."},{q:"\uC815\uCE58\uC0AC\uC5C5\uC740 \uBAA8\uB4E0 \uACBD\uC81C\uC0AC\uC5C5\uC758 \uC0DD\uBA85\uC120\uC774\uB2E4",s:'"\u3008\uC2EC\uAC01\uD55C \uAD50\uD6C8\u3009\uC5D0 \uB300\uD55C \uC548\uC5B4"(\u300A\uC911\uAD6D\uB18D\uCD0C\uC758 \uC0AC\uD68C\uC8FC\uC758 \uACE0\uC870\u300B1955\uB144 12\uC6D4)',e:"\uACBD\uC81C\uC0AC\uC5C5\uC740 \uC62C\uBC14\uB978 \uC815\uCE58\uC801 \uBC29\uD5A5\uC758 \uC778\uB3C4\uAC00 \uC5C6\uC73C\uBA74 \uC601\uD63C\uC744 \uC783\uB294\uB2E4. \uB458\uC740 \uB300\uB9BD\uD558\uC9C0 \uC54A\uC73C\uBA70, \uC815\uCE58\uC0AC\uC5C5\uC774\uC57C\uB9D0\uB85C \uACBD\uC81C\uC0AC\uC5C5\uC774 \uBA40\uB9AC, \uBC14\uB974\uAC8C \uB098\uC544\uAC08 \uC218 \uC788\uB3C4\uB85D \uBCF4\uC7A5\uD558\uB294 \uADFC\uBCF8\uC774\uB2E4."}];var s=e;export{s as default};
